insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2016-03-22','Coste de a la residencia “Hogar Virgen de la Cabeza” de Fuente del Maestre , para un posible traslado Actualmente hay plazas. Costes. Que si la persona se vale por sí mismo el precio es de 950 € mensuales. Si tiene grado de dependencia, según vaya subiendo el grado igualmente va subiendo el precio.(Andrea ha sido valorada y no tiene grado) No tienen ficha de inscripción, basta con contactar telefonicamente. El teléfono es: 924 53 00 33. Preguntar por Noelia.','2');
