insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2016-03-23','Recibimos requerimiento de Informe social y alta a terceros para solicitud de Renta Básica Expediente RB13-14818, nos ponemos en contacto con TS Isabel Pino del SSB Miajadas, acordamos envirle la documentación del Alta a Terceros firmada , pendiente de cumplimentar por la entidad bancaria. Al estar en piso supervidado la ts cree que no cumple los requistos (Ley 3/2013 de 21 de mayo, articulo 9 apartado g) Intentamos contactar con el piso supervidado 927 16 01 98 no siendo posible.','2');
