insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2016-03-20','SALIDA Del 20/03/2016 al 27/03/2016. Vacaciones de Semana Santa. Su hermano, D. JOSÉ MANUEL BRAVO PATILLA, con DNI nº 06.994.233-W, se hace responsable de ella mediante declaración de responsabilidad, de fecha 20/03/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-03-28','Actualmente va a comer al Comedor Social de Cáceres a diario. Creemos que está viviendo en casa de un amigo según nos informó la dueña el albergue y por el aspecto físico que presenta en las visitas de futuex, aunque el mantiene que vive en un cajero. Aún queda pendiente pagar la deuda del hostal, por lo cual es inviable la propuesta de alquilar un piso. No accede a la visita semanal con futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2016-03-23','INCIDENCIA El día 16/03/2016, a las 10 hs. de la noche, aproximadamente, Álvaro sufrió una caída accidental en su habitación. Se avisó al servicio de urgencias del Centro de Salud de Pinofranqueado y, el médico de guardia, tras una primera valoración, decidió activar a la UME de Caminomorisco. El diagnóstico médico fue de TCE, con signos de alarma como somnolencia, adormecimiento, cambio de carácter, disartia, hemiplejia del lado derecho, por lo que se le trasladó al Hospital Virgen del Puerto de urgencia. Una vez allí, se le realizó un TAC y, efectivamente, se observó una hemorragia a nivel ventricular que no es posible drenar quirúrgicamente. *********************************************************** Actualmente, a día 22/03/2016, los resultados del TAC parecen estar un poco mejor que en el del día del accidente, pero, ayer, el paciente presentó febricula que no cede con antipiréticos. Se le han realizado varios hemocultivos y analíticas de los que, aún, no sabemos el resultado.************************************************* Durante la estancia en el hospital, está acompañado en todo momento por personal de la Casa de la Misericordia y recibe visitas diarias de su hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='FERNANDEZ'and apellido2='SANCHEZ'),'2016-03-28','Manuel viene manifestando que no tiene suficiente con la asignación. Una vez revisada las cuenta con la sección ecoómica, confirmamos: - Que tiene autorizado sacar 90€ semanales. - Alquiler de la vivienda 270€ - Ingresos 867€. No se le autoriza el aumento de asignación. Se le indica a través de futuex que no solicite más extras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-03-28','Luis Miguel debe acudir al Juicio sobre delitos leves 6/2016, a celebrar en el Juzgado de Primera Instancia e Instrucción nº 5 de Cáceres, el día 11/04/2016, a las 10:15 horas. Cuenta con abogado y procurador. A su representación legal hemos enviado la citación y tras firmarla Luis Miguel en el despacho la hemos enviado al Juzgado.','1');
