insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-01-22','INCIDENCIA Comunicamos, desde el servicio de Centro Ocupacional Aprosuba 7, que la tutelada y usuaria de nuestro servicio, Minerva Martín Blanco, no ha asistido hoy al centro.******* Según conversación telefónica con la Coordinadora del Servicio, no ha acudido por la visita de un hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2015-12-03','INCIDENCIA Con respecto a la tutelada Vanesa Fernández Gómez, informaros que el día 26 de noviembre se marchó a su domicilio familiar en Trujillo. Según nos informó, la habían cogido para realizar un curso en una escuela taller de Trujillo, por el cual percibía unos ingresos económicos. Queda con nosotros que el viernes,27 de noviembre, tras reunión mantenida, llamaría para informar si la duración de dicho curso era de 6 meses o 1 año. Estamos intentando contactar con ella, pero no coge el teléfono. No ha vuelto a informar de nada. Tenía previstas revisiones médicas y no se pueden llevar a efecto porque incluso ha cambiado de asignción de médico en Trujillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='PEREZ'and apellido2='JIMENEZ'),'2016-03-28','Se firma Desistimiento de solicitud de Revisión de la situación de Dependencia y derecho a las prestaciones del sistema, solicitado el 22 de agosto de 2011. Se solicita con caracter de urgencia con fecha de hoy 28 Pendiente firmar y enviar por fax a Sepad de Zafra, ya que tanto Gerente y Secretaria no se encontraban en el edicifio. La Coordinadora Tecnica de Gestión (Belen Plasencia) nos indica que lo enviemos mañana a primera hora. Hemos informado a Natividad Hernández (Sepad Zafra) de que mañana se enviará por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIO'and edp.apellido1='MEGIAS'and apellido2='FRUTOS'),'2016-03-28','Natalio Mejías ha sido de nuevo derivado al hospital por empeoramiento de su estado el pasado día 26 de Marzo, segun me informa esta grave, ha estado a compañado por su hermana Antonia durante el sabado y el domingo durante el día. Se le ha buscado persona para acompañarle durante la noche del domingo al lunes por que esta grave y su hermana Antonia tenía que trabajar hoy Lunes. Ha venido una hermana de Madrid, Carlota y quiere estar con el durante el día, de momento hemos contratado a una persona para que este por la noche acompañandolo. Entrada 21:30 h y salida a las 09:30 h. 10 ?/ hora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-03-28','Alta de UME el 22 de marzo y nuevo ingreso ayer, 27 de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-03-29','Llama Agustina (Psiquiatra UHB Mérida). Le va a dar el alta hoy. Tenemos que pedir cita en el ESM de Mérida y hablar con Asunción Cabrera (924-388187) para seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2016-03-29','Se solicita trasnporte subvencionado (Nota interior) a Cruz Roja para traslado el día 12 de abril. para convivencia familiar con su madre. Desde Placeat nos comunican que el pasado 22 de marzo tenía prevista otro traslado y desde la Comisión no se gestionó el servcio, que es ya la segunda vez que ocurre. El pasdo mes de enero Alberto visitó su domicilio materno en una salida del centro, desde entonces no ha vuelto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-03-29','Nos comunica el Dr. CRRMérida (Visita CTAEX) que el hermano de MariLoli está ingresado en UCI en el Hospital de Mérida. Ella manifiesta que desea pasar la noche en el hospital, hasta el momento la han retenido. Desde la CTAEX no se le autoriza, ya que las visitas en UCI están programadas para ciertas horas y no permiten familiar acompañamiento, por lo cual Mari Loli debería pasar la noche en sala de espera o pasillo, lo cual no lo permite el Centro Hospitalario, y pudiendo ocurrir cualquier incidente que la desastibilice. Le solicitamos que la informen del protocolo, que proporcione el número de teléfono de contacto al Hospital, por si produciese algún cambio de salud. El Centro se compromete a acompañarla si ocurriese cualquier problema','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-03-29','Enviado partida literal de nacimiento a través de mensajería a Nuñez y Montes Gestoria Administrativa en Gelves Sevilla.','2');
