insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-03-29','Visita de Drtor CRR Mérida, nos informa que Emi tenía jucio hoy "cree que por agresión al Sr. Carlos Frade", tiene abogada de oficio que solicitará el juicio por video conferencia. Actualmente Emei está realizando varios episodios de confrotación tanto con los compañeros como con los profesionales del centro, lleva 3 ingresos en este mes, desde el centro valoran que el recurso mas apropiado no es el CRR, valoran solicitar "Subcomisión". Le pedimos a Javier que nos envie los informes de las incidencias habidas y a Gisela los datos y comparecencias de los juicios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2016-03-29','Solicita 70€ para regalo de boda de un sobrino en Madrid, la boda fue el fin de semana. Le pedimos cuenta bancaria sobrino y nos informa que desea enviarlo por correo . Pendiente de valorar por equipo. Vuelve a preguntarnos por las gestiones realizadas para encontrar compañera de piso. Se altera preguntando cual es nuestra función, ya que a quien puede acudir ella en caso que de que sufra un brote psicótico. le informamos que debe de llamar al 112, no comprende las funciones de la Comisión Tutelar, y se marcha enfandada ya que según ella, el juez y en los pisos supervisados le dijeron que la comisión estaba para atenderla "no como una niña pequeña".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2016-03-30','Llama Antonio, hermano de Aurora. Dice que el día 5 va al juzgado de Villanueva por isuultos. Dice haber enviado fax con recibos de agua y luz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-03-30','Reunión en CSS de Mérida con Isabel (Psiq.), Juan Pêdro (Psic.) y María (T.Soc.). Conclusiones: D. Manuel permeanecerá en el CSS de Mérida. Pedirán valoración de DEpendencia por si el CRR fuese una alternativa. Solicitarán Pisos Supervisados (Chalet en el recinto del Centro Socio Sanitario. Psiquiátrico). Se plantea la atención de CEDEX por el consumo de alcohol de Manuel. (Él nos informa que habitualmente consumia 1 litro de cerveza en casa + las salidas a las diferentes cafeterias de su barriada)','2');
