insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-03-30','Reunión CSS de Mérida (psiquiatra: Alfredo, Enfermera, Asun (psicopedagoga) Blanca.TS, CTAEX: Pedro, Toni. Se acuerda que Juan Bautista, realice ssalidas obligatorias sin pernoctar del centro semanales, a la vuelta se hará controles de consumo, incluido alcohol. Cuando trasncurra un periodo razonable de NO CONSUMO, se barajará la posibilidad de que pasen una noche en un hostal en Mérida, con su pareja. Todo esto de manera progresiva. Desde CSS, se comprometen también a trabajar con Isabel (novia, paciente CSS), la psobilidad de darle al alta e irse a vivir con otra paciente. PSIQUIATRA: valora que Juan Bautista no puede recibir el alta. A parte de la ESquizofrenia, padece diabetes que actualmente no están controlados. En el ultimo contorl dió positivo en cannabis, y en sus salidas del centro consume alcohol. Se compromenten en CSS en implicar a la pareja de Juan en el control de NO COnsumo. Se informa al CSS que no es viable la propuesta de ir a residir a la vivienda de Juan, ya que desde la Comisión en caso de salida del centro se le solicitaira Plaza Residencial.','2');
