insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2016-04-01','Se le autoriza un extra de 60€ A prtir del 4 de abril de 2016, recibirá una asignación semanal de 50€, acompañada para la retirada de la delegada tutelar. Debe una factura de luz de 200€, de la cual Paloma se hará cargo de 50%. Debe de comunicarnos futuex el día de la visita para autorización de extra y entregar en mano los 100€ a la propietaria de la vivienda a la cual se le debe. (comunicadao por email a Futuex). Hemos intentado hablar con cáritas de Jerez ya que tenemos dudas que desde dicha entidad se le hubiera facilitado alguna cantidad para abono de facturas. (ha sido imposible)','2');
