insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-04-04','Hablo con Carmen, T. Soc. del CAMP (ver fax). VIERNES: quedó en que volvería al CAMP por la tarde. No lo hizo. Cogió un tren, sin billete, y se fue hasta Almadenejos, donde le obligaron a bajar, Se hizo daño en un costado y lo llevaron al Hospital de Almadén y de allí al de Puertollano. SÁBADO: vuelve a Cabeza del Buey. DOMINGO: regresa al CAMP y se vuelve a fugar a las 19:00. (TODA ESTA "AVENTURA" ME LA CUENTA MARTA, SU SOBRINA). Intentará localizarlo y llevarlo mañana al CEDEX.','2');
