insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-04-05','Asun (psicologa CSS) nos informa que su madre ha estado en su vivienda y ha encontrado documentos que parecen indicar que el gasto de llamada ascendía a 700€ y a esto se añade la compra de uno o dos terminales móviles de alta gama (alguno de ellos para regalarselo a una de sus hermanas porque sabe que no tienen tanto dinero y él quiere cuidarlas y tener detalles con ellas). SE LE ASIGNA VISITA MENSUAL DE DELEGADA TUTELAR. para control de vivienda y gastos de telefonia. Marisa índicará que se de la baja a las tarjetas de crédito que tenga asiganadas Sea cual sea el motivo, lo cierto es que está haciendo gastos extraordinarios. Hace compras por internet porque ha comprobado que nadie se entera de estos gastos y que su incapacidad no es un condicionante para realizar estas compras.','2');
