insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-04-05','Llamada de José María Tovar (NACE). la Dirección de Novaforma le ha pedido que lleve a Tomás mañana para que el abogado de la Entidad pueda hablar con él. Pide la opinión de CTAEx. Le comento que la Comisión no autoriza dicha reunión, por cuanto el asunto ya está en manos del Juzgado y la misma podría ser incluso contraproducente para Tomás. Le propongo plantearlo a Fiscalía en cualquier caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-04-05','Resolución INSS, se le concede una PF a fecha de efectos del 1/04/2016 de 551,90€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ORTEGA'and apellido2='SEVILLA'),'2016-04-06','Recibimos llamada de Cristina (mensajeros de la Paz) la cual nos comunica que el antiguo cuadador de David y su hermano, lo ha localizado y a través de otro usuario quiere visitarlo. "Presuntamente", David había sufrido abusos sexuales del cuidador, NO EXISTE DOCUMENTACION ESCRITA, pero el tralado a Burgos fue motivado por esta causa. Todo esta información es a nivel verbal. Decidimos si se corrobora esta situación o no se admitirán dichas visitas, sino que sean supervisadas como medida preventiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-04-06','Llamo a Carmen Barquilla, Fiscal de Cáceres. No lleva el caso ella pero le hago la consulta reflejada en la incidencia de ayer, día 5 de abril:Es el Tutor, en cualquier caso, el que debe autorizar decha reunión y estar presnete en ella. Por otro lado, opina igual que yo, que puede ser contraprocucente para los intereses de nuestro tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-06','INFORME HOSPITAL INFANTA CRISTINA, SERVICIO MEDICINA INTESIVA. Dra. Casquet Gómez, A: Traumatismo craneoencefálico grave (HSA y HSD bilateral). En la actualidad, su estado de salud sigue siendo critíco, ya que persiste la situación de coma similar a los días previos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Alberto Córdoba (Intensivista UCI-1, 924-218100(centralita)). Solicita información de algún familiar de D. Eusebio. Se le da el teléfono de Fani (hermana). Se le explica la situación de Tutela a la que está acogido D. Eusebio, debiendo contactar con la CTAEx para cualquier decisión que sobre él se deba autorizar (al margen de lo que los familiares puedan opinar al respecto). Se le da los teléfonos de la Sección Social de la CTAEx y el de FAX. Se informa telefonicamente a Pilar (Piso S de Zafra)','2');
