insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-06','informe seguimiento servicio de psiquiatria: 7/3/16: paciente que en la actualidad lleva varios meses sin tomar ningún tipo de medicación, desde septiembre no acude ESM. Va acompañado de personal de la CTAEX. Recientemente ha habido un nuevo espisodio en el que la policia ha abierto diligencias, motivo por lo que se lecita con caracter muy preferente. En la visita de hoy accede a ponerse Xepelion. 4/4/16: acude de nuevo a la cita. No ha habido en este tiempo alteraciones de conducta. Mantiene una ideación delirante erotomaniaca, así aacuerdan la proxima inyección 150 Debe mantene abstinencia absoluta de alcohol y cannabis Proxima cita 4 de mayo Xpelion 150 cada 4 semanas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-03-09','Nos comunican que el 2 de marzo hay un incidente con una menor, nos ponemos en contacto con la poolicia local, la cual nos informa que el 2 de marzo a las 18:00, se pone en contacto con la policia local informando que un Sr. intenta tocarle el culo en el Parque de conquistadores, lo identifica con Francisco, la policia se persona en el lugar y le intervienen varios cogollos de marihuana. La Policia Local informa a la Delegación de gobierno de la posesión de marihuana. Indican al padre de la menor que debe de poner una denuncia en comisaria. El día 7 acude a ponerse el inyectable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-03-14','Envio carta a la Policia Local solicitando informe de las incidencias habidas con Francisco en la localidad, adjuntamos Sentencia de Incapacitación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='MORALES'and apellido2='BELMEZ'),'2016-04-06','iNFORMACIÓN ENVIADA POR EMAIL DR. CRR: Con respecto al caso de Emilia Morales, durante su ultimo ingreso estuvimos hablando con el pisquiatra que llevaba el caso en UHB, tras informarle de la situación que venimos teniendo durante los últimos meses esta de acuerdo en realizar la derivación para UME. Por lo que según indicaciones del psiquiatra (Alfredo de la Rubia) el mismo realizo la semana pasada la derivación a este recurso, procediendo a ser Emilia evaluada en los próximos 20 días y a la espera de plazas disponibles para ingresar en UME.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2016-04-06','Magdalens(TS) nos informa que Blas ha acudido a revisión de Urología, y le están realizando más pruebas. Ha realizado una visita a oftalmología y tiene una catarata en el ojo derecho que le provoca una pérdida importante de visión no ha querido incluirse en lista. Se trabaja desde el centro para que acepte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-04-06','Asun nos comunica que no ha asistido a la cita que tenía hoy programada, según ella porque no se lo comunicaron (lo cual no es cierto). Próxima cita 14 de Abril','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2016-04-07','Nos informa Mayte (discapacidad), que ha cambiado el perfil de alberto, de RAL A RAE, por lo cual hay un cambio de centro ya que solo hay 5 plazas, el nuevo recurso es Francisco es Asis, en Aldea del Campo. Desde que nos lo comuniquen hay 15 días para el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2016-04-07','Informe delegada tutelar 22/03/2016 Recibe visita de la vencina "María", la cual le informa que el banco le impide sacar dinero, se le informa que es la Junta la que se encarga y lo que necesite , (durante dos o tres días, estuvo inquieta, ya no ha vuelto a preguntar) Se encuentra contenta, y adapatada. Acude 3 veces a la semana a rehabilitación con la fiseo en el centro residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2016-04-07','a través de futues la directora del centro nos informa qye le han concedido grado 2 por denpendencia para poder obtener prestación económica para plaza residencial, que enviarán desde Sepad de Cácceres a la Comisiónla documentación. NO HE MOS RECIBIDO LA DOCUMENTACIÓN A FECHA DE HOY','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SAUCEDO'and apellido2='AGUEDO'),'2016-04-06','-se envia solicitud de revision de expediente de dependencia según lo hablado telefónicamente con Cecilio Leonés (jefe de sección dependencia badajoz)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2016-04-07','Llama D. Victoriano Guisado (916-900834 y 676-615302), vecino del inmueble del que D. Martín y Dª Vicoriana Hdez. (su madre) tienen en propiedad en Fuenlabrada, en la calle Leganés 47, 1ºG. manifiesta que hace dos años se puso en contacto con esta Comisión para poner en nuestro conocimiento la ocupación ilegal de la vivienda por una familia de etnia gitana y los inconvenientes que ello estaba produciendo en la vivienda de D. Victoriano y en la Comunidad. ++++llama en esta ocasión insistiendo en dichas molestias, en las reparaciones que, derivadas del "mal uso" de la vivienda contigua, ha tenido que hacer en la propia y para saber en qué situación están las actuaciones. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se contacta con el abogado D. Gaspar Guerrero López (620-738843), quien manifiesta que presentó presupuesto para llevar a cabo las actuaciones correspondientes a la declaración de hererderos y posterior adjudicación de herencia, pero que todo quedó pendiente sin que se llegase a retomar el tema. SE OFRECE PARA CUALQUIER ACLARACIÓN AL RESPECTO Y A SEGUIR LLEVANDO EL TEMA, LLEGADO EL CASO, SIN QUE DICHA COLABORACIÓN INFORMATIVA DEPENDA DE DICHA CONTARTACIÓN O NO. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Respecto a la situación de ocupación ilegal de la vivienda, la CTAEx presdentó la correspondiente denuncia en la Comisaría de Mérida el 8 de abril de 2014 (Atestado 2241/14).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2016-04-07','Llama Miguel(642-632131): ha tenido un incidente con un tabaco de "contrabando" que otra residente (externa)le proporcionaba. Se ha "descubierto" la situación y Miguel dice:"El coordinador me ha quitado 100 € de la hucha y me dice que tengo que pagar 400...", se supone que al hermano de la muchacha que le proporcionaba el tabaco y que esta quitaba a su hermano ¿¿¿???. Llamo a Soledad, pero est,a comunicando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2016-04-07','Se le da baja en plaza residencial de aprosuba y CO ya que desde el 27/11/15, ha abandonado el centro. Se le facilita el fax de aprosuba a Maribel Ramos de Discapacitados (SEPAD).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BUENAVENTURA'and edp.apellido1='ABRIL'and apellido2='PACHECO'),'2016-04-07','Tiene una averia en la vivienda que afecta al piso del vecino del piso inferior. Le hemos pedido a Ventura que nos facilite los datos para poner en contacto al vecino con el banco para arreglar el desperfecto. (Ventura sigue sin asumir que la vivienda no es de su propiedad y le pertenece al banco.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MARFIL'and apellido2='MUÑOZ'),'2016-04-08','Llama Javier San Andrés 924-650873), abogado de Herrera del Duque, respecto a la demanda interpuesta por el error en el abono de una factura. Nos nostificará la Procuradora, Rosana, mandamineto de pago por valor de 689.37€ para ingresar. Queda pendiente seguir con el abono del principal, los intereses y la minuta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2016-04-08','Conversación con Soledad (respecto de la incidencia anterior). Se aprovechaban de esta chica Miguel, Estíbaliz y Gori (al principio también Cristobal). Miguel de "líder". Miguel debe devolver el dinero de su hucha (100 euros) del tabaco que ha recibido desde febrero, aprovechándose de la muchacha quien lo hacía para ser aceptada (tiene mayor afectación que ellos).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2016-04-08','llamo a D. Victoriano (vecino del piso de debajo del de Martín). Al margen de las dificultades de convivencia que refiere, las principales reparaciones que ha tenido que hacer en su vivienda, por tres veces, son las relativas a las humedades procedentes del piso de Martín, ocupado ilegalmente. Nos envirará por FAX documentación acreditativa de dichas reparaciones, para tener constancia de ellas una vez resueltos los problemas de titularidad de la vivienda y de cara a resolver el problema de ocupación del piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2016-04-08','Nueva llamada del hermano de José María para saber si ya nos han llegado todos los "papeles".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-04-08','Llamo a Carmen para ver como está. Se corta la llamada y a continuación llama ella. No se le entiende bien, pero pide que le arreglemos el tema del dinero porque no tiene desde el mes pasado. Dice estar vendiendo libros como Agente de Círculo ¿?. Quedo en hacerle una visita la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-04-08','Llamada de Dora, madre de Javier. Asustada, porque su hijo no se separa de ella porque quiere ir con ella a casa a recoger un reloj de oro de su padre -"...y yo no quiero que entre en casa...hacía mucho tiempo que esto no me pasaba...". ++++++++++++Hablo con Javier y le insisto en que de persisitir en su comportamiento, el mismo tendrá consecuencias. ++++++++++++Retomo la conversación con Dora y le digo que voy a llamar a Asun, como paso previo a llamar a la Policía Local (estan además en el aparcamiento de la Politécnica)para que intervenga. ++++++++++++Hablo con Asun y le describo la situación, con las opciones que tengo. ++++++++++++Asun habla con Javier y parece entender las consecuencias de su comportamiento, desistiendo del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-04-11','RESOLUCIÓN DE RECONOCIMIENTO DE SITUACION DE DEPENDENCIA: GRADO II. A FECHA DE 26/02/2016','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-04-12','VISITA PSIQUIATRIA: TRATAMIENTO 6/04/16. aBILIFY 10mg 1 COMP AL DIA ZYPREXA 20MG VELOTAB I COMP POR LA NOCHE RIVOTRIL 2 MG POR LA TARDE 1 POR LA NOCHW','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-04-11','Llama Jesús: no nos hemos puesto en contacto con la Farmacia para hacer la transferencia del inyectable. Llamaremos a hora. Le comento que por qué no la compra él (4€), ya que la transferencia le cuesta dinero: dice que no porque si no no lellega con 50 €. Insiste en la renovación del carnet de conducir "ahora que tengo dinero..." pero le digo que antes hay que resolver las deudas que tiene. Comenta quie ya no va a buscar piso de alquiler, porque "...tengo previsto irme al psio de un amigo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-04-11','Solicita 50€ para ropa, no se acepta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-11','Mediante Nota Interior se comunica a la Comisión Tutelar la Resolución de Baja de los Pisos Supervisados de Zafra de D. Eusebio a fecha 07 de abril de 2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-04-11','Recibimos llamada de la TS de Jerez (Eugenia 654 981518-924 73 01 01), la cual nos informa que tras la peticiómm anual del Informe social por parte de la Comsión, y la visita a domicilio a la vivienda, esta se encuentra en una situación de falta de higiene brutal. Actualmente conviven en el domicilio la madre Maria, y 4 hermanos (Ramón, Luis/pensionista/, mayor/subsidio/, chico /sin recursos/) otro hermano de Ramón que no convinve con ellos, manifiesta que quieren llevarse a la madre fuera del domicilio ya que según él padece alzheimer y creen que de esta manera la comsión trasladaria a Ramón a un centro. La comisión accede al pago general de la vivienda por parte de Ramón, a cambio de que se le asigne un SAD (a la familia) por parte del Ayto. Pero que Ramon si se marcha la madre seguiria viviendo en su domicilio. Se le trasmite a TS. la cual abordará a la familia para informarla de la limpieza y si estuvieran de acuerdo pedir presupuestos. De momento no se informará a Ramón de la decisión por los conflictos que pudiera generar a nivel de convicencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-04-08','Hablamos con Juan Pedro Apolo 40148, acordamos enviarle el desistimiento de revisión de grado. Nos informa que tiene plaza residencial desde febrero. por recurso de discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-08','informe evolución médica: Mismo nivel neurológico, con Glasgow 5 puntos tras retirada de sedación. Continua con intubación orotraqueal y conexión a ventilación mecánica. Mal manejo de l secreciones. Se le remite fotocopia a recurso de discapacidad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-11','La delegada tutelar recibe una llamada de telefonos del hemano, Antonio Cuevas (667 955 006), que le informa que Paco está detenido desde le miercoles, según vecinos por amenazar con un cuchillo a la vecina a la cual acosó sexualmente. El hermano nos informa que no quiere que vuelva al domicilio . Contactamos con la Policia Local de Don Benito, la cual nos informa que realizaron tralado a UHB de Mérida. Contactamos con UHM y nos informan que está ingresado, lo lleva el Dr. Alí. (está en urgencias y nos piden que llamemos más tarde)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOTO'and apellido2='DURAN'),'2016-04-11','Llama Manuel, Hijo de D. José. Dice tener juicio de remoción de la tutela de su padre, la cual quiere asumir, el próximo día 18 de abril por videoconferencia (vive en Reus). No tenemos constancia oficial de la misma en la Comisión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2016-03-01','25/02/2016. INFORME FUTUEX Se realiza visita a la Residencia Padre Damián. Montaña una auxiliar de clínica me lleva a ver a Rosa, me cuenta que hace un mes ha empezado a comer y le han quitado la sonda. Estando sola, ella está muy tranquila. Prácticamente ha perdido la visión, pero tiene buena movilidad. Cuando llego Rosa está dormitando. Está arreglada y limpia. Cuando le hablo me cuenta cosas que ha dejado en su casa y recuerda lo mayor que es. Está en su mundo, pero recuerda haber empezado a comer y que esto ocurrió hace un mes. No le gusta mucho hablar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2016-03-31','SITUACION ECONOMICA: A Rosa se le han cobrado unos 2.000 € de más debido a un error. Se le estaba cobrando 600 € al mes cuando tenían que haber sido 300 €. Esto se subsanará cobrándole 40€ al mes (en lugar de los 300€) durante diez meses, quedando el 31 de Diciembre de 2016 regularizadas las cuentas. En caso de causar baja por alguna circunstancia, devolverán el importe que reste. De todo esto tiene conocimiento Marisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2016-04-11','INFORME FUTUEX 31/03/2016: Rosa es una mujer muy mayor con un imporante deterior cognitivo, Valora que nos ería capaz de participar en nigún tipo de actividad, por lo cual se valora la no intervención de afiliación a la ONCE.','2');
