insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2016-04-13','ACUERDOS TOMADON CON AIDA POR TELEFONO: - Se le realizará una transferencia de 200€ a Leandro(concepto pago operación lobulos) -Autorización 100€ regalo para Leandro y Sonia cumpleaños Ambas cuantias 300€ en total SE DESCONTARÁN DE LA Paga Extra de Junio -Referente al tratamietno del fiseo, dos opciones: si es un extra se realizárá por transferencia se pasará a descontar de la Paga Extra de Junio, sino que lo pagará ella de su asignación mensual.','2');
