insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-04-13','SALIDA El 12/04/2016. Se comunica, a esa Comisión Tutelar de Adultos, que el paciente Juan Bautista Ramírez de la Rosa, ingresado en este Centro -CSS Mérida- y tutelado por esa Comisión, se ha marchado en el día de ayer de permiso terapéutico con su familia a su domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-04-15','-NO LOCALIZAMOS A JONATHAN DESDE HACE DIAS . ME PONGO EN CONTACTO CON SU HNO ANTONIO QUE NO LO VE DESDE MARZO , ME VERBALIZA QUE EL DIA 11 DE ABRIL TENIA QUE HABER ASISTIDO A UN JUICIO EN MERIDA CONTRA SU MADRE Y NO ASISTIÓ , EN CTAEX NO TENEMOS ESTA CITACION. LLAMO A SU EXNOVIA ( SUSANA ) LA ULTIMA VEZ QUE LO VIÓ FUE LA ULTIMA SEMANA DE MARZO POR LA ZONA DE ESTACION DE TREN DE BADAJOZ QUE ES DONDE ELLA VIVE CON SU FAMILIA . LE TIRÓ UN MECHERO Y ELLA SALIÓ A CORRER . CREE QUE PUEDE ESTAR CON LOS FERIANTES .','2');
