insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-15','Nos informan por teléfono (Juanjo-INFANTA) que falleció el miercoles a las 21.00 Horas. Contactamos con el jefe de celadores del infanta Fulgencio Barroso, nos informa que el cadáver se encuentra allí, como es muerte judicial no hay certificado de defunción, que la funeraria se encarga de que el forense lo emita. contantamos con la familia a través de su sobrina, la cual nos trasmite que desean que el entierro se realice en su localidad, que nos proporcionará el número de telefóno de la funeraria que quieren que se haga cargo. Intentamos comunicar con Pilar de PS de Zafra( le dejamos mensaje en el contestador) para indicarles que nos envien los objetos personales de Eusebio a la Comsión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SAUCEDO'and apellido2='AGUEDO'),'2016-04-15','-NOS LLAMAN CAISS DE MERIDA , YA RESUELTO EL EXPEDIENTE DE NUESTRO TUTELADO DE PFHC CON COMPLEMENTO DE ATP CON EFECTOS EC. 1 DE ABRIL , PTE. RESOLUCION . SE LE FACILITA NUEVO NUMERO DE CUENTA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-04-14','REGRESO El 13/04/2016. Se comunica a esa Comisión Tutelar de Adultos que el paciente Juan Bautista Ramírez de la Rosa, ingreado en este Centro y tutelado por esa Comisión, regresó en el día de ayer de permiso terapéutico con su familia en su domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-15','Acordamos con la empresa de transporte ASM de zafra (asmzafra@gmail.com) que el lunes a partir de las 8:00 horas recojan los enseres de Eusebio y los trasladen a la Comisión tutelar). Se envia email con los datos. Pendiente que envien numero de cuenta y factura. Respecto al dinero en efectivo de Eusebio acordamos con Ramon (PS-Zafra) que lo ingresen en cuenta de Eusebio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-15','A las 14:41 horas Ismael (672 67 27 93) nos informa que el cuerpo ya ha salido del hospital trasladonse a su localidad de nacimeinto en Mohedas de Granadilla. El lunes se ponen en contacto con nosotros para finalizar las gestiones de pago del entierro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-18','Nos informa Ismael (Fuenraria) que esta semana la familia elegirá la lápida, una vez tenga la factura tanto del entierro como de la lápida nos enviarán la factura','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-04-15','INCIDENCIA Y FUGA Don Hermenegildo Ruíz Romero, con DNI 53.269.058-T, tutelado por la Comisión Tutelar de Adultos de Extremadura, tras su reingreso el 13 de enero de 2016, en el Centro Residencial "Nuestra Sra. de las Cruces", sito en la Avda. Alonso Martín, nº 16, se ha fugado en trece (13) ocasiones.************************************************************************************************************El 15/04/2016, a las 08:20 Horas, Hermenegildo ha vuelto a fugarse.','2');
