insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2016-04-18','D. Emilio Gómez Cantero (679 41 22 35) abogado que está tramitando el testamento de los padres de Marisa Montaño, para comunicar que ya tiene toda la documentación entregada en la notaría donde se realizará la lectura del testamento.Que antes de fijar fecha para dicha gestión, desde la notaría solicitan una copia de la aceptación y juramento del cargo de tutor de Marisa Montaño por parte de la Comisión Tutelar. egomezabogados@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2016-04-18','INFORME FUTUEX • Medicación y pautas: ETUMINA 40 mg (0-0-1) RIVOTRIL 0,5 mg (0-0-1) DEPAKINE CRONO 500MG (1-0-1) EFFICIB 50mg (1-0-1) ADIRO 100MG (0-1-0) LANTUS SOLOSTAR 100 inyectables (insulina) ROSUVASTATINA ORAL 20MG (0-0-1) ABILIFY MAINTENA 400MG inyectable acción prolongada 8 1 al mes) discapacidad intelectual moderada. Trastorno bipolar tipo I, episodio más reciente maníaco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2016-04-18','INFORME FUTUEX: VIVIENDA Francisco reside solo en el domicilio. Pero pasa tiempo en casa de su hermano, de hecho su cuñada Francisca y su sobrina Soraya, son las encargadas de su control y supervisión. Gracias a esta ayuda, él se muestra más tranquilo, y puede llevar y cumplir con medicación y control médico, así como higiene personal. vivienda propiedad de la Madre de Juan Francisco, que se encuentra ingresada en los pisos tutelados de mayores en la misma localidad. Esta vivienda de planta baja consta de tres habitaciones, salón, cocina –comedor, baño completo, despensa-lavadero, dos patios y una cocina-trastero en el patio grande exterior. Limpieza y orden, condiciones muy óptimas de habitabilidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2016-04-18','El 3 de Febrero de 2016 tenía consulta de revisión de psiquiatría en Don Benito, pero no llego a tiempo la autorización para retirada de dinero, ya que su familia no le podía adelantar dicha cantidad. Por tanto solicitaron cambio de fecha para nueva revisión que será en Junio 2016 (pendiente de confirmar fecha) Me dicen que retiraron los 80 euros, pero pasada ya la fecha, por tanto los tiene Francisca guardados para la siguiente cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2016-04-13','INFORME FUTUEX: "Sigue negándose a realizar actividad o trabajo alguno, dice que está muy ocupada, aunque por lo que hemos podido comprobar, incluso los servicios sociales, en su vivienda poco o nada realiza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-15','Hablamos con el Dr. Ari (uhb), el cual nos indica que está ingresado, pero indica de manera isistente que desde su centro de salud y ssb le busquen un recurso apropiado, ya que es un enfermo crónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-15','Informe futuex: Inma (TS CSM ) y Paco (Psiquiatra) opinan que se debería de aprovechar un traslado a UME u bien otro centro dada las dificultades. Enviarán informe junto con copia del informe de la policia a la Comisión. (Aun no hemos recibido copia del informe policial solicitado por la comisión)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-15','Hermano Antonio Cuevas 667 955 006. SE NIEGA A QUE VUELVA AL DOMICILIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-04-18','INCIDENCIA Y FUGA Don Hermenegildo Ruíz Romero, con DNI 53.269.058-T, tutelado por la Comisión Tutelar de Adultos de Extremadura, tras su reingreso el 13 de enero de 2016, en el Centro Residencial "Nuestra Sra. de las Cruces", sito en la Avda. Alonso Martín, nº 16, se ha fugado en catorce (14) ocasiones.************************************************************************************************************Comunicar a la Comisión Tutelar que el pasado viernes, 15/04/2016, Hermenegildo regresó al Centro en ambulancia a las 02:30 Hs.********************************************************El 17/04/2016, Seguridad del Centro confirma que Hermenegildo se ha fugado de nuevo. Sobre las 10:45 Hs., una cuidadora del Centro refiere haberlo visto por una calle de Don Benito.****************************************************Una Educadora Social del Centro comunica la fuga del residente a la Policía Nacional.**************************************************14:17 Hs. Ven a Hermenegildo por la carretera hacia Medellín.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2016-04-12','Visita a la vivienda de León, sita en la calle General Margallo nº 9 (actualmente nº 13). Quiere venderla por los 40.000€ que ofrece la inmobiliaria. Se dispone de fotografías en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-03-28','Luis Miguel debe acudir al Juicio sobre delitos leves 6/2016, a celebrar en el Juzgado de Primera Instancia e Instrucción nº 5 de Cáceres, el día 11/04/2016, a las 10:15 horas. Cuenta con abogado y procurador. A su representación legal hemos enviado la citación y tras firmarla Luis Miguel en el despacho la hemos enviado al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-04-18','Se recibe CITACIÓN por fax (927-620410). JUZGADO 1ª INSTANCIA e INSTRUCCIÓN Nº 5. CÁCERES. HORA: 10:00h. Procedimineto LEV 6/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-04-12','Reunión con Ventura en C. Salud de Cáceres-Centro, junto con Cristina, de FUTUEx (no aceptó acudir a su vivienda para hablar con él y conocerla).En el Centro de Salud se unió a nosotros Laura Casero, Enfermera que conoce mucho a Ventura, y que opina que no puede ser que pierda la vivienda porque si es así, es porque alguien se ha aprovechado de él. Contamos tanto con la colaboración de Laura como del Médico del Centro de Salud, Antonio Floriano. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Acompañamos a Ventura a ver al abogado con el que había contactado a través de un amigo común, Julián Cambero Valencia (927-243872 y 687-838616), quien dijo interesarse por el caso de forma altruista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-04-12','Conozco a Jesús en Cáceres, con quien quedamos Cristina y yo en el Casco Antiguo. Está lloviendo, y acude acompañado por un amigo. Lleva una gran mochila cubierta por un impermeable. Quiere renovar el carnet de conducir. Comprobar en ESM si la medicación puede ser incompatible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-04-15','Reunión con Carmen Barquilla, Fuscal de Cáceres. Ha hablado con la Jueza sobre Bargón y están valorando solicitar una comparecencia. Se le informa sobre la demanda de Jesús de querer renovar el carnet de conducir, posibilidad esta que nos preocupa y propone que la Comisión solicite como medida cautelar una valoración de su capacidad en base al artículo 762 de la LEC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-04-14','Visita domiciliaria, junto con Cristina de Futuex. Cuestiones pendientes: +++Estado de su brazo: no quiere operarse ni ir a ningún especialista privado (no quiere gastarse más dinero). +++DEPENDENCIA. Valorado con Grado I. Hablo con Clara 18-04-2016) para que agilicen PIA para SAD. +++No está contento con la actual Auxiliar de Hogar (contratada), pero tampoco quiere prescindir de ella). +++Llamar a maxilofacial del Infanta para ver qué pasa con su cita. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablamos con Encarna, T.Social del Centro de Salud. Cree que Francisco no quiere colaborar en nada, que quiere que todos estemos pendientes de él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-04-19','Llama Carmen, T. Soc. del CAMP (924-021574). Hermenegildo apareció ayer en Guareña. Llevaba una pierna en mal estado y está ingresado en el Hospital de Mérida.','2');
