insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-20','Recibimos fax de ESM (924 80 20 06) en el que nos envian las diligencias policiales 1.660/2016. Amenazas con un cuchillo a una vecina, Francisco reconoce los hechos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-20','Hablamos con Inma del ESM. nos informa del protocolo que puede realizar desde ESM. Solicitar una Comisión Sociosanitaria(se realizan 2 anuales, la última, en diciembre de 2015), podría trasncurrir 6 meses. Se puede tomar una decisión de ingreso en UME, la cual sería vinculante. Para entrar en UME Francisco debería voluntariamente acceder a una entrevista, sino acude, no se realiza ingreso. Desde UHB, se puede derivar a UME O UHR. Mañana jueves inma hablará de nuevo con el hospital. En la actualidad Francisco está compensado, se pone los inyectables mensualmente, y a pesar de ello ha intentado agredir a varias personas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-19','Entrevista con el Dr. Alí, en la UHB de Mérida. Considera que D. Francisco es un caso crónico que debería estar en la Unidad de Crónicos. En su opinión no tiene perfil de UME y debería ser derivado a Crónicos por el ESM de Vva. de la Serena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-04-21','Se notifica por fax al Juzgado de 1ª Instancia nº 2 de Cáceres el desconocimiento del paradero actual de Jonathan y su incomparecencia en el Servicio de Gestión de Penas de Badajoz el pasado 19 de abril.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-04-19','Autorización Pedro, 200€ a Víctor Martín Rodríguez, padre de Minerva. Última autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-04-21','Telefonea la madre de Jesús (657 947818) para q preguntarnos por Jesus e informarnos que asmistades suyas, le ha comentado que jesús duermen en un cajero, y que está pidiendo dinero. Nos recuerda que la ropa la lleva limpia porque todas las semanas su yerno recoge la sucia y le lleva la limpia ya planchada. siempre acude con una mochila caragada a los encuentros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUSEBIO'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENO'),'2016-04-21','factura entierro y lápida 6089,61€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-04-21','Contacta la hermana con nosotros para conocer la situación de su hermano , ya que su madre está preocupada. Se le informa que desde la comisión no se da información. Nos comunica que no quiere que su hermano piense que desentienden de él. Aprovechamos y le recordamos que su familia imcumplió el acuerdo en semana santa de acogerlo durante 5 días en su localidad del Jerte. Nos informa que tras hablar ella con Consuelo (Cáritas) le informó esta que no sabría a que centro iría, por lo cual a ella le entró el miedo de que se quedase de forma indefinida en Jerte. Le comunicamos que esa motivación nos la debería haber comunicado a nosotros. Que si José María quiere ponerse en contacto con ellos, no existe ningún problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-04-21','Se envia desistiemento de valoración de grado a gerencia territorial de badajoz. dependencia II.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-04-21','El Sociosanitario de mérida, presenta solicitud de situación de Dependencia y del Derecho a las Prestaciones del Sistema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-04-14','Don Hermenegildo Ruíz Romero, con DNI 53.269.058-T, tutelado por la Comisión Tutelar de Adultos de Extremadura, tras su reingreso el 13 de enero de 2016, en el Centro Residencial "Nuestra Sra. de las Cruces", sito en la Avda. Alonso Martín, nº 16, se ha fugado en doce (12)ocasiones.************************************************************************************************************Comunicar que Hermenegildo regresó al Centro en el día de ayer, miércoles, 13 de abril sobre las 00:30 Hs. En el día de hoy, según refiere uno de sus educadores de referencia, ha estado trabajando bien en el Taller de Granja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-04-21','el 20 de abril se inician los trabajos de limpieza en la casa de Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-04-21','Raquel, trabajadora social de Guadalupe, junto con Juan, iniciarán la solicitud al juzgado de paz en Guadalupe, el certificado literal de defunción de los padres de Juan, (creen que su madre ha fallecido en Talayuela, e intentaran que sea el mismo juzgado quien pueda pedirlo allí, si aquí no existe copia) y como no hay copia de libro de familia, se solicitará certificado literal de matrimonio de sus padres y del nacimiento de Juan Chamorro. En relación al D.N.I caducado de Juan, dice Raquel que a Guadalupe equipo móvil de la policía para realizarlo no suelen ir y que puede tardar muchísimo tiempo. Que debe de pedir cita en Cáceres para que se lo hagan, sobre todo si se le está gestionando documentación y necesite copia de dicho D.N.I, estando caducado puede haber problemas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-04-21','Envia presupuesto de lentes. Ha solicitado varios presupuestos en diferentes opticas, en unos montura, en otros lentes.....por lo cual hablamos con él, le solicitamos que vaya a su médico de atención primaria para que le derive a oftalmología, por pérdida de visión y remita informe.','2');
