insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-04-22','-Ayer sobre las ocho de la tarde el TS del CTRo de transeuntes de Mérida donde se encontraba Hermenegildo desde el lunes lo encontró fumando marihuana en la habitación. Se le comunica que puede pasar la noche y en la mañana de hoy tiene que irse porque esta falta es motivo de expulsíon.Al prohibirle que esa noche salga del centro coge sus cosas y se marcha , verbaliza que ha dormnido en cajero pero no lo podemos confirmar. Hoy acude al SEPAD solicitando un nuevo recurso , se le ha buscado habitación en el Hostal salud (924312259) y comida en el Bar Escalerita ( enfrente ) hasta el lunes que se determinará otra solución. Se le acompaña personalmente hasta el hostal .','2');
