insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2016-04-20','Reunión en el CSS de Mérida con Antonio (padre), María (pareja de Antonio) y el hijo común, hermano de Almudena. Asisten Juan Pedro (Psicólogo), Soraya (Ter. Ocup.), Blanca (T. Soc.) y por la CTAEX Pedro.++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ CONCLUSIONES: +++++En la reunión se describió a Almudena de la siguiente manera:La desorganización cognitiva y conductual es su principal rasgo de personalidad, tiene una esquizofrenia desorganizada; requiere atención individualizada permanente durante todo el día; su evolución está siendo buena, con periodos cada vez más frecuentes de conciencia clara y autocrítica, aunque presenta también una enorme variabilidad de un día para otro. Requeriría sistemas de entrenamiento individual para el cual no existen los recursos necesarios. En el CSS tiende a responder de manera "contenida" y si se le responde de forma adecuada suele reaccionar con calma. Tiene una personalidad infantil, busca la satisfacción inmediata de sus deseos y está muy necesitada de afecto. +++++Se dan pautas para que María "acepte" a Almudena cuando vaya a casa (creo que va a ser difícil porque Almudena no es previsible que ponga de su parte en ello). +++++Se deja explícitamente dicho que Almudena no puede volver a vivir sola como en periodos anteriores, por lo que las alternativas, llegado el momento, podrían ser CRR y en un paso psoterior pisos supervisados según la evolución de Almudena. +++++Blanca solicitará la revisión de grado I por empeoramiento.','2');
