insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-04-19','SALUD 20/01/2016. Acudimos para preguntar si tiene que seguir tomando su medicación para el estómago y pedir un volante para la analítica de revisión de los 6 meses. La última vez que fue al digestivo fue el 04/06/2013, y le mandan hacerse una prueba (tránsito). Tenía que volver a por los resultados el 14/06/2013. Tiene diagnósticada dispepsia funcional porque tiene reflujo y eso hace que tenga malas digestiones. Debe seguir con el mismo trtamiento. Próximas citas: 1.- Analítica de orina y sangre: 28/01/2016, 9:15 Hs.; 2.- Resultados analíticas: 04/02/2016. 9:30 Hs.; 3.- Digestivo: 05/10/2016. 11:10 Hs. **************************También nos dice las próximas citas que tiene programadas: 1.- 05/04/2016: Neurología; 2.- 06/07/2016: Neumología telemedicina; 3.- Cardiología (esta cita hay que cambiarla el día que vaya a hacerle el Holter, porque es mucho tiempo para recoger los resultados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-04-19','SALUD 25/02/2016. MAP. Vamos para pedir que le mande radiografía del cuello porque le dijeron que lo tenía muy rígido. También le comentamos lo de los vértigos. Le aconseja que no esté tanto tiempo seguido con el ordenador y que haga descansos entre medio y se levante. Nos da un papel con información para una correcta higiene postural. Nos da volante para radiografía. Próximas citas: 10/03/2016 a las 11:45 Hs, radiografía y a las 12:00 Hs. resultados con su médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-04-19','SALUD 19/02/2016. Urgencias, Cristina. Acude a urgencia porque se mareaba y vomitó. El médico le exploró y le fijo que eran vértigos, que tomara dogmatil 50 mg. cada 8 horas durante 4 o 5 días, aconsejándole que visite a su médico de familia. He pedido cita para su médico para el jueves 25/02/2016, a las 11:33 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-04-19','SALUD 05/02/2016. Resultados analítica. Tiene las plaquetas bajas, pero dentro del límite. Sodio alto, pero dentro del límite. Niveles CPK, altos (creatinquinasa). La última vez los tenía más bajos, aunque anteriormente los tenía igual de altos. Debe beber mucha agua, hacer deporte y tomar poca sal.','2');
