insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-04-19','SALUD 18/03/2016. Paddi. Le hacen limpieza y tiene que enuagarse con colutorio durante 15 días. Revisión al año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-04-19','SALUD 10/03/2016. Radiografía y MAP. Tiene mucha curvatura cervical y costillas cervicales. Le hemos comentado lo de los dolores de espada y le han visto que tiene una curvatura. Le receta paracetamos 3 veces al día y 1/2 Valium por la noche como relajante muscular, y que se aplique calor seco en la zona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-04-27','- se concierta con TAXI MERCEDES (924270527) de Badajoz el transporte para que mañana lleve a su hna y familia a un vis a vis al centro penitenciario . Mandará la factura el taxista para abono por transferencia . No se le manda dinero a la familia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-27','Reunión de la subcomisión de casos (UHB, UME, Subd. General de Salud Mental y CTAEx). CONCLUSIÓN: ++++++++++Derivar a UME (pdte de plaza en estos momentos) y posteriormente a URH.Plazo para ingreso en UME: 2-4 semanas. Mientras tanto alta clínica y marchar a casa (La CTAEx espone en la reunión las dificultades que ello puede implicar, así comno la negativa de la familia a que vuelva a la casa). ++++++++++++Hablar con la familia para pedir su colaboración. ++++++++++++Una vez haya plaza en UME, el ingreso se hará por parte del ESM o de la UHB. ++++++++++++Desde UHB solicitarán Valoración Dependencia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Antonio, hermano de Francisco: oposición inicial absoluta al regreso de Francisco. Con el planteamiento mantenido en la reunión, accede a que vuelva durante esas 2-3 semanas previas a UME. Le doy el teléfono del ESM de Villanueva como Rosa (Psiquiatra) me ha propuesto.La llamará.No comentará nada con su hermano ni con nadie la solución final de plaza en centro.','2');
