insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-03','Conversación con Juan Antonio (924-312259), dueño del Hostal Salud. INCIDENTES del fin de semana:desde que está allí pide dinero a los clientes (el dueño le ha advertido de que no puede hacer esto, advirtiéndole de expulsión si sigue así); se ha denunciado la desaparición de un móvil de un cliente; pide dinero también en el bar la Escalerita. Todo ello da muy mala imagen de ambos establecimientos. El sábado por la noche salió a las 2 de la madrugada a pesar de que el dueño le desaconsejó que lo hiciera y volvió a las 4. Otro día acudió en ambulancia. El dueño me dice que se puede quedar una noche más, pero que no puede mantener a una persona con ese comportamiento. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hermenegildo ha venido a primera hora de la mañana y a las 13h. En ese intervalo de tiempo he hablado con el Padre Fernando, de la Casa de la Misericordia de Pinofranqueado (927-674303. Correo-e: aromasdecaridad@hotmail.com) y con Julia, Terapeuta de la de Alcuéscar (927-120024. Corre-e:casadelamisericordia.alcuescar@gmail.com): en ninguna de las dos hay plaza vacante en estos momentos, pero en Pinofranqueado se prevé que la haya próximamente y envío el informe correspondiente al Padre Fernando. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Condiciones "impuestas" a Hermenegildo:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-04-28','REunión en la Comisión con Rosa, hermana de Jesús y con Juan Carlos Mozo Mena (927-628224), su cuñado. Se informa de la situación en la que se encuentra su hermano y de las gestiones realizadas para mejorar la misma, contando siempre con la absoluta falata de colaboración por parate de Jesús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-05-03','Llamada de FEfi, T. Soc. de SSB de Usagre (625-490979). El pasado jueves, 28 de abril, acudió el Técnico Pia para negociar prestación. Les indicó que estaba tutelado y que ello correspondía a la Comisión Tutelar','2');
