insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-05-04','Llamada a Natividad Hdez, Jefa de Sección de Dependencia (Zafra, 924-556010). Nos envirá las alternativas de PIA para firmar y remitir.Le doy mi correo electrónico para ello (remitir la firma de la misma manera).','2');
