insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-05-04','SALIDA Entre el 03/05/2016 y el 06/05/2016. Celebración, en Castuera, Badajoz, convivencia final de los JEDES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2016-05-04','Llamada de Dª María. Está muy "agobiada" por los continuos caprichos de su hijo: "Ahora quiere una bicicleta y yo no se la puedo pagar...Aún me debe 1000€ que me tiene que devolver...". No cree que tenga que estar en un centro ingresado, pero si continua así no quiere seguir agunatando: "Dice que quiere que la Junta deje de controlarle y controlar su dinero...". +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Juan Manuel: le recuerdo que su madre no tiene la culpa de que esté incapacitado,ni de que la Junta le controle sus cuentas, sino que ha sido el juzgado el que ha decidido que sea así. Y que si quiere que se le retire la tutela, pude ir aljuzgado correspondiente y soliciotarlo al juez, teniendo en cuenta que si los informes sobre él son negativos (por comportarse mal con su madre, etc...)el juez no le va a quitar la tutela. Parece conforme con la posibilidad de hacer esta petición al juzgado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo de nuevo con Dª María para saber si en algún momento se ha mostrado agresivo: me dice que a veces se pone fuerte. Le indico que si sucede, llame a la Policía y lo ingresarían en el Hospital. Le digo que nos llame klas veces que haga falta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='TOLEDO'and apellido2='SERRANO'),'2016-05-05','Se hace entrega de los efectos personales de Dª Pilar, reflejados en el acta firmada, a D. José Carlos Ruiz González, abogado del gabinete de Ruiz&Reynolds, en repersentación de DªTeresa Castaño Gallardo, única heredera de Dª Pilar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NELSON JOSE'and edp.apellido1='CAMPOS'and apellido2='DIAZ'),'2016-05-05','El CSS de Mérida comunica en el día de hoy, por fax, la "fuga" de Nelson, producida ayer a las 18h. A las 11:51, por fax, nos comunican su regreso al centro a las 02:30h de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-05-05','Llamada de Mamen, Técnico PIA de Zafra (924-552033). D. Arturo tiene un Grado I. PIA propuesto: ingreso en centro. Ël no quiere dejar su casa. Ver I.Soc.de Fefi (T.Soc. de Usagre) y ponderar SAD. Volver a llamar a Mamen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-05','Se envía informe por fax al Juzgado de 1ª Instancia nº 2 de Castuera, comunicando la situación actual de Hermenegildo y las últimas gestiones realizadas.','2');
