insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2016-05-06','Llamada de Juan (924-366582) para saber si ya somos tutores de su hermano. Se le informa de qué significa que los seamos. Está pendiente la visita domiciliaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-05-06','RECONOCIDO GRADO I (a continuación, correo-e de Mamen, Técnico PIA). ................ Hola Pedro: Te envío información acerca de ARTURO ROCHA MERCHAN, del cual hemos estado hablando esta mañana.................. He estado revisando más a fondo su situación y desde el Sepad se le ha reconocido grado I según Baremo de Dependencia, por lo que según nuestra cartera de servicios, no podemos ofrecerle desde aquí una plaza residencial, por tanto, en su PIA, le podemos ofrecer:....................... PRESTACIÓN ECONÓMICA VINCULADA AL SERVICIO DE AYUDA A DOMICILIO, con una intensidad de 20 horas mensules conforme la grado I y una cuantía de 162,76 euros el mes con el fin de completar al Servicio de Ayuda a Domicilio Municipal..................... PRESTACIÓN ECONÓMICA VINCULADA AL SERVICIO DE PROMOCIÓN DE LA AUTONOMÍA: CON UNA CUANTÍA DE 300 EUROS MENSUALES, CON LA INTENCIÓN DE QUE UN TERAPEUTA OCUPACIONAL PUEDA TRABAJAR CON ÉL HABILIDADES SOCIALES Y ACTIVIDADES DE LA VIDA DIARIA......................... Desde aqui no se le puede ofrecer la plaza residencial, pero si es lo más conveniente para él según su situación, se le podría tramitar desde otra via, por ejemplo via Decreto y mientras se le asigna plaza, puede estar en casa disfrutando de la prestación de dependencia........................ De todas formas, estamos en contacto para ver cómo lo hacemos. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-06','Llamo a Carmen (CAMP. 924-021574): de momento se está comportando correctamente. Están viendo ya el tema del dentista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2016-05-06','Llamo a Dª María. Se pone Juan Manuel. Su madre ha salido a comprar y se ha dejado el móvil en casa. Le pregunto si está más tranquilo que el otro día y me dice que sí, que las cosas son así y si no se puede hacer de otra manera qué le va a hacer (por su tono de voz parece calmado y dialogante). Me dice que si quiero hablar con su madrte la llame a la hora de la comida. En eso quedamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-05-03','Mediante fax (927-158093) del juzgado de 1ª Inst. e Inst. de Logrosán se nos remite informe médico-fornese de fecha 25-04-2016 de D. Juan, en el que se concluye que "Salvo que un último intento de abordaje por la medicina de Atención Primaria y por los Servicios Sociales de Base , fueran capaces de reconducir su residtencia a seguir adecuadamente el tratamiento médico, entendemos que EL DETERIORO PERSONAL MENCIONADO ACONSEJARÍA SU INGRESO EN UN CENTRO RESIDENCIAL que garantice los cuidados médicos y personales que necesita ¿por su diagnóstico?" (ver en expediente). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Al habla con el Juzgado, nos indican que desde el mismo, de oficio, se está valorando una posible ampliación de la incapacitación, dado que en estos momentos se trata a todos los efectos de una curatela en el ámbito de la salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2016-05-06','Llama María, T. Soc. CSS Mérida. Se ha derivado a D. Manuel a los pisos supervisados (chalets) del CSS de Mérida, como paso previo a su derivación a pisos supervisados externos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2016-05-06','Acaban de recibir sentencia del juicio de Jose Mª/ Jairo. L envía por fax. Plantea retornar a José Mª al CSS de Plasencia dado que se anula la orden de alejamiento. Le digo que no lo hagan antes de tener claro dicha posibilidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-05-06','Reunión con Valentín y Genoveva. Nos pasarán a la CTAEx el contrato anual de la plaza de Margarita. Debe renovarse cada 12 meses, de lo cual hemos de estar pendientes. Las factiras emitidas mensualmente nos las pasarán directamente de contratación para que las certifiquemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='PIRIZ'and apellido2='GONZALEZ'),'2016-05-04','TRASLADO El 04/05/2016. Al Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-05-09','Llamada de Tomás Molina, T. Soc. del C . de Acogida "Padre Cristobal" (692-627207). Fijamos reunión para mañana, 10 de mayo, a las 10:00h en el Centro.++++++++++++++++++++++++++++++++++++++El pasado jueves José Mª dijo que se quería marchar, porque se sentía abandonado por todos: familia, tutores, los compañeros del Centro...). A esto seguramente ha contribuido la negativa de su hermana a tenerlo durante la Semana Santa y el tiempo que lleva en este Centro sin que se le ofrezca alternativa alguna, a pesar de las gestiones de CTAEX. A todo ello se le ha unido que en la excursión realizada el pasado miércoles 4, se produjo una indisposición grave de uno de los residentes en el Centro que trastocó completamente la dinámica de la actividad, quedándose José Mª en LLerena despistado y sin que nadie de la excursión se diera cuenta de ello. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Ana Benavente (T.Soc. ESM Plasencia) para convocar subcomisión de casos y buscar recurso para José Mª. Me llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-05-09','Llamada de Dª Isabel (madre), preocupada porque le han dicho que lo han visto en malas condiciones. Dice estar dispuesta a pagarle un alquiler o un hostal... +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Mª José Gómez del Castillo, Psiquiatra del ESM de Cáceres (927-213730). CONCLUSIONES:última visita el 21 de abril de 2016; según el propio Jesús, no existe actualmente ningún tipo de consumo de sustancias; acude a las consultas clínicas con buen aspecto, T. Bipolar estabilizado, persiste se T. de Personalidad Paranoide. Lo ha pasado al protocolo de TMG, para que la T. Social le busque recurso de tipo CRR, al cual él siempre se ha negado a ir, reclamando siempre un piso de tres habitaciones para poder estar allí con sus hijos.+++++ La próxima visita era dentro de tres meses (pendiente de citar), pero le va a pedir a PIlar, T.Soc. (ahora de baja) que lo cite antes dentro del protocolo TMG. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Juani, dueña del Hostal "Las Veletas" (927-211210), para ver la posibilidad de que pueda quedarse en el Hostal que tiene su hermana en Cáceres: "No quiero "cargar con un caso así a mi hermana porque me han dicho que está en muy malas condiciones y que se droga..." (Esta alternativa se plantea con la idea de que sea la madre de Jesús la que pague este alojamiento).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-05-09','Hablo con Asun sobre la posible conveniencia de que Carmen vuelva a un recurso residencial, tanto por suestiones personales y de salud (autocuidados, habilidades socilaes, etc.) como económicas (se plante la posible venta de la casa de Valdecaballeros, no sin antes hablarlo con Carmen). Está de acuerdo, y la vía puede ser contacto con el ESM, o bien convocatoria de suibcomisión de casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-09','INCIDENCIA El 06/05/2016. 20:10 Hs. Entra una ambulancia del 112, trae a Hermenegildo desde Cabeza del Buey.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-09','INCIDENCIA El 07/05/2016. 15:40 Hs. Un educador comunica que Hermenegildo está desaparecido del Centro.***************** Sobre las 19:17 Hs., llama la Policía Municipal de Villanueva de la Serena para comunicar que tienen detenido a Hermenegildo en la comisaría. La Policía informa que el residente iba en una bicicleta. Desconocemos si fue robada o hallada en un contenedor, pues Hermenegildo da distintas versiones de lo sucedido.********************************** Desde nuestro centro, se avisa a un taxi para que un Educador vaya a buscar a Herenegildo.********************** A las 20:17 Hs., Educador y residente regresan al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='MORENO'and apellido2='CARRASCO'),'2016-05-10','FALLECIDO El 09/05/2015.','2');
