insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-05-10','Visita realizada por Pedro a José Mª en el C.A."Padre Cristóbal". Está bastante enfadado por el tiempo que lleva sin una plaza, desde que tuvo que dejar el CRR de Plasencia por consumo de sustancias. Se le explican las gestiones realizadas por la CTAEx y nuestro compromiso para encontrar un recurso adecuado a su situación. En la reunión estápresente también Tomás Molina, T. Soc. del Centro. Plantea que, si la obtención de recurso público (CRR, Pisos supervisados) se retrasa, cabría la alternativa, si se dieran los requisitos, de ofertarle si la hubiera, plaza en los pisos que Cáritas tiene en Mérida. José Mª no quiere CRR, solo se plantea pisos supervisados. Seguimos con las gestiones para obtener plaza en la red de Salud Mental, a través del ESM de Plasencia.','2');
