insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2016-05-11','SUSPENSION ACTUACIONES El 11/05/16. Llamada de Curro, Gabinete Jurídico. Nos informa que va a intentar recurrir la sentencia de Incapacitación. A petición suya, hemos de parar todos los trámites hasta nuevo aviso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='GARCIA'and apellido2='DE PRUNEDA TREVIJANO'),'2016-05-12','Ha domiciliado su pensión en una cuenta bancaria del Banco Santander. Según los servicios jurídicos del Banco, su curatela no le impide realizar estas gestiones. Hemos solicitado al Juzgado que lo incapacitó, que nos aclaren el alcance de la curatela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2016-05-12','El Programa de Familia de la Mancomunidad Tajo-Salor, puso en nuestro conocimiento que un sobrino de Felisa, estaba haciendo gestiones en notarías de Montánchez y Arroyo de la Luz, para hacerse con el testamento que hizo el padre de Felisa, D. Manuel Felipe Baz. El testamento se encuentra en la notaría de Montánchez, pero nos indican que hay un error en el segundo apellido del padre, apareciendo Díaz, en lugar de Baz. Hemos solicitado a últimas voluntades (adjuntando el DNI de D. Manuel y el certificado de defunción), que nos indiquen si hizo testamento y donde. Asimismo, la madre de Felisa, Dª. Paula Teomiro Bonilla, hemos solicitado certificado de defunción, falleció en Casar de Cáceres, el 13/3/2012). Una vez que tengamos esta información, solicitaremos al Registro de Cáceres, las propiedades a nombre de los padres, que según sabemos, se trata de una vivienda en Navas del Madroño. Todo esta documentación, a los efectos de tramitar la herencia de los padres de Felisa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2016-05-12','A través de la Oficina Liquidadora del Impuesto de Sucesiones de Zafra, se nos hace llegar dos impuestos que debe pagar Juan, en concepto de las herencias de sus hermanos Francisco y Gabino. Ambas liquidaciones no son definitivas. Según esta oficina, ambas herencias se tramitaron en 2012 y 2015, respectivamente, sin haber intervenido esta Comisión. Estas herencias se hicieron con dos poderes notariales, concedidos por Juan a su hermana María, para intervenir en ambas herencias. Nos hemos hecho con copia simple de ambos poderes, para revocarlos, ya que los hizo estando ya incapacitado y tutelado por nosotros. Las gestiones para la revocación se están llevando con la notaría Los Maestros de Mérida. Las herencias, según el notario de Los Santos de Maimona que intervino en ellas (tenemos las copias simples) se realizaron correctamente, tan solo que no intervenimos. Consecuencia de una de ellas, Juan hereda, a parte de inmuebles, una cantidad de dinero que tenía su hermano Gabino en Liberbank de Los Santos de Maimona(924544402) (15.117,03 euros, que estamos reclamando).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2016-05-12','Seguimos intentando obtener la Declaración de Herederos del marido de Victoriana y padre del también tutelado nuestro, Martín Miranda Hernández, con la notaría de Cáceres, 927240577 (David). Se envió toda la documentación necesaria para ello. Esta documentación es necesaria para tramitar la herencia de Rafael. La estamos tramitando junto con un abogado, Gaspar Guerrero (de Villanueva de la Cañada, Madrid. 918117478-620738843). Él será también quien gestione el cambio de titular en la piso de Fuenlabrada, que aún sigue a nombre de Pilotos Reunidos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-12','El Juzgado de Primera Instancia e Instrucción nº 2 de Castuera, se inhibe en el procedimiento de internamiento 18/2016. Remiten las actuaciones al órgano judicial correspondiente de Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-05-12','Se le cita en el Juzgado de Primera Instancia nº 1 de Mérida, el 31/5/2016, a las 11:00, para reconocimiento forense por delito de lesiones. P.A. 732/2015.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-04-29','INFORME DEL 25/04/2016, SOBRE INTERVENCIONES POLICÍA LOCAL** En relación con la intervención realizada el pasado 2 de marzo de 2016 en el Parque de Consquistadores, se informa que: Que sobre las 17.58 horas del día indicado, se recibe llamada telefónica al parecer de una menor de 15 años de edad, la cual se encuentra filiada en estas dependencias policiales y manifiesta "encontrarse en el parque de la Pl. de Conquistadores en compañía de una amiga y hay un hombre que en otra ocasión la tocó el culo, que la está acosando; temiendo que hoy pretenda hacer lo mismo". Personados el Oficial con registro profesional nº 01.15.39 en compañía de los Agentes con registro nº 01.153.18 y 01.153.53; los cuales se entrevistan con la menor, repitiendo lo mismo que comunicó por teléfono indica que, ese hombre "se encontraba sentado en un banco en el interior del parque". Se procede a su idetificación, resultando ser: FRANCISCO CUEVAS LÓPEZ con DNI 0916946 nacido el 1/03/1962 hijo de Antonio y Petra y con domicilio en c/ Arias Montano, nº6 bajo de esta ciudad.*************************************** Durante la intervención, se le cachea, ocupándole en un bolsillo de la sudadera que vestía, cuatro bolsitas conteniendo lo que parece ser Marihuana.******************* Posteriormente se solicita la presencia de Policía Nacional, quienes personados y una vez informados tanto por la menor, como por el padre de la misma, se personó en la zona y ratificó los tocamientos que hace unos cinco meses había sufrido su hija por parte de este individuo, y éste manifiesta la intención de denunciarlo.*************** Por parte de los miembros actuantes de esta Policía Local, se comparece en la oficina de denuncias de la Policía Nacional. Procediendo los miembros de la Policía Nacional al traslado del acosador a Comisaría.********************** Así mismo, se hace constar que en esta Policía Local se tiene copia de un Auto del Juzgado de Instrucción nº 2, de esta ciudad, con número de diligencias urgentes/juicio rápido 0013/2016 donde consta la Prohibición de Acercamiento de FRANCISCO CUEVAS LÓPEZ a la vecina PETRA NARANJO OLIVARES, con domicilio en calle Navegante Juan Morcillo número 16.**************************************** Igualmente por parte de miembros de este Cuerpo, al informado, se le han realizado cuatro actas de Intervención de Sustancias Estupefacientes, las cuales han sido remitidas a la Delegación del Gobierno de Extremadura (Área funcional de Sanidad control de Estupefacientes) de Badajoz, siendo éstas en las siguientes fechas: El día 03/06/2015, mientras se encontraba sentado en un banco en el Parque del Rodeo, le fue intervenido un cigarrillo con una sustancia al parecer "Marihuana". El día 22/09/2015, mientras se encontraba en el Parque de los Conquistadores, le fue intervenido un cigarrillo con una sustancia al parecer "Marihuana". El día 21/10/2015, mientras se encontraba sentado en un banco en la calle San Francisco, se estaba liando lo que pudiera ser un "porro", encontrándole una bolsita conteniendo lo que pudiera ser "Marihuana". El día 02/03/2016, en un control realizado en el Parque de los Conquistadores, le fue intervenido cuatro bolsitas con lo que parecen ser cogollos de "Marihuana".*********************************** Se quiere hacer constar que con el informado se interviene frecuentemente por hechos relacionados con molestias, produciendo intimidación y situación que generan temor en los ciudadanos.******************************************** Además se conocen comportamientos de acoso exhibicionismo a distintas mujeres a lo largo de muchos años en el entorno del barrio, a quienes han producido daños psicológicos y viéndose obligadas a cambiar su forma de vivir, no formulando denuncia por miedo a las represalias.* Informe firmado por el oficial de la Policía Local nº. 01.153.15, en Villanueva de la Serena, a 25 de abril de 2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-12','Hablo con Mamen, T. Soc. del SSB de Jerez. No hay hasta estos momentos incidencia alguna en relación a Ramón. Se le comenta la situación de un amigo al que Ramón le deja quedarse en la casilla que tiene en el campo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2016-05-12','Solicitamos al Registro de la Propiedad de Zafra, notas simples de las propiedades de Andrea. Las hemos recibido y las correspondientes a las urbanas, no coinciden con los datos que tenemos del Ayuntamiento. Mañana (13/05/2016), vuelvo a llamar al Ayto de Fuente del Maestre, para hablar con el padron municipal y me lo aclaren.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-05-12','Ejecutoria 397/2015.Jonathan se ha presentado esta mañana sobre las 09:30h en el Servicio de Gestión de Penas de Badajoz, donde la Comisión había quedado con él a las 10:00h. Un cuarto de hora antes nos hemos presdentado allí, y las T. Sociales nos han comentado que ya se había marchado. Nos facilitan copia de la información que le han dado a él sobre el cumplimineto de la pena (ver doc. escaneado en expediente): ENTIDAD: AYTO. DE MÉRIDA;ACTIVIDAD: APOYO A OPERARIO DE JARDINERÍA; HORARIO: DE 08 a 14:00h (de lunes a viernes, a doble jornada); INICIO EJECUCIÓN:18-05-2016.POLICÍA LOCAL: Oficial encargado nº 276 (924-380138).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-05-12','Se le cita en el Juzgado de Primera Instancia nº 1 de Mérida, el 31/5/2016, a las 11:00, para reconocimiento forense por delito de lesiones. P.A. 732/2015.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2016-05-11','-Se envia contrato a la RM de Guadalupe con el coste de 1300€ para que puedan tramitar la prestación vinculada ( se le ha reconocido GII) . -Se ha recibio el Informe social de la TS de la RM','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2016-05-13','Hemos solicitado al Ayuntamiento de Fuente del Maestre, un certificado aclaratorio a cerca de dos propiedades de Andrea. En el Registro de la Propiedad vienen con un domicilio y en el certificado del ibi viene con otro. Consultado con el Ayuntamiento nos indican que se trata de los mismos, pero no coinciden porque el catastro da unos números y el registro de la propiedad otros.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2016-05-13','Hoy volvemos a enviar a la notaría, la documentación relacionada con la solcitud de la Declaración de Herederos, porque no la encuentran.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2016-05-13','Manuela Glez. solicita información sobre la situación familiar de Alberto en realción a la convenciencia o no de asignar plaza de RAE con mayor proximidad al domicilio familiar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ En conversación con Ana (Psicol. de Placeat 927-421950), considera que Cáceres ciudad no sería una alternativa aconsejable por el riesgo de que Alberto, al conocer el entorno, pudiera "escaparse" y no tenerlo localizado. En localidades más o menos próximas no supone problema alguno, dado que es más Alberto el que solicita el contacto familiar (que es muy positivo para él), más que la propia familia: su padre lo ignora prácticamnete cuando acude pero su madre sí le demuestra una gran afectividad. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++SE comunica a Manuela y Maite esta información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-05-12','Hablo con Mamen, T. Soc. del SSB de Jerez. No hay hasta estos momentos incidencia alguna en relación a Ramón. Se le comenta la situación de un amigo al que Ramón le deja quedarse en la casilla que tiene en el campo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-13','Contacto con el Padre Fernando: tiene en cuenta la solicitud de plaza para Hermenegildo en cuanto disponga de plaza en el Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-05-13','Conversación con Tomás, T. Soc.del C. "Padre Cristóbal" (924 30 26 18): +Se le informa de las gestiones realizadas desde CTAEx. +Enviará informe de la estancia de José Mª en el centro, proponiendo como alternativa, en caso de que la adjudicación de plaza en Centro se retrase, la estancia en el piso que el Centro tiene en Mérida. +Acompañarán a José Mª el próximo día 30 de mayo a la consulta del ESM de Plasencia (he pedido a este Equipo que envíen comunicación de dicha consulta). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ SE pasa el caso a la Subdirección de Salud Mental. En contacto también con el ESM de Plasencia, comentan que se va a convocar una subcomisión de casos para buscar recurso adecuado a D. José Mª. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Tomás, T.Soc. del C. "Padre Cristóbal" informando de las últimas gestiones, así como solicitando a la coordinadora del Centro el nº de cuenta para hacer el pago por la estancia "prolongada" de D.José Mª.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2016-05-13','Llamada de David Labrador (686-409644), abogado de Paloma. Dice haber mandado un fax solicitando la documentación de la incapacitación por la que se "autoriza la limitación de las cuentas de Paloma, porque ella no entiende lo que le pasa y no tengo dicha documentación para explicárselo". Le pregunto si Paloma lo ha contratado para una remoción "o lago así", pero me dice que no, que simplemente se lo ha comentado para que se lo aclare...Volverá a enviar el fax mencionado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='SANTANTON'and apellido2='GOMEZ'),'2016-05-11','- SE ENVIA APROSUBA6 LAS SOLICITUDES DE PFHC+ P.ORFANDAD PARA SU TRAMITACION Y POSTERIO ENVIO PARA SER FIRMADA POR LA GERENTE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-05-13','llama JUan Carlos (618-049726), el cuñado de Jesús: "Pedro, sintiéndolo mucho, porque se que estáis haciendo todo lo posible por él, pero vamos a plantear una denuncia en el juzgado porque no puede ser que él siga en la calle..." Entre otros muchos aspectos tratados en esta conversación, se le recuerda el ofrecimiento que Dª Isabel hizo a la Comisión de costearle un alojamiento a su hijo en tanto en cuanto le podamos asignar un centro -que él siempre ha rechazado cuando se le ha ofrecido, y se le ha ofrecido en muchas ocasiones- Se le propone que, si lo pueden convencer, lo lleven al Albergue Municipal y, si hay plaza, que ingresen en su cuenta los +/- 15 €/día que cuesta y que nosotros hablaremos con el Albergue para abonarlos mensualmente...". Y, por supuesto, si consideran oportuno presentar la denuncia están en su derecho de hacerlo....','2');
