insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2016-05-16','Hemos solicitado al Registro de la Propiedad de Trujillo, notas simples a nombre de sus padres, Pedro Bravo Javier y Encarnación Patilla Castro, a los efectos de determinar la titularidad de la vivienda sita en Plaza Castillo, 1, de Miajadas o si Encarnación tiene a su nombre otras propiedades (nos costa que puede tenerlas en la calle Félix Rodríguez de la Fuente, 10 ó en Monfragüe, 22, esta última es la dirección que aparece en los DNI de los hijos de Pedro, Antonia y José Manuel). En cuanto a la vivienda de Plaza del Castillo, 1, es una vivienda que según nos informa el servicio social de base de Miajadas, los padres de Juan Bravo Javier y Pedro Bravo Javier, dividieron a la mitad para ambos. Tenemos nota simple del Registro de la Propiedad de Trujillo indicándonos que esa vivienda pertenece a Juan, pero queremos saber si Pedro tiene también parte de propiedad.','2');
