insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOTO'and apellido2='DURAN'),'2016-05-17','Comparecencia en el Servicio de Gestión de Penas de Cáceres. Nati (T.Soc.:927-278647 y 927-278645). Cumplirá la medida en el centro de Mayores Virgen de la Montaña I, en Casar de Cáceres. Acudimos a la Residencia para hablar con su directora, Beatriz, sobre dicho cumplimiento. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Don José manifestó que su hijo menor, D. José Manuel Soto Verjano, está dispuesto a ejercer la tutela de su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-05-13','SE pasa el caso a la Subdirección de Salud Mental. En contacto también con el ESM de Plasencia, comentan que se va a convocar una subcomisión de casos para buscar recurso adecuado a D. José Mª. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Tomás, T.Soc. del C. "Padre Cristóbal" informando de las últimas gestiones, así como solicitando a la coordinadora del Centro el nº de cuenta para hacer el pago por la estancia "prolongada" de D.José Mª.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-05-17','llamada de Jesús: le han notificado comparecencia para mañana, 18 de mayo, a las 12:00h,de la cual no teníamos constancia: la confirmo en el Juzgado de 1ª nº 4 de Cáceres (también nos habían citado para el 25 de mayo, pero al comprobar el fax lo tenían erróneo). La comparecencia de mañana anula la del 25 de mayo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++El abogado de oficio que él mismo ha pedido es D. Jesús García de Tienda, con teléfono 927-215427.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-05-17','Conversación con Francisco (927-244205 y 630-211717), hmno. de Saturnino (622-495968).Hablará con su hermano para hacerle comprender la conveniencia de que se le autorice a sacar dinero del banco solamente si va acompañado por Francisco, antes de tomar la decisión, de manera unilateral por parte de CTAEx, de enviar al banco autorización para que saque el dinero solamente si va acompañado por su hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-16','INCIDENCIA El día 16/05/2016. Hermenegildo acude en reiteradas ocasiones a lo largo de la mañana a mi (Carmen Pacheco Puig) despacho para hablar con su madre, no se realiza la llamada por su mala conducta en el fin de semana. Al preguntarle la psicóloga por los incidentes de este fin de semana, Hermenegildo se pone violento verbalmente, le tiemblan las piernas, llegando incluso a amenazarla con que la va a agredir. Niega que haya pedido un anillo pero sí reconoce haber pegado a una residente fuera del centro porque le acusó de robar. Sale muy alterado y despavorido del despacho dando gritos y un portazo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-16','INCIDENCIA Y FUGA El día 15/05/2016. Un residente del centro dice que Hermenegildo le ha pedido el anillo de oro. Se ha fugado a las 21:30 Hs. y regresado a las 22:10 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-16','INCIDENCIA Y FUGA El día 14/05/2016. Según dos residentes del Centro, Hermenegildo dio un manotazo a una residente después de discutir fuera del mismo. Después de la cena salta la valla y regresa a las 22 Hs. por voluntad propia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2016-05-17','Hablo con Marcos (Director Residencia): la prioridad de D.Isabel es su traslado a Plasencia por acercamiento familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='GARROTE'and apellido2='ARROYO'),'2016-05-17','Hablo con Yolanda, T.Soc. SSB (685-406278).Conclusiones: +++Retirar el acompañamiento de D. Manuel: no tiene dinero para continuarlo. +++Ir pagando la deuda con los pisos supervisados cargando en cada nuevo recibo una parte de la misma (llamar para acordar). +++Tiene Seguro de deceso con Santa Lucía: Póliza Nº561042710 (Información: 902-242000, 24h)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-05-17','Conversación con Mª Carmen, hermana de Juan (927-367528).Muy descontenta con el estado de "abandono" en el que se encuentra su hermano, aunque reconoce que está mucho más tranquilo y la alarma social en el pueblo ya no existe hace meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2016-05-17','Conversación con Olga, T.Soc. SSB de Valverde de Burguillos. Enviará informe sobre la situación actual: el padre necesita ingreso en residencia, su hijo se lo impide y la familia no se atrave a enfrentarse a él: le indico que la propia familia o el SSB puede denunciar la situación ante el juzgado de Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2016-05-17','Se solicita al Juzgado autorización judicial para vender la vivienda propiedad de el y su hermana . La vivienda está en Aliseda y la recibieron en herencia de sus padres .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2016-05-18','- se modifica la PNC con efectos ec desde 1 / 10 / 2015 que pasa a ser de 367,90€ . Se le ingresaran 440€ por atrasos no percibidos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2016-05-18','Se extingue la PNC por ser causante de PFHC con efectos 1/10/2015 . Hay un cobro indebido con PNC de 2694€ que hay que abonar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ABDONA MATILDE'and edp.apellido1='SANCHEZ'and apellido2='HERNANDEZ'),'2016-05-18','- se revoca la anulación de la PNC con efectos ec 01/02/2014 , con unos atrasos de 11364€ que se utilizarán para cubrir deudas pte con R.Mayores','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2016-05-18','Llama Belén, del C.Penitenciario de Badajoz (924-289117) interesándose por si sabíamos algo de él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-05-18','Comparecencia ante el Juzgado de 1ª Instancia nº 4 de Cáceres.Presentes:Jueza, Secretaria, Fiscal, abogado de Jesús, letrado de la Junta (Curro) y representante de la CTAEX (Pedro). Tras dicha comparecencia, llego a la conclusión de que el ejercicio de la curatela llevado a cabo por la Comisión es la que se ajusta a su redacción e incluso supera a lo que el mandato de esta impone a la misma. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Desde Fiscalía se propone solicitar una reducción de la medida de pago por alimentos dada la situación económica de Jesús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2016-05-19','No se puede pedir revisión de grado hasta pasado un año, al no haber un empeoramiento de la situación diagnosticada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2016-05-19','-denegada renta basica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-05-19','Conversación con Francisco, hermano de Saturnino.Ha hablado con su hermano y "acepta" la condición de acudir al banco los días 4 y 18 de cada mes como hasta ahora, pero siempre en compañía de Francisco: caso de no ser así, no podrá sacar el dinero. Respecto a necesidades extraordinarias que se puedan dar, Francisco se compromete a comunicarlas por correo electrónico a la Comisión, justificando las mismas. Se le indica que las presentes medidas (acompañamiento) se mantendrán en tanto en cuanto el comportamiento y actitud de Saturnino así lo aconsejen según criterio de esta Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-05-19','Solicita 150 € para factura de calentador que ha comprado nuevo. Aportará la factura por fax o en su siguiente visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-05-19','Visita de Maria Dolores. "Me ha dicho mi psiquiatra y en el CRR que es mi tutor el que me tiene que hacer un certificado para que me den el alta y me pueda ir a mi casa..." Trato (Pedro) de hacerle entender las competencias de cada uno de los agentes que intervienen en su situación, pero no creo que lo comprenda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-05-19','-actualmente ingresado en UHB LLERENA . - Van a solicitar ingreso en UDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2016-05-19','Recibimos I.Social de Olga (646-848875 y 924-560060 de Atalaya). Desde ayer llamando al ESM de Zafra sin poder contactar con ellos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con la Dra. Ana, suplente de la Dra. Marisol, quine esta de vacaciones hasta el lunes que viene. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Clara para agilizar los trámites de Dependencia del padre de José Luis, para ver posibilidad de solicitar ingreso en módulo familiar del CAMP de Don benito.adjuntaremos I. Social del SSB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-05-19','He enviado un correo electrónico a la Institución Tutelar de Málaga, que tiene la petición que hicimos de traslado de la tutela a la Junta de Andalucía, a través del Juzgado de Primera Instancia nº 3 de Vélez-Málaga (desde febrero del 2016), a los efectos de preguntar en qué momento se encuentra el expediente.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-05-19','-se solicita dependencia en 2010 valorada de GI N1 , se desestima revision de grado pero se revisa el PIA . Se le concede Promocion de la Autonomia y se consigue así ingresar en Vivienda Tutelada de Ap8 ( truco para ingreso pq con G1 no se puede acceder a recurso residencial )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2016-05-19','He enviado un correo electrónico a la Institución Tutelar de Málaga, que tiene la petición que hicimos de traslado de la curatela a la Junta de Andalucía, a través del Juzgado de Primera Instancia nº 3 de Vélez-Málaga (desde febrero del 2016), a los efectos de preguntar en qué momento se encuentra el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-23','-Acude a la oficina de CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-05-23','INCIDENCIA El 16/05/2016. Nos ponemos en contacto con UME, quienes nos informan del estado alterado en el que ha llegado Emilia a la Unidad, siendo necesario un ingreso en UHB durante unas horas para poder controlar la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-05-23','INCIDENCIA El día 15/05/2016. Turno de tarde: Mantiene un buen estado de ánimo, se lleva a las 17:15 370€ y la medicación, la vienen a buscar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-05-23','INCIDENCIA El 14/05/2016. Turno de mañana: Viene a visitarla un hombre que dice conocer del hospital. Queda con él por la tarde y está muy contenta.********************************* Turno de noche: Muy demandante de atención al comienzo de la noche, nos limitamos a atender lo imprescindible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-05-23','INCIDENCIA El 13/05/2016. Turno de Mañana: Llega de pase de la UME a las 10:15 Hs. Se instala en la habitación 247 con Juani Rivas. Está muy animada. Trae medicación para el fin de semana. Se le han dado las llaves del armario. Esta tarde hará ella copia y entregará ticket para que se le devuelva el dinero. Entregará, de todas formas esas llaves al irse. Se le vuelve a insisitir en que no se realizarán compras.** Turno de Tarde: Llama su tía por el tema del dinero que envió. Le decimos que no puede utilizarlo y se le dará cuando se marche. Seguidamente interviene TO, y le comenta la misma pauta. Se pone un poco alterada y TO le da unas series de pautas para su estancia en el CRR que ella no quiere aceptar y se enfada. Anteriormente ya la TO ha hablado con su tía y le ha comentado que aquí no viene de fin de semana, por tanto, no puede utilizar asignación ni el dinero para compras. Al final se enfada bastante e intenta que se le de dinero para zapatos. TO, le dice que no es posible y decide irse a acostar.********************* Turno de Noche: Acude en varias ocasiones al despacho por diferentes temas. A las 1:30 Hs. pide una tila por no poder dormir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-05-23','Se le cita para el próximo 13 de julio, a las 11:40, en el Juzgado de Primera Instancia nº 4 de Sevilla, en el procedimiento de juicio sobre delitos leves 82/2016 (agresión con otro interno del Penitenciario de Sevilla)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2016-05-23','Solicitamos autorización judicial, a través de abogado de oficio (D. Carlos Villalón), para vender el apartamento de la Línea de la Concepción (Cádiz). A través del Auto 123/165, del Juzgado de Primera Instancia nº 4 de Badajoz, lo inadmiten, porque no es necesaria la autorización judicial para este tipo de actos, debido a que la Sentencia que incapacitó a Rafael, no lo contempla. Tan sólo exige la asistencia de la Comisión Tutelar para realizar el acto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2016-05-25','-Se envia la renuncia a Pisos Supervisados de Mérida . Alfonso no quiere ingresar , su deseo es irse con la familia . Consume tóxicos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2016-05-25','-El recurso asignado al final de RAE, es el de HNos de cruz blanca en Caceres , Manuela lo elige pq el recurso es más cerrado y cree que no habrá problemas . Hay que hacer una renuncia en Placeat . - Se gestiona el traslado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2016-05-25','Hemos recibido el Auto con fecha de 18 de mayo de 2016, correspondiente a la Ejecutoria nº 421/2016-1, seguida en el Juzgado de lo Penal nº 1 de Plasencia, en el que absuelven a José María Vicho y condena a Jairo Puertas Martín, a una medida de internamiento en centro, para tratamiento médico adecuado por plazo de un año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIONISIA'and edp.apellido1='BENITEZ'and apellido2='SANCHO'),'2016-05-25','Hoy vino Abel Corbacho Sánchez, familiar de Dionisia, según él. Está interesado en asumir la tutela, porque en su día, según él, nadie se puso en contacto ni con él ni con ningún otro familiar de Dionisia, durante el proceso de incapacitación. Está muy indignado, quiere denunciar a la Comisión, al Sepad, a la Residencia (la antigua directora manifestó que no había contacto de Dionisia con sus familiares). Se le han indicado los pasos a seguir para que solicite, ante el Juzgado de Primera Instancia nº 1 de Almendralejo, la asunción de la tutela. No entiende por qué debe ser él quien inicie el procedimiento. Nos solicitó documentación, pero no se la hemos facilitado, debido a que no sabemos quién es, documentalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-05-25','El Juzgado de Primera Instancia e Instrucción nº 1 de Cáceres, en su sentencia 245/2016, de 24 de mayo, en el procedimiento 42/2016, reintegra el derecho de sufragio activo de Ventura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2016-05-26','Párrafo Primero. Nos llama Juan Antonio Pablos Solís, tío de José Fermín. Él y el resto de herederos, están interesados en la compra de la parte que le corresponde a José Fermín, de una casa que forma parte de la herencia de los abuelos de José Fermín y padres de Juan Antonio, Antonio Pablos Rodríguez y Florentina Solís de la Cruz. La casa está en Pozuelo de Alarcón, Madrid, C/. Santa Emilia, nº 8. Según Juan Antonio, tiene un valor de 111.000 euros. Le he indicado que nos envíen una propuesta de intención de compra, firmada por el resto de herederos, junto con la tasación de la casa, que tienen de la Comunidad de Madrid y el importe que recibirá José Fermín por la venta. Párrafo Segundo. Esta petición ya la hicieron en el año 2011. Solicitamos autorización judicial para vender la parte correspondiente a Fermín y nos la concedieron, autorizandose por Auto 127/2011, de 23 de diciembre, del Juzgado de Primera Instancia e Instrucción nº 2 de Trujillo. Párrafo Tercero. Vamos a esperar, no obstante, a recibir la documentación señalada en el párrafo primero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-05-26','recibimos la visita de sus familiares en la CTAEX, solicitando 200€ de gastos extraordinarios para ropa, calzado, etc. Se le concede, a la espera de facturas. No tiene seguro de decesos. El Equipo de Salud mental lo van a derivar a CEDEX de Fregenal para desintoxicación de alcohol.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-05-25','SE recibe Auto del Juzgado Nº 2 de Cáceres en el que se DENIEGA la remoción de la CTAEx como curadora de D. Jesús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2016-05-27','Llama Fátima, T. Soc. del ESM de Mérida (924-487229), para verificar si la Comisión le ha dicho que es el Psiquiatra quien le tiene que dar permiso para marcharse a Badajoz.SE le aclara la información dada a Concepción: el alta médica corresponde al ESM; la restitución de la capacidad, que es lo que ella, en otras palabras desea, corresponde al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-05-23','Se recibe Informe Médico-Forense del Juzgado de 1ª Instancia e Instrucción Nº 2 de Cáceres en realción a D. Valeriano M.S., en el procedimiento abreviado 224/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-05-27','Llama Dª Isabel, madre de Jesús: sigue penasando en pagarle un alquiler razonable a Jesús, pero ella misma reconoce que, teniendo como ella tiene un piso en Cáceres, no le deja una habitación porque también hay estudiantes y "...mi hijo se acuesta a las tantas, entra y sale cuando quiere y así no puede ser". La propuesta de la Comisión es que en estos momentos Jesús lo que necesita es un period de tiempo en un Centro (CRR) para trabajar con él habitos de comportamiento, de manejo de dinero, trabajar su adicción a las tragaperras, etc. Posteriormente se podría valorar el alquiler de una vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2016-05-27','Llama Aquilino (655602088): quiere 85 € para un anillo de oro para su pareja (cumpleaños). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con María, Psicóloga del CRR: estamos trabajando con él la gestión del dinero, la anticipación de gastos, el ahorro, etc.+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Aquilino: no se le van a autorizar los 85 €: de los 120 €/semana que tiene, si ahorra 40 hasta el 17 de junio que es el cumpleaños, le puede comprar el anillo. Pero "...entonces yo no tengo para mis gastos..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-05-27','Llamo al Dr. Randal de Jesús Méndez Almansa (C.S. Barcarrota 924-73 63 77 y C.S. Salvatierra 924-752830). Se le expone la situación de J.Florencio en cuanto a la factura de farmacia, reconociendo que le hace recetas de medicamentos porque "...en la famracia le dicen que si no no se la dan...". Se le informa de la acumulación de medicamentos que tiene en su casa y de que la Comisión , por supuesto, no tiene nada que objetar respecto a las recetas que desde un punto de vista clínico sean precisas, pero que no se le debe "hacer el juego" ante aquellas peticiones que él haga sin otro fundamento que su deseo de que se le proporcionen. El Dr. Randal asegura que ya no va a acceder más a sus petciones y que le recetará solamnete lo que en su criterio clínico considere preciso. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablaremos con el Farmacéutico para abonar las dos últimas facturas y conminarle a que solo le dispense a J. Florencio las recetas procentes de su Médico de Familia (la última receta era de un médico de Badajoz).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2016-05-27','Llamo a la Residencia de Mayores de Barcarrota, donde debería estar D. Francisco desde febrero de 2015. Sin embargo, en el procediemineto de remoción de tutela de fecha abril de 2016, interpuesto por D. Luis Cardoso Pérez (681-202134), sobrino de D. Francisco, se recoge que es dicho sobrino el que actualmente vive con él, dispensándole los cuidados que precisa. ++++++++++++++++++++++++La Directora de la Residencia, Mª José (924-737993), a diferencia de lo que se indica en el escrito del representante de D. Luis Cardoso Pérez solicitando, en nombre de éste, la remoción del cargo de tutor que ostenta esta Comisión para hacerse cargo de la misma, nos informa que D. Francisco reside allí desde febrero de 2015 y que todos los cuidados que requiere se dispensan desde la propia Residencia: acompañamiento a hospital, etc. Es cierto que su sobrino, D. Luis, lo visita con frecuencia, pero NO ES CIERTO QUE CONVIVA CON ÉL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2016-05-27','Llama Mar TS de Ciudad Jardín porque se hizo unas analíticas, le han dado alterado los resultados y no consiguen contactar con ella. Nos ponemos en contacto con su delegada de zona y la va a localizar para ir el lunes al centro de salud con ella. ( Teresa)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2016-05-27','Llamo a la Residencia de Mayores de Barcarrota y hablo con su Directora, Mª José (924-737993). A diferencia de lo que se indica en el escrito del representante de D. Luis Cardoso Pérez (sobrino de D. Francisco) solicitando en nombre de este la remoción del cargo de tutor que ostenta esta Comisión para hacerse cargo de la misma, su Directora nos informa que D. Francisco reside allí desde febrero de 2015 y que todos los cuidados que requiere se dispensan desde la propia Residencia: acompañamineto a hospital, etc. Es cierto que su sobrino, D. Luis, lo visita con frecuencia, pero NOES CIERTO QUE CONVIVA CON ÉL.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-05-27','Enviada prestacioón de supervivencia y P.F. a la Seguridad Social de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-05-27','Hablo con Clemen, Directora del CAMP.Le informo de que Hermenegildo será admitido en la UDAC, en espera de plaza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='HOLGUIN'and apellido2='MENESES'),'2016-05-27','Conversación con la T. Soc. del Hospital de Talarrubias (924-648100) y con Cristina, Coordinadora RAEG de Aprosuba 12. El médico de Aprosuba considera preciso un nuevo ingreso de D. Manuel. Felisa indica que si la médico le ha dado el alta y no le ha pasado el caso a ella es porque el proceso agudo que motivó el ingreso ha pasado y, por lo tanto, se da el alta y regreso a su domicilio. Cristina dice que no están preparados para atender un caso así.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='HOLGUIN'and apellido2='MENESES'),'2016-05-27','Concersación con Feliasa, (T. Soc. del Hospital de Talarrubias','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-05-30','Llama Teresa, Directora de Novaforma (662-337119). Mª José, la madre de Alvaro, no le ha querido dar el tratamiento prescrito por su Psiquiatra durante este fin de semana e insiste en que no se lo va a dar porque no lo necesita. Teresa quiere saber cómo proceder.+++ Se le indica lo siguiente: advertirán a la madre que en caso de que en la salida del próximo fin de semana se compruebe que no le ha dado el tratamiento, no se autorizará la salida siguiente. Teresa se muestra conforme con ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='HOLGUIN'and apellido2='MENESES'),'2016-05-30','LLamamos a Aprosuba 12 (Cristina), llevaron a Manuel al hospital el viernes pero no lo ingresaron, lo volvieron a llevar al centro. Comenta que está empezando a comer algo pero está muy débil y cree que vuelve a tener problemas por obstrucción intestinal.Le comento que nos tengan informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2016-05-30','Le han concedido un grado 1, nivel 1 para servicio atención residencial. Nos solicitan firmar aceptación PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2016-05-30','José Antonio Campos, abogado, está tramitando las herencias de los padres de Santiago, fallecidos. Hemos enviado liquidación del impuesto de sucesiones de la herencia de la madre y vamos a enviar la liquidación del impuesto de sucesiones de la herencia del padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-05-30','Hemos recibido correo electrónico de Luis Miguel, hermano de Ceferino. Nos indica que tiene comprador para la vivienda que actualmente está en régimen de alquiler. Cuando recibamos la autorización judicial para poder vender, nos pondremos en contacto con los compradores (Mari Angeles Roso 622161764)y Eduard Novikov (633383858)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='VAZQUEZ'and apellido2='CORRALES'),'2016-05-30','Hemos recibido caducidad de la primera liquidación del impuesto de sucesiones y nueva propuesta de liquidación del mismo impuesto, concediéndonos 10 días para alegar. Posteriormente, recibiremos la liquidación del impuesto para pagar. Nos corresponde pagar el 50% y el otro 50% a su hermana María. Antes del pago, debemos intentar hablar con María, para acordar qué día va a realizar el pago ella, para que paguemos nosotros también. Posteriormente, comunicárselo a la Oficina liquidadora de Zafra (Eva 924550298) para que emita certificaciones de pagos parciales de ambas liquidaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-05-30','Desde Aprosuba 10 nos informan que se encuentra en la UHB de LLerena otra vez. Nos remiten fax con los informes médicos y nos informan de los incidentes ocurridos. Nos solicitan la solicitud de derivación a la UDAC, que es lo único que falta en la documentación para la UDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2016-05-30','Se envía informe de CTAEx a Gabinete Jurídico sobre demanda de remoción de tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2016-05-30','Se recibe en la Comisión Resolución de PIA con adjudiccación de plaza en el Centro Hermanos de La Cruz Blanca en Cáceres: C/. Manga nº 2. Teléfono: 927-246852).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2016-05-30','Conversación con Nuria, Técnico PIA (689575719): enviará resolución PIA para firmar y remitir: Prestación vinculada al servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-05-30','Llamada a Nuria, Técnico PIA (689-575719): enviarán resolución PIA y esperarán aceptación por parte de D. Juan (tiene curatela a efectos médicos y de tratamiento). Nos la enviarán también a la CTAEx. Plazo para el archivo de la propuesta 3 meses.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SAUCEDO'and apellido2='AGUEDO'),'2016-05-30','Pendiente modificación PIA para acceder a plaza de Dependencia. Hablo con Clara para tratar de agilizarlo y comunico a Rosa María Alonso Pérez(Jefa de Sección de Admon. General.Servicio de Familias, Infancia y Adolescencia, 924-008831)las gestiones que se están realizando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-05-31','Nos llega solicitud de derivación a la UDAC firmada por la directora gerente, se lo remitimos a Olga (TS, Unidad de programas asistenciales) a través de nota interior','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2016-05-31','Conversación con Olga , T. Social. Pendiente de visita esta semana por parte del Técnico PIA.+++++++++++++++++++++++++++++++++++++++++++Conversación con Manuela sobre posibilidad de tener plaza en el módulo familiar del CAMP de Don Benito: cree que no va a ser posible por el perfil de enfermedad mental de José Luis.++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Toni(Futuex).La alternativa que se ve desde la CTAEx es el ingreso en CRR de José Luis y a su padre en Residencia de Mayores procurando la cercanía entre ambos, incluso en la misma localidad (Cáceres, Badajoz, Mérida o Plasencia.. En el caso de Plasencia, podría recurrirse a la Unidad de Desintoxicación del CSS).Me llamará Silvia para conocer últimos datos de la visita al ESM de ayer (30 mayo). Pendiente llamar a Leticia Tolosa, Psiquiatra del ESM de Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2016-06-01','Llama de nuevo David, abogado de Paloma (no ha sido contratado de manera "oficial" por ella ni por el padre, al parecer solamente le han pedido opinión sobre su situación y carece de documentación alguna. Se le comenta que no podemos facilitar dicha documentación. Le vuelvo a llamar pero no me coge el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-06-01','Llama Dª Isabel, madre de Saturnino (667-562172). Preocupada porque su hijo no puede disfrutar de su dinero como el quiera y responsabilizando a la Comisión de su ingreso en prisión. Se le trata de explicar todo ello y los motivos para ello. Se le propone que hable con su hijo y le plantee que pueda hacer algún curso en la UP, en alguna asociación, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-06-01','Recibimos en la comisión al presidente, vicepresidente y secretario de Aprosuba 10 (Juan, Joaquin y Emilio). Nos quieren trasladar la urgencia de derivar a la UDAC a Agustín. Ya habíamos trasladado el trámite de audiencia a firmas, pendiente de derivar a la Unidad de Recursos, una vez firmado por la directora gerente. Agustín actualmente se encuentra en la UHB de Llerena.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-06-01','Recibimos en la comisión al presidente, vicepresidente y secretario de Aprosuba 10 (Juan, Joaquin y Emilio). Nos quieren trasladar la urgencia de derivar a la UDAC a Agustín. Ya habíamos trasladado el trámite de audiencia a firmas, pendiente de derivar a la Unidad de Recursos, una vez firmado por la directora gerente. Agustín actualmente se encuentra en la UHB de Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='MORENO'and apellido2='CARRASCO'),'2016-06-01','Llama Dª María Sonia Moreno León (690-786893). Demanda información sobre los trámites a seguir tras el fallecimiento de su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2016-06-02','Conversación con el Dr. Agapito. En relación a la petición realizada por Jairo en realción a la compra de un ordenador para cursar estudios su psiquiatra considera que, dado que se encuentra en una unidad cerrada, sin conexión a internet, en la que en estos momentos no paga al ser una medida judicial y querer el el aparato más como máquina dce escribir que otra cosa. Lo comentará en la reunión ddel equipo y nos informará al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-06-02','INGRESO Entre el 07/04/2016 y el 10/05/2016. Ingreso en el Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-06-02','Ha llamado la TS Inma de CS de Jerez nos lo comenta Alberto. Ramón se encuentra en la UHB del Infanta Cristina. Hablamos con una enfermera y con el TS (Juanjo) de psiquiatría, está ingresado desde el 30 de mayo. Queremos hablar con el psiquiatra, nos llamarán para informarnos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2016-06-02','Conversación con Mª Barrasa (CSS Mérida). Mantener a Ricardo en lista de espera para pisos supervisados del Grupo 5. Y solicitar autorización judicial de venta del pìso de Ricardo. María enviará último Informe. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Carmen Ferrer (69263): tiene que consultar que, si habiendo dos centros en Mérida de Pisos Supervisados, es posible elegir uno u otro. En este caso se trata de que el entorno de la Avda. América no sea el más apropiado para Ricardo. Nos informará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-06-03','Han convocado a la CTAEx a la Subcomisión de Casos para el 07 DE JULIO DE 2016 A LAS 13:30h EN EL CSS DE PLASENCIA. Ha estado una semana en casa de sus padres sin ningún problema. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Comunico a Tomás esta reunión. Enviará el Informe pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-06-03','Llamo a Pilar, T. Soc. del ESM de Cáceres (927-213730).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-06-03','-Visita a domicilio a Carmen , direccion C/ Pio Baroja , nº 2 1ºB . Venia de inyectarse la medicació . Compensada, discurso coherente , aseada , ropa limpia . Para comer traia un paquete de arroz con leche y un litro de vino con casera . La vivienda en perfectas condiciones de habitabilidad e higiene , ropa ordenada , casa muy limpia , cocina impecable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2016-06-03','Se informa a Asunción Cabrera de la situación de Isabel y su compañera de piso. El propietario, Atilano, dice que la compañera se va definitivamente.Pérdidas de dinero, les han robado, siempre hay una razón para pedir más dinero. Hablará con Isabel y nos dirá si Manuela se va definitivamente.','2');
