insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-06-03','Conversación con Francisco, hermano de Saturnino. +++++Le han dado el dinero en el banco sin estar su hermano presente. +++++Dice que no va a ir en una temporada al dentista. Hablaremos con el banco y con la clínica (que nos avise en caso de falte a las consultas).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2016-06-06','Maica ha tramitado la ayuda de transporte para su madre, Dª Isabel (680-784490). A Maica, T. Social de Torrecilla de los Ángeles (927445172) le preocupa el entorno en el que se ha movido siempre Alfonso, entorno que sigue manteniéndose sin cambios. Para ella, la relación de Alfonso con su madre es algo conflictiva, especialmente cuando la convivencia se prolonga en el tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-06-06','-Se deniega el tratamiento de habilitacion funcional del Madex , no hay ninguna posibilidad . -Hablo con la monitora de pisos para saber de su evolución , se encuentra más tranquila sin el móvil , tenia demasiados contactos con su madre ( que ha localizado despues de muchos años ) y hermanos , y con Miguel . Mantiene la relación de pareja con Miguel , se ven una vez a la semana pero no mantiene la relación con su familia .','2');
