insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2016-06-08','-Se deniega la peticion de dinero por parte de la madre para ayuda a los FS que el hijo pasa con ella . Hemos hablado con TS de CSS Plasencia que no lo aconseja puesto que él tiene suficiente con su dinero de bolsillo','2');
