insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2016-06-08','En relación a la propuesta de FUTUEX de sustituir la bañera por un plato de ducha, ahora mismo no tienen dinero suficiente para abordar la obra, habrá que esperar a que ahorren un poco. Por otro lado, nos comenta el yerno de Concepción que la casa está muy sucia en cuanto se va la auxiliar de ayuda a domicilio y tanto Concepción como su marido Antonio no mantiene una higiene y aseo personal adecuado por eso él y su hija hace meses que no los visitan ya que tienen niños pequeños.','2');
