insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CARDENAS'and apellido2='CARMONA'),'2016-06-09','Nos llega un fax del centro Sociosanitario Adolfo Díaz Ambrona de Mérida informándonos que Mª Carmen será trasladado al Hospital de Mérida el 09/06/2016','2');
