insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2016-06-09','SE HAN PEDIDO DATOS FISCALES CORRESPONDIENTES AL 2015 Y ANTONIA NO ESTÁ OBLIGADA A PRESENTAR DECLARACIÓN PORQUE LOS INTERESES DE SUS CUENTAS NO SUPERAN 1600 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-09','Nos llama Clemen del CAMP, porque Hermenegildo se ha vuelto a escapar y le han llamado del Centro Hermano de Cáritas de Badajoz que estaba allí. Se va a quedar esta noche en el Centro Hermano de Badajoz, hablamos con Yolanda la TS (924240047) cualquier problema que llamen a Clemen o a nosotros pero por la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='LEAL'and apellido2='GOMEZ'),'2016-06-09','Visita domiciliaria a Carmen (TELÉFONO: 649-606914). No acudió ayer a ponerse el inyectable porque se le pasó, pero al llegar me comentó que había ido antes de llegar yo, extremo este que pudimos confirmar con la T. Social del ESM. Carmen está bien, lo que me enseñó de la casa (salón, cocina y patio está como lo vimos amalia y yo en nuestra primera visita: salón lleno de jarrones y otros enseres por el suelo; cocina despejada y relativamente limpia; patio recogido y con trozos de pan por el suelo porque, al parecer, se los da la perro de la vecina.+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Carmen me comentó lo siguiente: ++++++hABÍA PAGADO UNA DEUDA A hACIENDA DE 14.000€, PARA LO QUE HABÍA TENIDO QUE SACAR UN PRÉSTAMO DE 9.000€;sU INQUILINA DE LA CALLE MACOM Nº 137 LE ADEUDA UNOS 4000€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-06-10','Visita de Jonathan a la Comisión. Se le informa de las próximas citaciones pendientes, se habla con él sobre el motivo por el que no acudió a cumplir los trabajos en beneficio de la comunidad, aspecto por elk que se le ha vuelto a requerir desde SS Penitenciarios. +++Se le autorizan 50 € para ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2016-06-10','Reunión en Apba. 3 con el Equipo Técnico, CTAEx (Amalia y Pedro) y José Manuel Lobato Camacho (antes Honrado Rodríguez), hijo de Dª Emilia que adoptó Dª Manuela Araceli Camacho Cruz, su madre adpotiva, quien también estuvo presente en la reunión y su marido D. Antonio Lobato Acedo.+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++La CTAEx tuvo conocimiento en el día de ayer por Apba 3 de que D. José Miguel había encontrado a su madre y quería conoccerla. Durante la reunión acreditaron su identidad mediante copia de la Partida de Nacimiento, en la que constaba inscripción al margen de la adopción ver en expediente), cotejados los datos con los correspondientes DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='MARTIN'and apellido2='CALLE'),'2016-06-10','Hablamos con la hija Puerto Paniagua, ya sabe la familia que se anula la transferencia. Tlf del trabajo de la hija (924514164)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2016-06-09','Guardo el correo de la R.M: Buenos dias, comunicaros que a partir de este mes vamos a pasar a cobrarle a MARIA SANCHEZ BELLO, 1300€ que es el coste de la residencia para un grado II que es el que le han dado a ella el SEPAD. Me he puesto en contacto con el equipo de dependencia de Trujillo, y me comentan que ya se están haciendo los tramites de la ayuda que le pertenece, y que la tiene aprobada desde el día que entró en residencia el 29 de octubre de 2015, les he facilitado el contrato que para la tramitación de dicha ayuda.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2016-06-09','SOLICITO REVISION PIA PARA TRASLADO A CTRO DISCAPACIDAD MAS CERCANO A BARCARROTA.','2');
