insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-06-10','Vamos al domcilio de Carmen, le comentamos lo del comedor social y le parece bien. Vamos a tramitarle la documentación. También le solicitamos revisión del grado de dependencia porque fue valorada en 2010 sin grado, a través de la TS del CS nos facilita el informe médico, para tramitarselo. Seguimos manteniendo la cita con el psiquiatra para el 7 de julio con ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='FUENTES'and apellido2='ALCANTARA'),'2016-06-13','-INGRESA EN LA UDAC MAÑANA . ESTABA EN APROSUBA 10 Y TUVO QUE SER INGRESADO EN LA UHB DE LLERENA DESDE DONDE SE HARÁ EL TRASLADO CON AMBULANCIA.','2');
