insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-06-13','El juicio relacionado con el procedimiento abreviado 371/2015 (amenazas-acusada) y que se suspendió en su día por no comparecer la otra parte, vuelve a celebrarse el día 13 de julio, en Mérida, a través de videoconferencia. El juicio es en Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-06-14','El 10 de junio, conseguimos hablar con el psiquiatra Dr. Moises Bolívar, nos comenta que el 14 de junio hay una valoración en la URH de Mérida. Hablamos con Juanjo T.S. (Hospital Infanta C.)le comentamos que cuando tenga noticias nos informe. Anteriormente también estuvimos hablando del caso con Maribel de Salud Mental para ver la opción de una subcomisión de casos para que Ramón no fuera enviado a casa desde la UHB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2016-06-14','Nos llamaron desde Aprosuba Zafra porque Juana Nieto ayer 13 de junio no acudió al centro. Se había quedado en casa de su madre y le habíamos hecho un reintegro extra de 50€ para una boda y además se había comprado un vestido de 85€ y después de todo no ha ido a la boda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-13','Nos llega un informe del CAM y el día 10 de junio se envío un taxi con un educador para recogerle del Centro Hermano de Badajoz de vuelta al CAM','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-05-10','-Se confirma con el servicio de discapacidad que tiene solicitada plaza en RAL por decreto en los 4 centros mas cercano a Mérida : Montijo, Zafra , Bjoz y Mérida. Se solicitó por Decreto. No se puede solicitar por dependencia pq solo tiene grado 1 , está muy mal en la lista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2016-06-14','Realizamos visita domiciliaria para cuadrar nuevo presupuesto porque ahora ya no comparte piso. Antes de ir a su casa la llamamos por teléfono no nos lo cogió, en su casa estuvimos llamando a la puerta y no nos abría. Después de vernos en la calle nos dejo subir. La vivienda estaba bien, tenía poca comida en el frigorífico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-15','Hablo con Rosa, CSS de Plasencia: tienen previsto estudiar el posible acceso a la UDAC mañana. Nos comunicarán la resolución tomada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-06-15','Nos llama Juanjo el TS del Hospital Infanta C.nos informa que mañana 16 de junio Ramón ingresa en UME Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2016-06-15','Se habla con Futuex. Acompañarán a Sonia a la consulta de digestivo el próximo día 21 de junio a las 12:10h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-06-16','Llama Ventura pidiendo 30-40€ para comprarse unos zapatos. Le digo que se los compre el lunes con eldinero de la semana y que una vez que mande la factura de la compra le haremos un extra por el valor de la misma. Durante la conversación profiere amenazas contra mí, contra la CTAEx, contra Cristina Herrera, que solo se acllan cuando le doy la opción expuesta arriba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2016-06-15','Un familiar de Rosa ha encontrado un DNI antiguo, le comenté que lo remitieran a la residencia donde está Rosa. El director de la residencia nos llama para comunicar que ya ha recibido el DNI y por ahora dejamos los trámites de la renovación del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2016-06-16','Lo han operado de fimosis. Nos remiten informe médico y abonamos un acompañamiento de su hospitalización de 248,20€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2016-06-16','Llamada de Sara Lozano, hija de Isabel. Refiere llamadas constantes pidiendo dinero, diceindo que la Comisión no le da dinero para comer, etc. Se interesa también por la deuda de 800€ que le reclaman a Isabel y de la cual no hemos obtenido respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-08','INCIDENCIA Permance en el Centro Residencial (Ntra. Sra. de las Cruces)desde que regresase el pasado dia 23/05/2016, a las 21:30 Hs.************************************************** 04/06/2016. Tras regresar al centro residencial, después de las salidas en horario establecido, la educadora responsable en ese momento, aprecia un actitud de nerviosismo y temblor.*Hermenegildo, en tono amenazante hacia la educadora, la insta a que no le registre su armario, acción que no se realiza para prevenir posible fuga.*Al día siguiente, otro educador encuentra en la habitación restos de cigarrillos que contienen "Marihuana". A lo que se presupone y según manifiestan los educadores que es posible que haya estado fumando dentro de la habitación. Destacar que dicha habitación es compartida con otros tres residentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2016-06-17','Conversación con María León:propone solicitar desde el SSB de Valverde de Burguillos plaza residencial pública para el padre (está pediente de firmar convenio con residencia de Higuera de la Serena)y plaza privada para Luis, con la finalidad de pasarlo a plaza pública cuando cumpla los 50 años. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Olga, T.Soc. de valverde de Burguillos. Se le propone plantear esta situación a Fiscalía como un asituación de emergencia ante la negativa del hijo a permitir el ingreso del padre, dado que desde el ESM no se plantean el ingreso del hijos en la red de salud mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-06-17','Visita de Dolores. Dice tener testamento en una de las dos Notarías de Almendralejo y que desea que en caso de fallicimiento la casa se la quede su hermano Pedro ("El resto de la familia no se merece nada mío..."). Trerá el testamento para tener una copia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-06-17','Conversación con Fabiola, Psiquiatra del ESM de Jerez (924-751834): Ramón tiene el próximo inyectable el lunes 20 de junio. En caso de no acudir (amenaza ya con ello) remitirá por fax informe a la CTAEx que remitiremos al Juzgado de Jerez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-06-17','Teresa, Directora de Novaforma, envía correo-e informando de que la madre de Álvaro ha estado allí, con actitud hostil y alterando la normal convicencia del centro. Se ha negado a firmar el documento por el que se compromete a darle la medicación durante el fin de semana a Álvaro y por ello se le ha negado que este fin de semana se vaya con ella a su casa y mientras persista en su actitud. Han tenido que llamar a La POLICíA para que saliera debl centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-06-20','Se recibe en la Comisión Fax del Defensor de los Usuarios del Sistema Sanitario Público de Extremadura en relación a la cita solcitada en la especialidad de MAXILOFACIAL: comunican la entrada de la solicitud en la Instirución y su traslado a la D.G. de Asistencia Sanitaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2016-06-20','Quire erenovarse el DNI y pregunta qué dirección poner. Acudirá a la oficina del padrón municipal para poner la dirección del Hostal en el que vive actualmente y con la certificación acudir a la oficina del DNI. Teléfono del trabajo: 927-004245','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-06-20','Llama Blanca, T.Soc. CSS de Mérida. Informa que Juan y su pareja dicen haber ido a un notario para hecerse pareja de hecho. Quiere que vayamos a hablar con los dos para decirles que Juan no puede firmar documento alguno. Le pido que trate de averiguar la verosimilitud de lo del notario, y en caso de ser verdad, que nos diga cuál espara hablar con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-06-20','Francisco Ayala Teléf: 666-750146. Conversación con Toni (Futuex) y Encarna (T. Soc. C.Salud) Conversación con Francisco: es cierto que en una ocasión dos toxicómanos le eseperaron fuera del banco para quitarle la paga. Desde esntonces acude siempre acompañado port Alicia o por la Auxiliar. En alguna ocasión ha llamadso al 091 para que lo protegieran y lo han acercado a casa. Pide dinero extra (80€) para pasar el final de mes, ya que se ha gastado dinero en el viaje a Matalascañas y en el veterianario de su perro (él asegura que ha sido así). Se le autoriza un extra de 80€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-20','Convesración con Soraya, Directora CSS de Plasencia (927-428800).En la reunión del Equipo Terapéutico de la UDAC se concluyó que sería conveniente un ingreso previo de Hermenegildo en la UHB de Mérida para estabilizarlo y luego derivarlo a la UDAC de Centro a Centro. Le explico mis dudas al respecto, dado que dicha derivación la deben hacer desde el ESM de Don Benito-Vva o bien desde el C.salud si se diera una situación de desetabilización de Hermenegildo. Enviará la resolución del Equipo de la UDAC. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Clemen para informarle al respecto, pero no coge la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-21','Hablo con Clemen, Directora del CAMP. Le expongo la propuesta del Equipo Terapéutico de la UDAC y, al igual que yo, opina que la derivación a la UHB sin que haya situación de desestabilización va a ser muy difícil: "Isabel Tebas, Psquiatra de Hermenegildo (ESM Don Benito) considera que este no es un caso de salud mental, simplemente que quiere actuar como le apetece y nada más." En el caso de accseo directo a la UDAC, Clemen me comenta que el propio CAMP podría hacer ese traslado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a la Psiquiatra para ver si es posible la derivación a UHB: me llamará. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Isabel Terbas (Psiquitra ESM Don Benito 924-802006): entiende que la UDAC es un recurso al que se puede recurrir dado que no existe un Centro que se adapte a las características de Hermenegildo. Cree que no es necesario el paso previo por UHB, cuando además no existe una situación de crisis. Hablará con CSS de Plasencia para dar su opinión, sin descartar la posibilidad de hacer dicha derivación si se considera imprescindible. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++++++++++++++NUEVA CONVERSACIÓN CON ISABEL TEBAS: se ha llegado a la conclusión, hablando con la Psiquiatra de la UDAC y el Médico del CAMP de que EN ESTOS MOMENTOS NO ES NECESARIO EL PASO POR LA UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2016-06-21','En relación con el expediente de impugnación del testamento otorgado por Marcelo (No puede testar), el abogado de oficio designado se excusó del cargo, al ser representante de la parte contraria. El colegio designa a otro profesional. Nos lo comunican.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-06-21','Nos llama la TS Raquel, y nos pasa a Juan al tlf. Quiere dinero para visitar a una hija que vive en Madrid, hoy nos dice que se va a ir a Madrid a buscar trabajo y que va a renunciar a la pensión.... Después hablamos con la TS y nos comenta que cada día va con una cosa.. que ella cree por algún familiar que tuvo una hija pero que ésta falleció pero que él no sabe nada. Juan también nos comenta que no quiere ningún recurso de dependencia, ni SAD, ni centro de día, ni nada... no quiere a nadie en su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-06-22','Llama Ventura reclamando el dinerpo de los zapatos (ver incidencia anterior). Enviará factura. Pide 1800€, en metálico, para irse de vacaciones del día 2 de julio durante 10 días a Marina D´Or. Le pido nos envíe presupuesto de las vacaciones y nosotros podemos hacer la transferencia, si se aprueba el gasto, directamente al hotel que nos indique dicho presupuesto: "¡QUIERO QUE SEA EN METÁLICO, EN METÁLICO...!". Enviará el presupuesto. De nuevo insiste en sus amenazas de denuciar a la Comisión y de repsonsabilizar de todos sus males a Cristina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-22','Hablo con Rosa (CSS PLasencia). Soraya no está. Todo preparado para ingreso de Hermenegildo en UDAC. Confirmará si es posible el mismo el lunes 27 o martes 28 de junio. Solo está pendiente de saber si la resolución del ingreso ha de ser previa al mismo o posterior a él (comenta que Miguel Simón refirió que no había inconveniente en que fuera a posteriori). He tratado de hablar con Miguel pero hoy está de viaje (lo dejo para mañana).+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Mariluz del tema y me dice que ella no sabe nada de este caso... +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Clemen, Directora del CAMP, y le informo de que es posible, si no surge ningún inconveniente, de que se pueda ingresar a Hermenegildo en la UDAC la próxima semana, a ser posible lunes o martes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-06-22','El juicio relacionado con el procedimiento abreviado 371/2015 (amenazas-acusada) y que se suspendió en su día por no comparecer la otra parte, vuelve a celebrarse el día 05 de julio,a las 11:00h, en Mérida, a través de videoconferencia. El juicio es de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-06-22','Juicio en Juzgado de Instrucción nº 4 de SEVILLA, el 13 de julio de 2016 a las 11:40h. D. Leves 82/2016','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-06-22','Tiene abogada de oficio (Paloma palomaabog@yahoo.es), para que le represente en el procedimiento de modificación de medidas (solicitar al Juez que suspenda o minore la pensión alimenticia a su exmujer).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2016-06-22','Visita del padre de Minerva, D. Víctor. Quiere 250€ para pasar lo que queda del mes. NO TRAE LAS FACTURAS Y RESGUARDOS DE COMPRA a las que se comprometió la última vez. Le digo que cuando los traiga podremeos hablar del tema y que si se trata de cubrir hasta final de mes le podemos dar 100€. Dice que "...por 100€ no se da otra vez la caminata de volver a casa por las facturas". DE AHORA EN ADELANTE, TODO DINERO QUE SE LE DE LO TIENE QUE JUSTIFICAR, A SER POSIBLE PREVIO A SU ENTREGA (transferencia a tiendas, entrega con factura, etc.)+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Vuelve a las 14h con un sobre lleno de comprobantes de compra pero sin la factura del calentador como habíamos quedado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-06-22','Llamada de Rosa, Directora de la sucussal de Liberbank en Guadalupe (927-367053): está asustada por las amenazas de Tomás, quien no entiende que su cuenta está controlada por la Comisión al estar tutelado por ella. ++++++++++++++me pone al teléfono con él: en lo que le puedo entender, parece tener un discurso incoherente, hablando algo al respecto de un trofeo ¿? y, quizá también por el problema de sordera que pacede, según Rosa, no he sido capaz de que entendiera su situación, por lo que habría que tratar de hacer visita para explicarlo. No quiere poner denuncia por el temor de que le ocurra algo a ella o a su familia. Le propongo que nos envíe un informe de la situación lo más claro posible, para poder comunicar nosotros al juzgado la situación. Lo enviará (se le da correo-e y fax). Llamo a Raquel, T. Soc. de Guadalupe, pero no coge el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-06-22','Conversación con Asunción sobre el tema del registro de parejas de hecho.++++++++++ Comunico a Elvira Teruel (Reg. de Parejas de Hecho, D.G.de Infancia y Familia (68812)la situación de Juan como tutelado.Tienen cita en el Registro el día 4 de julio a las 12h. Le dijeron a Elvira que vivían en un Hostal de Madrid y dieron como teléfono de contacto el que en realidad es el de la hermana de Juan. Enviaremos a Elvira sentencia de incapacitación y aceptación de cargo. Solicitamos al Juzgado autorización para registrarse como Pareja de hecho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-06-23','VER CORREO-e DE ASUN en el expediente de Juan.+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Requisito para entrar en el Registro de Parejas de Hecho: NO ESTAR INCAPACITADA NINGUNA DE LAS DOS PERSONAS. Por lo tanto, NO es necesaria solicitud alguna al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-06-23','Se le cita en el Juzgado de Primera Instancia e Instrucción nº 1 de Mérida, para el juicio sobre delitos leves nº 46/2016 (pelea con Juan Nahum Cruz Ponce). No necesita abogado. No necesita que asistamos. Por las posibles lesiones, no fue reconocido por el forense, sin embargo Juan si.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2016-06-23','Juan Butista quiere formalizar su relación con una interna del sociosanitario, como pareja de hecho. No puede hacerlo al encontrarse incapacitado, requisito sine qua non para poder hacerlo. Elvira Teruel, de la Dirección General de Políticas Sociales e Infancia y Familia (924008812), les citó el 4 de julio al desconocer que se encontraba incapacitado. Ese día, si van a verla, nos llamará para que le remitamos la Sentencia de Incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2016-06-23','Se envía a Carmen Gallego Morillo (75510), del Cadex, Sentencia de Incapacitación y aceptación del cargo. Informa de que la madre esta solicitando un certificado de discapacidad para desgrabarse en Hacienda. No tenían constancia de que estuviera tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-23','Hablo con Valentín sobre la resolución para el traslado e ingreso de Hermenegildo en UDAC.++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Hablo con Rosa (CSS Plasencia). El INGRESO EN UDAC se puede hacer el próximo MARTES 28 de JUNIO, SOBRE LAS 11:00H: debe llevar dinero de bolsillo para gastos de bolsillo (+/-100€) y toda la documentación necesaria. Enviarán documentación a Mariluz para hacer la Resolución. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Clemen, Directora del CAM de Don Benito.No contesta. Hablo con Cristina, T. Social del CAMP: le informo de la fecha para el traslado y lo que tiene que llevar. Lo comentará con Clemen. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Recibimos en la Comisión Aceptación del Ingreso de Hermenegildo en la UDAC sin necesidad del paso previo por la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='VAZQUEZ'and apellido2='GUERRERO'),'2016-06-23','Estamos tramitando las herencias de su hermano Fernando (tenemos autorización judicial) y su madre Francisca Guerrero Monzú (hemos solicitado autorización judicial).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-06-23','Nos llama José Florencio, quiere 300€ para ropa, dice que su madre no nos va a llamar para solicitarnoslo. Le comento que nos lo solicite a través del centro (Aprosuba).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2016-06-23','Nos llaman del Centro donde está en Jaraicejo y nos comentan que está iniciando una relación con un señor del pueblo y van a hablar con el médico para derivarla a Planificación familiar y ver qué anticonceptivo le viene mejor porque tiene 52 años y aún con regla. Ines, Residencia. 608766943','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2016-06-24','Conversación con el Padre Fernando, Director de la Casa de La Misericordia de Pinofranqueado. Enviará informe sobre la relación de la madre y hermano de Álvaro con éste. INFORMACIÖN RECIBIDA:su madre (90 años, reside a temporadas en Cádiz) y su hermano Felipe (recién jubilado, reside en Moraleja) siempre se han preocupado por él y han sido con los que más relación ha tenido: lo ingresaron en el Centro tras salir de la UHB de Plasencia, lo han visitado (cada 15 días +/- su hermano, la madre cuando puede).Considera que la solicitud de D. Felipe de la remoción se puede deber a que d. Álvaro ha mejorado sustancialmente desde su ingreso, gracias a la atención personalizada, el control de la medicación, etc., consiguiéndose una importante mejora en su comportamiento y una reducción importante de su agresividad.Aunque es posible que esta sea la principal razón para querer su tutela NO SE PUEDE OBVIAR que también la madre, de 90 años, tiene propiedades (fincas, etc.), ni por supuesto que la madre está pagando desde siempre la mitad de la plaza de su hijo (500€). Cuando se ha ACCIDENTADO tanto uno como otro han acudido por las tardes al hospital para que el Padre Fernando, que lo acompañba por la mañana, pudiese maracharse del hospital. EL PADRE FERNANDO ENVIARÁ INFORME EN RELACIÓN A ESTAS CIRCUNSTANCIAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-06-27','Nos comunican desde Sevilla la trabajadora social que si fue la hermana de Jesús el 11 de junio a la convivencia familiar al centro penitenciario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2016-06-29','-solicitada cambio titularidad de PFHC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2016-06-29','el 28 de junio ingresó en la UDAC. Hablamos con Pilar TS nos comenta que no ha habido ningún incidente en el traslado, que llegó con dos educadores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MACIAS'and apellido2='MARTINEZ'),'2016-06-29','Nos envian desde dependencia elección de centros, hablamos con Pilar Bueno TS CS. Plasencia y elegimos plaza para mensajeros de la paz en Nuñomoral','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-06-30','Nos llega aceptación PIA, concecido ayuda a domicilio 20 H y cuantía económica 75€. ( Grado I)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2016-06-30','-Se incrementa su P.Incapaciadad a 636.10€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE VALERIANO'and edp.apellido1='RUBIO'and apellido2='ENCINAS'),'2016-06-13','Nos manda Mar de Salud Mental de Ciudad Jardín , un escrito de José Valeriano con sus últimas voluntades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-07-01','Ayer acudí al Juzgado de Primera Instancia e Instrucción nº 1, de Logrosán, a dos juicios por delitos leves 12/2016 y 24/2016, contra Tomás, por amenazas a su hermana María Isabel. No se presenta a los juicios. La hermana manifiesta ante la Juez, que se ratifica en las denuncias y que quiere que se dicten Sentencias condenatorias. A Tomás lo absuelven de los delitos que se le imputan, por aplicarle la eximente completa del artículo 20.1 de Código Penal. Una vez se dicte sentencia nos la comunicarán. La Juez me hace saber que al ser tutores de Tomás, debemos actuar para salvaguardar, primero a él, y segundo a su familia y vecinos, que reciben amenazas contínuas por su parte. Debemos informar al Juzgado de las actuaciones que podemos realizar, con los recursos de los que disponemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2016-07-04','Conversación con Pablo Cortés Rodicio (T. Soc. E.V. Dependencia Plasencia Norte. Valorado con un Grado II. Va a solicitar plaza pública en Badajoz, Mérida y Montijo (por acercamiento), si bien considera que la más adecuada es el centro de Demencias de Montijo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Juana, T. Soc. de Pozuelo, para que a través de su Médico de Cabecera solcite cita para el Neurólogo a fin de que emita informe para ingreso en la residencia de Montijo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SAUCEDO'and apellido2='AGUEDO'),'2016-07-04','Hablo con Rosa: no se puede hacer el traspaso de plaza de Educación a plaza de Dependencia porque en estos momentos no la hay. SE aconseja que para este tipo de casos se incien los trámites lo antes posible, si se prevé que el menor, una vez cumplida la mayoría de edad, va a ser tutelado por la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='PARIENTE'and apellido2='LUCAS'),'2016-07-04','Hablo con Juana, T. Social de Villa del Campo, 927-448177). Existe un local que está en muy malas codiciones y que afecta a los vecinos y quieren saber qué deben hacer. Le pido que nos envíen informe con las incidencias del local y su dirección, para ver de quíen es propiedad el mismo (Juana dice que en el Catastro no figura bien alguno a nombre de Dª Luisa).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-07-04','Número nuevo de Javier 657 83 30 08. ++++++++++++++A petición de Javier, a través de Asun, lo cito el miércoles 6 de julio a las 10:00h para hablar de un asunto aún por revelar. ++++++++++++++Me comunica que se va a ir con su madre y hermana a Portugal del 7 al 9 de julio y pide 80€ para llevar. Pendiente de hablar con Asun y con Adoración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='MUÑOZ'and apellido2='BURDALLO'),'2016-07-06','FALLECIDO El 05/07/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MACIAS'and apellido2='MARTINEZ'),'2016-07-05','ingresa en mensajeros de la Paz desde la UDAC (927-433003/87). Fecha de resolución 30 de junio de 2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-07-06','No consigo hablar con Asun. Los teléfonos de Dora Salamanca son: 924-314943 y 620-226363. Conversación con su madre: +++No considera necesario que se le de dinero por parte de la Comisión. +++Ella le puede dar dinero de bolsillo para que lleve algo, aunque luego se lo tenga que devolver (no lo pide Dora, sino que se lo propongo yo para que Javier sea consciente de que se trata de su dinero.) +++Dora lleva anotación de todo el dinero que le da a Javier (tabaco, veterinario para el perro, etc.) Incluirá en esas anotaciones el dinero que le de durante su estancia en Portugal. Le comento que lo siga haciendo así, porque en algún momento también nos puede ser útil en la Comisión. +++Tiene cierto temor a que durante estos tres días Javier se pueda tener uno de sus enfados, pero está ilusionada con el viaje. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++REUNIÓN con JAVIER.Acude para plantear un tema de carácter íntimo relacionado con el bloqueo que ha realizado a los números 800 desde su móvil. En relación a este tema, se le hacen ver los riesgos asociados al mismo y la forma de, llegado el caso, prevenirlos. Quiere que cada 2-3 meses pueda disponer de cierto dinero para ello.Quedamos en que cuando surja la situación nos llame para plantearlo. +++Respecto al dinero para el viaje está conforme con que se lo adelante su madre y luego, llegado el caso, se le reembolse a ella (se le propone ahorrar también para los gastos que comenta). +++Comenta que querría estudiar un módulo de Auxiliar de Veterinaria en el IES Tierra de Barros, pero en el PRL le dicen que todavía no tiene los hábitos necesarios para emprender ese camino. Le comentó que busque toda la información relativa a esos estudios (matrícula, horarios, prácticas, desplazamientos, etc.) y podemos volver a hablar de ello, teniendo en cuenta las consideraciones hechas desde el PRL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2016-07-06','Conversación con Pablo Cortés: Ha estado hablando con Juan en la residencia y él se niega a cualquier centro que no sea en Montijo (ver senetencia de incapacitación). La única alternativa de ingreso en Montijo en estos momentos es la R. Virgen de Barbaño en plaza privada (por Dependencia se le abonarían 426€) si existiese plaza vacante (EN CUALQUIER CASO HAY QUE CONTAR CON LA ACEPTACIÓN DE JUAN según sentencia, con el riesgo, además, de que una vez en Montijo dejase la residencia y se marchase a su casa). La otra posibilidad es que el informe de neurología permitiese el ingreso en el Centro de Demencias de Montijo, a la cual se podría acceder mediante cambio de PIA. EStudiaremos el caso y nos pondremos en contacto con Pablo. EN CUALQUIER CASO, Y EN BASE A LA SENTENCIA, NO PODEMOS SUPLIR LA VOLUNTAD DE D. JUAN A LA HORA DE TOMAR UNA U OTRA ALTERNATIVA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-07-06','Hablo con Manuel y Juan, hermanos de Ramón (924-953089). Les explico el por qué no se puede seguir transfiriendo a sus padres la cantidad de dinero acordada. Juan lo entiende, pero reclama los gastos que han tenido desde el ingreso de su hermano (traslados, tabaco, ropa...¿?)Se le indica que se les hará una transferencia. Respecto a la tutela, están de acuerdo en que sea la Comisión la que la asuma "...porque mis padres están muy mayores y Ramón se estaba portando muy mal...".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-07-06','Hablo con Manuel y Juan, Hermanos de Ramón: Juan comprende que en estos momentos no sigamos transfiriendo a sus padres el dinero acordado dado que su hermano no está con ellos, pero insiste en que los gastos ocasionados en este mes pasado sí tienen que cobrarlos (le indico que se hará una transferencia al respecto). Respecto de la tutela estan conformes con que sea la Junta la que se encargue de ella "porq','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-07-07','EL JUZGADO DE INSTRUCCIÓN Nº 2 DE ALMENDRALEJO NOS REMITE LA SENTENCIA DEL PROCEDIMIENTO DELITOS LEVES 32/2015 ABSOLVIENDO A JONATHAN DEL DELITO DE LESIONES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2016-07-07','Conversación con Pilar (Aux. Enferm.), al tener llamada con menasaje en el móvil del día 5 de marzo: Isabel está mucho mejor que cuando ingresó. Dice reclamar que la visiten y poder salir de la Residencia. Quiere darle a su hermana los 800€ porque se lo prometió para pagar una deuda. Require autorización judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2016-07-07','Recibimos fax de Aurora relativo a un nuevo procedimiento abierto en el Juzgado de Villanueva Nº 1, por delito de amenzas a su hermano Antonio. Hablo con el juzgado para comunicarles que Aurora está tutelada, les envio un fax con el Auto y solicito que a partir de ahora nos notifiquen todo lo relativo a este procedimiento. Lo siguiente será fijar fecha para la vista oral.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2016-07-08','Conversación con marcos, Director de la REsidencia: +++Pago de la plaza: la cargan en su cuenta. +++Gastos de bolsillo: enviará un presupuestoi aproximado de los gastos habituales que mensualmente tiene Dª Isabel. +++Gastos extraordinarios: cuando surjan lo comunicará. +++Consultas médicas: nos avisarán con antelación en caso de requerir acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-07-07','REunión de la Subcomisión de casos en el CSS de Plasencia.Conclusiones: +++Se considera que la psicopatología que tiene José María no es de base, sino que se desencadena por el consumo de tóxicos, por lo que debe ser en la red de drogodependencias donde se le busque el recurso adecuado, proponiéndose pisos de esta red ¿? +++NO se ve perfil para entrar en CRR por el motivo anterior y porque además hace falta la voluntariedad de la persona para el ingreso. +++Alternativa en caso de que no se le pueda asignar recurso en red pública es el piso que "Padre Cristóbal" tiene en Mérida. +++Controles en CEDEX Mérida: todos negativos hasta ahora.++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Tomás. Dado el nivel de integración de José Mª en el "Padre Cristóbal", cabe considerar que la mejor alternativa para continuar con el trabajo que se está realizando con él es que se mantenga en este recurso, pero accediendo a uno de los pisos que que la entidad tiene en Mérida (en Badajoz tiene dos). Tomás lo planteará en la próxima reunión de Equipo y me comunicará lo que se haya decidido para dar también la autorización desde CTAEx. José Mª ha pedido pasar un día en el CRR de Cáceres con su hermano Félix:tanto los profesionales del "Padre Critóbal", en coordinación con los del CRR y la hermana de ellos consideran que es una buena idea, pero cxon un contacto telefónico previo entre ellos para valorar su reacción ante la propuesta. La CTAEx, si todos los profesionales implicados esta´n de acuerdo en dicho contacto, no va a oponerse al mismo en este momento. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Ana (ESM) para informar, pero no consigo comunicar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2016-07-11','Llaman de la Famacia de Miajadas (927-348889).La madre de José Manuel ha encargado unas gafas y ha pedido al famacéutico que se pusiera en contacto con nosotros (la Comisión no tenía conocimiento de ello). El presupuesto es de 30€. Enviará factura con nº de cuenta y el nombre del tutelado (se da correo de ctutelar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-07-11','Llamo a Ana (T. Soc.ESM Plasencia). SE informa de : +++No hay pisos supervisados en la red pública de drogodependencias. +++Se informa de la conversación con Tomás (Centro "Padre Cristóbal"): dada la buena adaptación aquí de José Mª, se cree conveniente optar al piso que el centro tiene en Mérida (también acude al CEDEX para tratamiento con metadona y todos los controles negativos). +++Se insiste en que, dado que la permanencia en estos pisos no puede exceder de seis meses, hay que seguir planteando alguna alternativa de recurso para José Mª. COMUNICARÁ TODO ELLO A Carmen Parrado, Psiquiatra del ESM de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-07-11','Visita del padre de Miguel Ángel Molina, "exmarido" de Eva: "...Me he enterado de que Eva va diciendo por ahí que he abusado de ella..." Dice no haber recibido notificación alguna del juzgado y que el conocimiento de dicha acusación la ha obtenido por parte de su cuñado a quien al parecer se lo ha dicho Eva.Niega absolutamente dicha acusación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-07-11','-Se envia la PFHC con el cambio de titularidad . Se solicita que solapen ésta con la que venia percibiendo para que no quede ningun mes en descubierto , se le envia directametne a JUAN RICO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-07-11','Conversación con Luis Miguel (654-703639) y con la encargada fde la Inmobiliaria Talavera (C/. Salamanca, Cáceres). Enviarán borrador de contrato de arrendamiento para su valoración y firma (Luis Miguel quiere pagarlo a medias con su hermano Felipe, quien hasta ahora ha abonado el presente alquiler, EL CUAL DEBEN ABANDONAR A FINALES DE JULIO porque lo necesita la propietaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2016-07-11','Llamada a Miguel Ángel, hermano de José Mª, para saber los motivos de aquel para considerar no oportuno las visitas de José Mª a su madre. MOTIVO: considera que al salirse de su rutina habitual, cambiar horarios, comidas, medicación, etc. eso le va a provocar a su hermano una desestabilización que va a afectar también negativamente a su madre. "...Nosotros vamos cada mes, mes y medio a ver a mi madre y no tenemos inconveniente en acercarla para que vea a José Mª...". Se le explica que dichas visitas serán de unas horas, que no supondrán ninguna modificación abrupta de la rutina de su hermano y que, tal como él nos dijo en la visita que le hicimos, su madre también se alegra mucho de verlo (Miguel Ángel reconoce que así es). Finalmente no ve inconveniente en que su hermano pueda visitar a su madre de vez en cuando, incluso aunque no vaya acompañado (como inicialmente le propongo), siempre que esas visitas no den lugar a efectos no deseados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2016-07-11','Llama la Mª Victoria (T.Soc. Ayto. Alburquerque, 924-400000 y fax 924-401047). Situación de posible emergencia sanitaria de D. Isidoro: ha estado en el médico este fin de semana y los médicos han considerado que estaba deshidratado, pero que no presentaba criterios de ingreso hospitalario. Se envía sentencia de incapacitación a la T. Soc, para que su médico de cabecera inicie protocolo 112 para ingreso, ya que en dicha sentencia se contempla la autorización para ingreso en centro para atender su patología mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2016-07-12','Conversación con Victoria. D. Isidoro ingresó voluntariamente ayer en la UHB del Infanta. Hablará con la Unidad y me llamará para ver qué alternativas se plantean. Se intentó ya en la Unidad de desintoxicación alcohólica de Plasencia, pero no fue posible por no cumplir el perfil, al no ser consciente D. Isidoro del problema que tiene y no querer ingresar voluntariamente. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++SE mantiene en observación a las 14:16, momento en el que nuevamente hablo con Victoria: enviará la documentación solicitada por fax y correo ordinario.Nos mantendrá informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2016-07-01','Conversación con Jairo.Llama él solicitando: +++Quiere pedir una valoración de Dependencia ·"por privado". +++Renunciar a su pensión. +++Una familia de Marchagaz se me quiere llevar a Salamanca cuando termine los estudios. +++Necesita ropa: enviará relación a través de la T.Social por fax. No ha hablado de nada de ello con el personal del CSS porque son "el enemigo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2016-07-12','Conversación con Pilar (T.Soc. CSS Plasencia): Todo es la fantasía que tiene en su mente. Ha dejado la academia de acceso a la UNED. Está en URH (LO LLEVA MARIVÍ). No existe familia alguna en Salamanca ni recibe llamadas de nadie salvo de su abuela.','2');
