insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-07-07','SALIDA El 09/06/2016. Al cardiólogo. Acude para recoger resultados del holter. Todo está bien. Las palpitaciones que muestra son normales, es algo que le sucede a todas las personas por un sobresalto o un cambio de ritmo. No hay que darle importancia. Próxima cita: 04/12/2017, a las 11.15 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-07-12','Conversación con Carmen, hija de Mª Carmen y con el arquitecto Municipal: la casa, si interviene el Ayto de forma oficial, la declara de ruina inminente. Aconseja que sea la propiedad quien actúe. Carmen pedirá 2-3 presupuestos a las constructoras de la zona para valora la intervención. Según presupuestos, solicitar autorización judicial y si no es posible asumir el coste deberá ser el Ayto. el que proceda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-07-07','SALIDA El 31/05/2016. Prueba Holter. El día 30 le ponen el aparato y el día 31 se lo retiran. Tiene pequeñas palpitaciones, se ve como en determinados momentos se acelera un poco el corazón. Por lo demás, todo bien. Cita cardiólogo: 09/06/2016, a las 11.15 para que vea los resultados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-07-07','SALIDA El 30/05/2016. Holter. Le colocan el aparato y tiene que llevarlo 24 horas, no se puede hacer movimientos bruscos ni coger peso. Dormir boca arriba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-07-07','SALIDA El 06/05/2016. Urgencias. Tiene náuseas y mal cuerpo, muy cansado y ha vomitado. Le dicen que tiene gastroenteritis. Le inyectan Primperan. Tiene que hidratarse poco a pcoo y dieta blanda 3 ó 4 días, nada de lactosa. Si tiene molestias paracetamol.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-07-07','SALIDA El 05/04/2016. Neurólogo. Después de la exploración y de hacerle preguntas le dice que no nota cambios desde la última visita de 2014. Le dice que debe estar pendiente de si pierde fuerza o se cansa al subir escaleras. Próxima revisión febrero de 2017 a las 12.40 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-07-07','SALIDA Entre el 13/06/2016 y el 17/06/2016. Vacaciones a la playa. Va a Islantilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-12','Conversación con Montse, T. Soc. de Cilleros (625-545621). Se le plantea la propuesta, dados los antecedentes de Dª Antonia, de ingreso previo en UHB para estabilizar y pautar tratamiento que permita una mejor adherencia al Centro de Mayores. Comparte esta propuesta y me da el teléfono del Consultorio Local de Cilleros (927-512231). Los médicos conocedores del caso son el Dr. José Manuel y el Dr. Jesús. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Jesús. Le planteo la propuesta y la comparte, dado que el entiende que no es un caso fácil de resolver por cuanto Dª Antonia requeriría de un Centro de Mayores con características diferentes a los habituales (mayor control, etc), centro que no existe en etsos momentos. Acepta la propuesta de INGRESO EN UHB, que ya habían valorado hoy con Antonia en la Comisaría y que inicialmente contaba con la aprobación de la propia tuetalda (psoteriormente se ha desdicho sobre ello). Considera que se puede proceder a dicho ingreso mañana, hablándolo previamente con ella y procurando su aceptación. UNA VEZ INGRESADA, NOS AVISARÁN PARA QUE HABLEMOS CON EL/LA PSIQUIATRA de la UHB con la finalidad de explicar el caso y solicitar mantengan el ingreso unos días hasta conocer la plaza que, por emergencia social, ya ha sido solicitada.','2');
