insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-13','Conversación con Juan Manuel, Médico de A.P. Deriva a UHB de Plasencia y se comunica a Fernando (T: Soc. UHB) con la idea de que permanezca en UHB hasta su traslado a Centro Residencial (solicitado por E. Social).','2');
