insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2016-07-14','T. Soc. del SSB de Torre del Mar (ver expediente). LLamadas reiteradas sin obtener respuesta. Se envía corre-e a Javier Pacheco (Coordinador): CONTRATO DE ALQUILER por 12 meses y se informa del embarazo de Vanesa, para que se lleve a cabo el seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2016-07-13','Mantiene ingreso en el Infanta, pero le van hacer pruebas en el HPS Perpetuo Socorro y que no lo admiten en CSS de Plasencia en donde ya ha tenido varios ingresos en nla Unidad de Alcoholismo.Juanjo, el T.Soc. hablará con el psiquiatra para valorar posibilidad de acceso a la red de salud mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-07-14','Conversación con Dora, para saber qué tal durante el viaje a Portugal:+++Durante los días en Portugal (de miércoles a sábado) todo fue bien.+++ El domingo tuvo un ataque de cólera de los suyos, con puñetazos a la pared, gritos...delante de toda la familia (salta en cuanto se le niega lo que pide o se le contraría de alguna forma.): "...no puede estar con nosotros durante muchos días. No cumplía la más mínima norma de convivencia: metió al perro en la psicina, no colaboraba en las tareas de casa, se despertaba tarde y no tomaba la medicación a sus horas...Solamente ayuda a su abuelo regando, etc. y luego le da una propina (que puede ser su motivación)". Pactado con Asun, han estado 4 días sin ningún tipo de contacto con él. ESte domingo quieren reunirse para despedir a una de sus hemanas que se marcha de viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN ANTONIO'and edp.apellido1='EVERLISTA'and apellido2='LEONISA'),'2016-07-14','-tras conversacion telefónica con Silvia , TS del SSB , acordamos aplazar la decisión con respecto a Julián , a finales de agosto tiene cita con el neurólogo y vamos a esperar el diagnostico . Julian tiene G3 de depencia , estamos valorando dos posibilidades o Ayuda a Domicilio con una empresa de la zona dispuesta a empezar el servicio sin cobrarlo o ingreso en CAD Montijo para el que nos piden el informe del neurólogo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2016-07-13','- se le ha aprovado por dependencia mantenimiento en CO de Somima en Madrigalejo + 150€ para 10 h. de ayuda a domicilio . Estamos intentando contactar con Pilar para que le ayude a buscar la empresa . Se le envia el listado a su domicilio . Longina la TS del SSB de Madrigalejo conoce el caso .Cuando tengamos el contrato con la empresa y el resto de docuementación se enviará a Dependencia de Miajadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2016-07-13','-tf de su cuñada Pilar Carrero -tf de la Oficina Comarcal Agraria de Madrigalesjo donde trabaja Pilar 927029601/2 - pilar.carrero@hotmail.com -Se queda con Pilar que nos enviará el contrato nuevo con la empresa SAD por 10h para que desde aqui se envie a dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2016-07-14','Conversación con Eva Jiménez, T.Social SSB de Arroyo de la Luz (927-270002, Ayto.////correo-e: evaluzssb@gmail.com////655-093822, particular).++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Gestiones a realizar: +++Enviará Informe Social y Médico para justificar autorización Judicial de Internamiento Involuntario en Centrop de Discapacidad. +++Soliictaremos al Juzgado dicha autorización. +++Comprobar expediente de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2016-07-15','Victoria(T.Soc. SSB): comunica el ingreso de D. Isidoro en la UHB. Ha hablado con Mercedes (924-240047), del "Centro Hermano" de Badajoz: estaraían dispuestos a valorarlo y ponerlo en su lista de espera: la alternativa queda en función de los que se proponga desde la UHB del Infanta:++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++NO hay camas en el "Perpetuo Socorro". Está ingresado en UHB. Juanjo (T. Soc. "Infanta Cristina", 924-218075): hablará con el Psiquitra , Pablo Calderón (UHB Infanta)y nos llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-07-15','Conversación con Mariloli:ha salido hoy y mañana de permiso a su casa. Insite en que se quiere ir a una residencia (hace dos días, cuando acudió al despacho, dijo que ya no se quería ya ir a la residencia). +++++++++++++++++++++Conversación con Gisela: confirma el permiso de Mariloli para irse dos días a su casa. La semana que viene acudirá Mariloli a la CTAEx para que le firmemos la solicitud de la tarjeta de transporte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-15','ALTA HOSPITALARIA @ Buenos días, a través del presente comunico el Alta Hospitalaria, de la Unidad de Hospitalización Breve (Psiquiatría), de la paciente Antonia Campa Silguero, con fecha 14/07/2016. Destino domicilio en Cilleros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2016-07-15','Llamo a José Manuel (927-582309///635-031144///correo-e: jcorreamorato@gmail.com). Temas: +++factura de farmacia. +++Obras: siempre con presupuesto, según coste más de uno. Estudiaremos el pago del total o una parte de lo ya hecho y que no ha contado con aprobación por escrito de la CTAEx. +++Cancelar cuenta de ahorro que la tutelada tiene con su nieto Pablo y que no se ha cancelado aún. +++Valorar posibilidad de que la abuela no tenga que ir al banco para sacar el dinero, dada su edad. +++Enviará presupuesto de los gastos cotidianos de Dª Manuela para valorar cuantía autorizada. Le paso todo ello a Alberto para su gestión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2016-07-15','Se entrega a Maite documentación pendiente para acceso a Centro de Discapacidad de David.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='GARROTE'and apellido2='ARROYO'),'2016-07-15','May propone plaza residencial en Fuente del Arco.Conversación con Yolanda (T.Soc.Zafra) sobre idoneidad de plaza residencial en Fuente del Arco. Plantea mantenerlo en Zafra una temporada más, aún a riesgo de perder la plaza.le dejará el informe a Rosa o Julián para traslado y procurará que el día del traslado lo acompañe una persona significativa para él, seguramente Milagros. Yolanda esta de vacaciones hasta mediados de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-07-15','Reunión en la Comisión con Tomás, T. Soc. del "Padre CRistóbal". Informa que tras la reunión del Equipo para valorar el paso a los pisos supervisados del Centro de José Mª consideran que habría que trabajar algo más su autonomía. Le planteo si, en alguna ocasión, ellos o el CEDEx ha planteado la derivación a Comunidad Terapéutica de José Mª: nunca se ha planteado.VALORAR OPCIÓN DE DERIVACIÓN DESDE CEDEX A C. TERAPÉUTICA (estoy llamando pero no cogen teléfono) para atajar el problema de base. Para ello, reunirse con José Mª y Tomás, dada la voluntariedad que se requiere para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MACARRO'and apellido2='SANCHEZ'),'2016-07-15','Conversasción con Pablo (Dependencia): D. Juan no aceptó ninguna de las aletrnativas que desde Dependencia se le ofrecían en las distintas localidades próximas a Montijo: "Ha de ser Montijo o nada...". Aceptó la propuesta de Pablo para mantenerse en Pozuelo hasta que tuvieramos el informe del neurólogo valorando necesidadde ingreso en Residencia de Demencia de Montijo. Mientras tanto, pablo cerrará el PIA con un mantenimiento de la plaza actual, revisable cuando tengamos dicho informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2016-07-18','Llama Paloma: quiere un móvil y 40 € para ir a cenar con su padre. +++Hablo con Silvia (Futuex, 625548631): considera necesario el móvil para cuestiones como pedir cita en médico y estar comunicada en general. Se autoriza móvil de prepago (105+20€ de tarjeta con llamadas). +++Dinero para cena: no se autoriza, porque ya se le ha subido de 60 a 70 € semanales la asignación durante los meses de verano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='CALDERON'and apellido2='TAPIA'),'2016-07-13','INGRESO Actualmente ingresado en la Unidad de Psicogeriatría por alteración del comportamiento e incumplimiento de normas básicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2016-07-13','Tiene solicitado traslado a Centro Residencial de Casar de Palomero y Pinofranqueado para estar más cerca de su población de origen. Alto nivel de ansiedad y agitación. No tiene control del dinero, por lo que desde este Centro se le facilitan 5€ diarios para comprar tabaco y café. En junio de 2016 se le ha solicitado Prestación por desempleo para trabajadores eventuales agrarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='TREJO'and apellido2='MUÑOZ'),'2016-07-13','Desde su ingreso en este centro residencial -Felipe Trigo- ha mejorado notablemente física y cognitivamente. Está adaptado y se relaciona con facilidad con el entorno y el resto de residentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2016-07-18','Hemos recibido Auto 401/2016, del Juzgado de Primera Instancia e Instrucción nº 7 de Cáceres, decretando el sobreseimiento de la causa de la denuncia presentada por su madre, María José Álvarez Molano, en relacion con la venta del coche de Álvaro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2016-06-15','Nos envían solicitud de transporte subvencionado para sustitución de la tarjeta por pérdida. Lo pasamos a firma y lo enviamos a la Consejería.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-07-18','Conversación con D. Gregorio Rodríguez, alcalde de Valcecaballeros (628-556073). Enviará requerimiento de derribo y consultará si es posible que el Ayuntamiento se haga cargo del derribo y luego pasar la factura. Se plantea la venta del terreno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-18','Hablamos con Fernando TS (927-428302) nos comenta que la decisión del alta fue de la planta de psiquiatría, que él comunicó la situación y entregó la sentencia de incapacitación. la Dra. Lorenzo ha sido quién ha llevado a esta paciente. La trabajadora social de Cilleros (Montserrat) nos ha comentado que ha ido una vecina porque Antonia estuvo en su puerta a las 4 de la mañana del viernes 15, dando golpes con un cuchillo (hablamos con Dª Mauricia Martín, vecina agredida, quien dice que denunció los hechos a la G.Civil). Remitimos por fax el expediente para ingreso en residencia a Pina (territoriales de Cáceres) de Antonia, posteriormente se lo remitiremos por correo ordinario junto con los originales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-07-19','Esta misma mañana, a las 08h, se ha presentado con un señor mayor, D. Joaquín Guerrero Vázquez, en la sede de la Comisión Tutelar en Mérida. Motivo: D. Joaquín le reclama 40€ de una televisión que le vendió y que todavía no ha cobrado, así como otras pequeñas deudas como el billete de autobús con el que han llegado a Mérida, dinero para tabaco, etc. Se le ha pedido a D. Ramón que devuelva la televisión a D. Joaquín, propuesta que no ha supuesto ningún rechazo ni queja por su parte. SE le han autorizado 20€ para que ambos pudieran volver a Jerez de los Caballeros (al parecer el billete de ida lo ha pagado el acompañante de Ramón. SE COMUNICA POR FAX AL JUZGADO (ver).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-07-18','Conversación con Clara, T.Social del C.Salud (927-154305) y con Dª Isabel Glez. Jiménez (hermana de D. Tomás).Su hermana comenta lo siguiente: +++Comenta que estuvo viviendo con su hermano durante un año en su casa, pero que al final tuvo que dejarlo porque la dependencia de la droga de su hermano ya le daba miedo. +++Su hermano estaen una situación fatal. Ingresó hace 11 años en un Centro de desintoxicación en Morón de la Frontera, pero no le sirvió de nada (cree que salió peor aún). +++Cree que no ha ido nunca al ESM de Trujillo ni ha estado nunca ingresado. +++La casa la tiene destrozada: hace tres años era una casa en perfecto estado, pero se le metió en la cabeza que en ella había un búho de oro escondido(el lo llama su tesoro)y que se lo queríamos quitar. Ha picado suelos, techos, paredes, buscando "el tesoro" y así es como ha quedao la casa. +++No se puede hablar con él, porque se muestra muy agresivo. +++Actualmente están pendientes de la partción de la herencia familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-19','Conversación con Fernando. Intento de hablar con la Dra. Lorenzo. Se encuentra ocupada. Solicito nos envíen por fax Informe de Alta de Dª Antonia y, a ser posible, que se ponga en contacto con nosotros si considera que hay algún dato más de relevancia que debamos conocer. Le doy fax y teléfonos de Pedro Y Gloria. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al ESM de Coria quien ha llevado el seguimiento de Dª Antonia (ver Informe Médico-Forense durante el procedimiento de incapacitación).No consigo contactar con el ESM (927-149237). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Ester, Enfermera del ESM de Coria (927-149237): la T. Social está de vacaciones (cree que vuelve en agosto); el Psiquiatra que lleva a Dª Antonia es Juan José Mora y TIENE CITA CON ELLA EL 3 DE AGOSTO (el Psiaquiatra vuelve de vaciones la semana que viene). LLamarlo para solicitar informe de antecedentes y valoración de recurso adecuado para Dª Antonia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2016-07-19','Conversación con Mariví (T.Soc. CSS Plasencia).Base real que se origina cuando era pequeño, sobre la familia de Salamanca que menciona. No ha vuelto a tener contacto desde entoncesd con esta familia. Lo mismo con un tío que vive en Madrid, que pudo haberse hecho tutor de jairo, si no fuera porque este quemó la casa familiar. El único contacto que mantiene es con su abuela por teléfono: no puede vistarlo por problemas de salud. +++Otra de sus fantasías es la matriculación en la UNED para mayores de 25 años ("a la que contribuimos entre todos...").En el curso pasado no pagó las tasas (no se preocupó de abrir los avisos de la UNED para abonar tasas y por ello anularon la beca solicitada: se mantiene esa fantasía. Acude a una academia para preparar el acceso para mayores de 25.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2016-07-19','Visita de Cati: +++quiere probar a gestionar los dos reintegros mensuales en un solo reintegro a principi de mes. Le propongo mantener la situación como hasta ahora durante el verano, y pasado éste, según haya ido, probamos un mes a que reciba todo el dinero en un solo reintegro. +++plantea que si su antigua compañera de piso, Sonia, puede veolver con ella si se encuentra en una situación problemática. Esto depende de la Comisión y de momento no debe meter a nadie e3n el piso con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2016-07-19','Conversación con el Padre Fernando. no ha podido enviar el informe pendiente porque ha estado enfermo. Lo enviará lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2016-07-20','Solicitan salida desde asociación Vera para vacaciones con la familia del 8 al 18 de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-07-20','Conversación con Adolfo, Médico de Familia de D. Tomás (C. Salud:927-154305): +++Mientras vivió su madre estaba un poco más controlado. +++Acude a su consulta cuando se le termina la medicación. +++Nunca ha estado en el ESM. ACTUACIONES: +++En la próxima consulta le propondrá derivación al ESM para valoración psiquiátrica. +++Enviará informe clínico con situación sanitaria de D. Tomás y con propuesta de recurso apropiado para él. ***LA PROPUESTA de la CTAEx en cuanto al recurso que creemos más adecuado es ingreso en CSS de Plasencia para diagnóstico, estabilización y valoración posterior del recurso idóneo para él. ***Adolfo, al igual que la CTAEx, considera que no va a aceptar voluntariamente estas medidas, por lo que, llegado el caso, se procedería a solicitar al Juzgado la autorización de ingreso involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-20','Conversación con Pina Barrena (Territorial de Cáceres: 74325): Dª Antonia no da perfil para ingreso en C. de Mayores, salvo que un informe psquiátrico indique que ya no se producen estas alteraciones de conducta. Le explico que tenemos pendiente hablar la semana próxima con el Psiquiatra del ESM de Coria. PINA MANTENDRÁ EL EXPEDIENTE ABIERTO HASTA QUE DISPONGAMOS DEL INFORME CORRESPONDIENTE (TIENE CONSULTA EL DÍA 3 DE AGOSTO EN EL ESM). Se solicita acompañamiento a la consulta por parte de FUTUEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2016-07-08','VISITA DE LA CTEx AL CRR de Mérida: Buena adaptación al centro y, aunque en ocasiones manifiesta su deseo de volver a su casa de Cáceres, refiere estar muy agusto en él. Hablaremos con el hermano sobre su deseo de visitar a su madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2016-07-20','Conversación con Victoria: en el hospital, dada la gravedad del estado de D. Isidoro, se están planteando la posibilidad de ingreso en plaza de carácter sociosanitario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2016-07-08','VISITA de la CTAEx en el CRR de Mérida.Necesita renovar las gafas y se le trata de convencer de la necesidad de cuidar y revisar su salud bucodental.Se le convence para que vaya al dentista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2016-07-08','VISITA DE LA CTAEx EN EL CRR DE MÉRIDA. Se le intenta convencer para que vaya al dentista, pero no quiere segguir con la que inició el tratamiento (desconfía de ella). SE le propone acudir a otro, pero siendo esta la última opción para el tratamiento. Nos habla de sus primos Antonio y Mercedes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2016-07-08','VISITA DE LA CTAEx EN EL CRR DE Mérida: Su madre está en la Residencia de Olivenza y su hermana tiene un piso en dicha localidad (propiedad de la madre). Quiere irse algunos periodos de tiempo a vivir al piso: se le propone, y acepta, empezar por periodos cortos (una noche, un fin de semana, etc) e ir prolongándolos en el tiempo. Además se le proporcionará visitas por parte de FUTUEx.Queda a criterio de CRR cuando empiezan dichos periodos. Se le autoriza la compra de un móvil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MARTIN'and apellido2='SANCHEZ'),'2016-07-20','Se entrega en CTAEx Resolución de Baja de D. Teodoro en el CRR de Plasencia, pasando a ser atendido en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2016-07-20','Conversación con Pablo (nieto de Manuela, 676-783101) reclamando ver a su abuela. Se envia al Juzgado punto de encuentro en Mancomunidad de Valencia de Alcántara (C/. PIzarro nº 16). Propuesta:Miércoles de 10 a 12h. CONTACTO: Manuel Moreno (Gerente de la Mancomunidad,teléfonos: 927668147 / 628936678). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Mari Carmen (nieta): 671-438716.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-07-20','Nos avisan el día antes del Centro Sociosanitario de Mérida que le van a operar hoy de tiroides. Estuvimos en el hospital pero duraba mucho la operación y se quedo la TS del centro (María), los médicos le informaron a ella. Emilia ha sido intervenida y puede que tenga afectada las cuerdas vocales. El médico sugiere que necesita vigilancia 24 horas por el tema de los drenajes. Hemos contactado con Liliana y va a hacer el acompañamiento ella (655487649) 8€/ hora por el día y 10€/hora noche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2016-07-21','Visita de Catalina a la CTAEx para darnos la noticia de que su hermana se viene a vivir con ella. Parece muy ilusionada pero genera muchas dudas un anuncio tan repentino.Al parecer la hermana debe dejar su piso, como tarde, el lunes que viene y no sabemos nada sobre ella. Según Caty, su hermana es pensionista también. Al preguntarle por si van a compartir el alquiler del piso me dice que claro, que en "algo" la ayudará...Al parecer lo ha comentado con el dueño del piso y está de acuerdo (esto lo tengo que comprobar). Solicito información a Asunción Cabrera por si puediera saber algo de la hermana. Desconozco el motivo por el que su hermana de repente le ha comunicado que se viene a vivir con ella: Caty dice que porque quiere volver a su tierra. Se le comenta que la CTAEx no puede dar el vistoi bueno a dicha propuesta sin conocer de nada a su hermana. A lo sumo se puede quedar con ella durante unos días para poderla conocer y valorar la conveniencia o no de dicha convivencia (pendiente de la información que Asunción nos pueda proporcionar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2016-03-14','Se ha enviado a José De Egea Cabezas, contrato de arrendamiento firmado.Teléfonos de contacto: 924-372421 y 645-018030. Yolanda (hija):691-538603','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2016-07-21','Hablo con Olga TS( Valverde de Burguillos), no ha hecho ningún informe del padre. Comenta que el padre está algo mejor, que va con un andador y sale poco a la calle. Se le amplio el SAD de dependencia en más horas mensuales y siguen con la misma auxiliar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-21','Conversación con Dr. José Manuel, Médico de Dª Antonia.En su opinión, nuestra tutelada tiene una "personalidad manipuladora y tramposa" y quiere tener a su hijo en "un puño". "Tiene otra hija que no quiere saber nada de su madre desde hace mucho tiempo. Si la relación con su hijo va bien, en el pueblo es una balsa de aceite; si va mal, la cosa cambia." Su Médico considera que si ella fuera a una residencia en la que estuviera bien controlada, se adaptaría enseguida a las comidas, limpieza, compañía, etc...Cuando se lo hemos planteado (intentaron con los pisos supervisados de la localidad) dijo inicialmente que sí, pero cuando se enteró de que tenía que pagar se negó. ALTERNATIVAS: +++Residencia privada: tiene dinero para poder estar una temporada, a ser posible la más cercana a su localidad. +++Residencia pública: si es por emergencia social se requiere informe psiquiátrico que indique la no existencia de alteraciones conductuales (pendiente de hablar con ESM de Coria: Psiquiatra Dr. Juan José Mora). +++Si NO EXISTE VOLUNTARIEDAD para el ingreso, solamente cabe pedir autorización judicial para ello. José Manuel volverá a intentar hablar con ella para que acepte ingreso en residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL JESUS'and edp.apellido1='RODRIGUEZ'and apellido2='MURILLO'),'2016-07-22','enviamos a dependencia aceptación PIA para mantenimiento de la plaza en el CAMP de Don Benito.','2');
