insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2016-07-22','autorización para salida a Tenerife del 15 al 21 de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-07-22','Asistencia al Juzgado de lo Penal nº 1 de Badajoz. PA 194/2016.Se le condena a pena de 31 días de trabajos en beneficio de la comunidad y al pago de las costas. Pendien tes de recibir Sentencia. Cuando llegue, comunicar con Psiaquiátrico penitenciario de Sevilla para ver si fuese posible el cumplimineto allí. De no serlo, se trataría de que lo cumpliese yan en el recurso que se le asigne aquí. OBSERVACIÓN:a diferencia de lo percibido en el juicio de Sevilla, hoy Jesús se msotraba vacilante, con dificultad para articular palabras y con el labio inferior en movimineto constante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-07-08','Visita de la CTAEx en CRR de Mérida. Nos comenta Gisela que Mariloli ha empeorado en cuanto al manejo del dinero y propone modificar la autorizxación que tiene para sacar dinero sin acompañante. A partir del próximo mes deberá ir acompañada por Gisela o Javier, hasta que demuestre que no es necesaria dicha medida. Dolores manifiesta quejas en cuanto a la compañera de habitación, que dice ronca por las noches (sobre esto se le plantea a Gisela una posible solución que pondrá en práctica para ver si es efectiva: "tiritas" nasasales).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='LARIOS'and apellido2='CARRASCO'),'2016-07-08','Visita de la CTAEx en CRR de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='LARIOS'and apellido2='CARRASCO'),'2016-07-08','Visita de la CTAEx en CRR de Mérida. Fermina se muestra muy hermética, pero Gisela manifiesta que está muy adaptada a la Residencia y tiene un buen manejo del dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2016-07-22','SALIDA El 28/07/2016. Visita a su familia en el domicilio familiar con Cruz Roja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2016-07-08','Visita de la CTAEx en CRR de Mérida. Sigue acudiendo a la asociación de Ludopatía de Almendralejo. Plantea problemas de ronquidos por la noche, lo que supone una molestia para su compañera de habitación.Sobre ello, se le plantea a Gisela una posible solución que pondrá en práctica para ver si es efectiva: "tiritas" nasasales.','2');
