insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-07-22','ALTA CLÍNICA en el día de hoy tras su operación de tiroides. Se encuentra bien y sin problemas para hablar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2016-07-08','Visita de la CTAEx en CRR de Mérida.En tratamiento por su Trastorno de la conducta alimentaria. Manifiesta, como en otras ocasiones, que se quiere marchar con su familia. Sin embargo, como confirma Gisela, no existe contacto alguno ni con sus padres ni con sus hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2016-07-20','Acude Consuelo a la CTAEx. No quiere que la enfermera la ingrese:"...yo me encuentro bien, pero ella quiere que pese 48,5kg y yo ya peso más de 47...y estoy bien...". Argumento que reitera durante la hora que, al menos, hablamos del tema. No ha acudido a la consulta que tenía con su Enfermera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJO'and edp.apellido1='PIÑERO'and apellido2='CORRALES'),'2016-07-22','Llaman de la Residencia Santa Isabel de TRujillo. Esther, trabajadora de la Residencia: lo han llevado al CAR de TRujillo para valoración y decidir si lo mandan al Hospital de Cáceres.Insuficiencia respiratoria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2016-07-11','Reunión en Mérida con el','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2016-07-11','Reunión en Mérida con Javier y Carolina del CRR de Plasencia. Guadalupe se siente cansada y demanda su paso a un recurso residencial de mayores que la acerque a Jaraiz, lugar de residencia de su hija (ver Informe del CRR).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2010-11-23','SE LE AUMENTA A 300 € EL REINTEGRO MENSUAL QUE TIENE AUTORIZADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2016-07-11','Reunión en Mérida con Javier y carolina del CRR de Plasencia.Perfectamente adaptado al Centro. Su tratamiento contra la Hepatitis "C" le produce agotamiento. Se le aumenta el reintegro mensual a 350€ para requerir extras con menor frecuencia. Ver Informe CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-07-25','Llamamos al hermano de Jonathan, Antonio, dice que no sabe nada de él desde hace meses, que lo último que sabía era que estaba por las ferias. Nos comenta que no le llamemos a él , nos facilita el tlf de su madre Mª Carmen por si ella pudiera saber algo(722797982). Llamamos a la madre y tampoco sabe nada, juicio de mañana en Mérida (12:00)y la comparecencia en SS Penitenciarios en Badajoz el día 19 de agosto (12:30). Manifiesta amenazas constantes de su hijo, que dice haber denunciado. Se le propone que cuando vuelva a suceder, en ese mismo momento que llame al 112 para que envíen a la Policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2016-07-25','Recibimos el Informe del Padre Fernando.Ver expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-07-25','Llamamos a la madre y hermano de Jonathan para ver si le pueden notificar el juicio de mañana en Mérida (12:00)y la comparecencia en SS Penitenciarios en Badajoz el día 19 de agosto (12:30).','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-07-25','Reunión con Tomás (T. Soc.) y Tomás (Voluntario) del Centro "Padre Cristóbal". Ven como mejor alternativa el paso a los pisos que Cáritas tiene en Badajoz y Mérida, dado que José Mª ha cumplico en el Centro todo el itinerario propio de una Comunidad Terapéutica y con unos resultados muy positivos.Enviará Informe de propuesta y documento de solicitud de Plaza para ser firmada por la CTAEx. Durante en su estancia en el piso se trata de prepararse para una mayor independencia posterior, valorando también como opciones el colaborar como voluntario en alguna Asociación, prepararse el graduado, etc. PROPUESTAS POSTERIORES: +++Tras la estancia en el piso, por un periodo que puede oscilar según necesidad, la alternativa es un alquler compartido con algún comapañero con el que se vea una cierta compatibilidad. +++Otra posibilidad que ya están llevando a cabo con otro de sus casos es el convivir con una familia "de acogida" que le podría alquilar una habitación, facilitando una convivencia integradora como si en una familia propia estuviera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-07-21','Valentín pasa a la Comisión Nota Interior con Informe y Protocolo de Búsqueda de Recursos ante la próxima excarcelación de D. Jesús del Hospital Psiquiátrico Penitenciario de Sevilla prevista para el día 20-01-2017. En ese momento se le propone la convocatoria de una Subcomisión de Casos para valorar la situación de Jesús y buscar el recurso más adecuado para él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-07-25','Conversación con Mª Paz, de la Subdirección de Salud Mental (924-382656). Se expone el caso y, en una primera valoración, parece ser que lo más viable podría ser UDAC y según evolución derivación a Centro. DE acuerdo en que todo debería pasar, o bien por una reunión interna con el SEPAD o por la convocatoria de una Subcomisión de Casos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-07-25','La Inmobiliaria Talavera, de Cáceres, sita en C/. Salamanca, 3, 10002, 927220220-653765371, va a enviarnos por correo ordinario, por triplicado, el contrato de arrendamiento de Luis Miguel. Firman ellos en lugar de la parte arrendadora porque según Lola, de la inmobiliaria, está de vacaciones. Una vez recibido, lo firma Consolación y se lo devolvemos a la inmobiliaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2016-07-25','+++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJO'and edp.apellido1='PIÑERO'and apellido2='CORRALES'),'2016-07-26','De la Residencia de Las Hermanitas de los Ancianos Desamparados nos comunica Sor Margarita (927-321400///fax: 927-321004)el fallecimiento de D. Alejo en esta madrugada.Al parecer no dejó indicado su deseo de ser enterrado en un lugar determinado, por lo que será enterrado en Trujillo en lugar de en su localidad natal de Madrigalejo, dado que sus hijas no desean que sea enterrado en dicha localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2016-07-25','Llama la tía de Rafael: lleva dos meses con él y seguimos -dice-con la transferencia a su cuenta peculio (NO SE NOS HA COMUNICADO LA EXCARCELACIÓN).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2016-07-26','Llamo al C. Penitenciario de Badajoz. Hablo con Patricia , T. Social (924-289117). DEsconoce le tema de la cuenta peculio, pero me informa de que la excarcelación fue el pasado día 5 de junio. Me da teléfono de Peculio (924-289127): no me pueden decir si esas cantidades se han devuelto (procedimiento habitual tras una excarcelación) porque no tiene en estos momentos acceso a la cuenta. Llamaremos más tarde y comprobaremos los movimientos en la Cuenta de Rafael.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-07-26','Conversación con Francisco (hermano. Dirección Teniente Ruiz nº 1, Bajo. 10.003. Cáceres). Al parecer, en el banco le han vuelto a dar el dinero sin estar él presente (ha estado unos días fuera).+++Dice que lo ha visto bastante mal, con mal aspecto y con indicios de que pueda haber consumido "algo".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-07-27','Llamo a Pilar, T.Soc. ESM de Cáceres (927-213730)///Psiquiatra Dra: Mª Pellitas Ríos Muñoz: le informa de la situación expuesta ayer por Francisco y pido que citen a Saturnino. Enviarán la citación a saturnino y a la Comsion Tutelar, para que desde aquí hablemos con su hermano para que lo acompañe, tal como quedé ayer con él, dado que es posible que de no ser así no quiera ir a la consulta. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva llamada de Francisco: considera la situación de su hermano como insostenible. Me enviará correo con la descripción de la situación tal como él la percibe y admás dice que hablará con el médico de cabecera, conocedor del caso. Le pido que, o bien si la situación lo requierte el Médico inste su ingreso en UHB o bien que nos envíe Informe que nosortros podamos aportar al juzgado solictando dicho ingreso. ENviará su escrito y acudirá al médico de su hermano (Dr. Carlos Roncel).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-07-26','Visita de D. Miguel Rebollo, marido de una de las sobrinas de D. Arturo (622-623518/924-585298).Acude a la Comisión muy enfadado porque considera que su tío político lleva 8 meses tutelado y no se ha hecho nada con él y está en una situación muy mala. Información que proporciona: +++Durante 30 años han sido los sobrinos los que se han ocupado de él. +++Se le solicitó una plaza en residencial en 2013 que se le concedió y a la que no quiso acceder, motivo por el cual, al parecer, se solicitó la incapacitación. +++Durante el procedimiento de incapacitación se le dijo a la familia, todo ello según refiere D. Miguel, QUE TAL COMO QUEDARA INCAPACITADO D. ARTURO, AL DÍA SIGUIENTE ESTABA EN LA RESIDENCIA. +++Comenta que la situación de su tío es muy mala, que no acepta la ayuda de nadie ni quiere ir tampoco al médico de cabecera (nunca ha ido). RESPUESTA A SUS DEMANDAS: +++Se le explica los tramites que hay que realizar para ingresar a una persona en contra de su voluntad. +++Se le informa de los trámites realizados desde que tenemos la tutela de su familiar y se hace llamada a May (lista de espera en Residencia:3º en Los santos) y a Martina para confirmar grado de Dependencia (Grado I). REFLEXIONES: +++Con Grado I no se tiene acceso por Dependencia a plaza residencial (ver opciones de PIA en incidencias anteriores en esta Intranet). Además, si en aquel momento ese era el Grado, cabe suponer que el estado de D. Arturo no era de tal necesidad que requiriera dicho ingreso. Si en estos meses la situación ha empeorado, es lago de lo que nadie ha informado a esta Comisión. +++Al instar la incapacitadción se podía haber propuesto como medida cautelar el ingreso en centro adecuado, cosa que al parecer en ningún momento se planteó a pesar de ser la negativa de D. Arturo la que, según D. MIguel, motivó la apertura de dicho procedimiento. Según éste, han pasado diferentes jueces por este juzgado y todos han convenido en que D. Arturo no debía estar en esta situación, pero en ningún caso se ha comunicado con la Comisión para informar de ese supuetso empeoramiento. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Tal como le he dicho a D. Miguel, se va a solicitar una revisión del Grado de Dependencia. Además, me pongo en contacto con la MÉDICO DE FAMILIA de D. Arturo, la Dra. Olga Chaparro (C. Salud de Usagre: 924-585309). Según me comenta, tras exponerle la situación, ella lleva dos años como Médica en ese Centro y NO CONOCE A D. ARTURO NI NINGUNO DE SUS FAMILIARES SE HA PASADO POR SU CONSULTA PARA PLANTEARLE LA SITUACIÓN DE LA QUE HABLAMOS (cuando le pregunté a D. Miguel quién era el Médico de Familia de D. Arturo no supo contestarme...). Quedo con la Dra. en que mañana le hara una visita domiciliaria, pero me pide que, dado que no lo conoce, ni él a ella, la acompañe algún familiar a la visita. Tras la visita emitirá un informe de la situación de salud de nuestro tutelado y, si la situación lo requiriese, solicitaría su ingreso llegado el caso. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Tras hablar con la Dra., llamo a D. Miguel, quien se compromete a llamarla y a que algún familiar acuda mañana con ella a visitar a D. Arturo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-07-27','Llega fax de Aprosuba -14, informando de la sentencia por violencia doméstica dictada en el juicio celebrado el pasado día 21 de julio (DEL CUAL NO TENÍAMOS CONSTANCIA):30 DIAS DE TRABAJOS EN BENEFICIO DE LA COMUNIDAD Y 1 AÑO DE ORDEN DE ALEJAMIENTO DE SU MADRE. Una vez llegue la sentencia hay que buscar plaza residencial (¿por emergencia social?). Ya lo he comentado con Manuela para que sepa que vamos a plantear dicha solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='GARROTE'and apellido2='ARROYO'),'2016-07-27','Conversación con ARA, Directora de la Residencia de Fuente del Arco (924-878249 y 670-602881. Los de Manuela, T.Social SSB: 924-878001).Previsto el traslado para el día 1 o 2 de agosto. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a José Julián, T.Soc. SSB de Monesterio. Se le da el teléfono de Ara para coordinar el traslado en los días indicados. Hablará con Milagros para que acompañe a D. Manuel a Fuente del Arco. Se le dan varios teléfonos de la Comisión por si tienen que contactar con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-07-28','Conversación con Olga Chaparro, Médico de Familia de D. Arturo (C. Salud Usagre: 924-585309 y 924-280805). En la visiat de ayer fue acompañada por D. Miguel y uno de los sobrinos de D. Arturo. Considera que la situación de nuestro tuetelado no es tan mala y apremiante como nos dió a entender D. Miguel, si bien es cierto que su principal problema es de movilidad: "Le propuse solicitar un anadador o un bastón, pero se negó a cualquier tipo de ayuda. Solamente me dejó tomarle la tensión, cosa que sorprendió a sus familiares (la tenía un poco alta) y me dijo que no volviera más por allí porque no me abriría la puerta. Su familia le lleva todos los días la comida." +++ Le enviamos el modelo de informe médico para solicitar una REVISIÓN DEL GRADO DE DEPENDENCIA y nos enviará también informe de la visita realizada ayer. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nos llegá minutos después de esta conversación Informe de la visita, en el que se hace constar que la situación no se puede considerar de emergencia, aunque serían necesarias "...pruebas complementarias (analítica y ECG) y exploración física completa que el paciente no acepta.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-26','Conversación con el Dr. Juan José Mora, Psiquiatra del ESM de Coria (927-149237). Hablamos de la situación de Dª Antonia y de la dificultad de encontrar un recurso que se pueda adaptar a su trastorno de personalidad. La verá en consulta el próximo 3 de agosto y nos remitirá su informe,con valoración de antecedentes y situación actual, así como, a ser posible, una propuesta del cual considera que puede ser el recurso más beneficioso para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORO'and edp.apellido1='MORGADO'and apellido2='SANCHEZ'),'2016-07-27','Nos llega fax de Juanjo TS de psiquiatría del H. Infanta Cristina. Isidoro está ingresado en la UHB y le va a solicitar una plaza de atención sociosanitaria T3, nos remite la solicitud para firma delegada tutelar. Isidoro si quiere irse a una plaza de T3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-07-27','Acompañamos nosotros a Carmen al comedor social porque teníamos cita con María TS para entregar la documentación y que ella la conociera. El día 1 de agosto comenzará en el comedor, vamos a probar a ver si se adapta. +++TELÉFONO de Carmen: 661-112466.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2016-07-28','Conversación con Pina (74325). Enviaremos Informe del ESM cuando nos llegue. Ella está de vacaciones hasta el 16 de agosto. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Montse, T. Soc. de Cilleros (625-545621): D. Juan Carlos, hijo de Dª Antonia (651-664601), no quiere que su madre acuda al ESM d Coria con la ambulancia. +++Hablamos con D. Juan Carlos. No se opone a que su madre y él puedan desplazarse en la ambulancia, pero tampoco muestra su agrado por ello: "Siempre he sido yo el que he llevado a mi madre al médico y le aseguro que no faltará a la cita el día 3 de agosto a las 11:00h.Yo soy autónomo y puedo compaginar mi horario para poderla llevar..." . Le parece bien que su madre siga un control médico continuado, para que su situación actual se mantenga: "Ahora se encuentra muy bien, más activa y animada..." +++Tras la conversación con D. Juan Carlos, llamo a Montse:hablará con el Médico de Cabecera para anular la ambulancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-07-26','Reunión con Tomás (T. Soc.) y José María en el centro "Padre Cristóbal". Se le explica la propuesta de pasar a Pisos de Autogestión y estáde acuerdo con ello. Seguramente se podrá llevar a efecto a partir de septiembre. +++Tomás me enviará la solicitud de ingreso para su firma y remisión a Ana (Directora):pcristobal.cdmeba@caritas.es //abgarcia.cdmeba@caritas.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2016-07-28','Se está tramitando la declaración de herederos del padre de Jacinto. Hablamos con Julián (abogado de la madre que esta llevando el caso 699778726). Ha llegado una carta con una sanción por no haber liquidado en su día el impuesto de sucesiones, el importe son 200 € pero se reducirá a 150 € si abonamos en plazo y no recurrimos. Cuando llegue la carta de pago nos la enviará por email para proceder a su abono. Igualmente tramitará la declaración de herederos en la Notaría. Posteriormente nos enviará la minuta por sus servicios que se repartirá entre la madre de Jacinto, su hermana y él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2018-12-17','(Pedro)Llamada de D. José Mª Pardo Bravo (924-097238), Presidente de la Comunidad de Vecinos de Dª Carmen. +++ADEUDA LA COMUNIDAD desde OCTUBRE DE 2015 (último mes que la pagó) hasta la fecha. +++Lo paso a Alberto y me dice que lo envíe por correo electrónico. Así se lo pido a D. José Mª y así lo hará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LETICIA'and edp.apellido1='NIETO'and apellido2='SAN CARLOS'),'2016-07-28','Visita de Noelia y su primo Alfonso David: NO QUIEREN QUE Leticia VAYA A CASA DE SUS PADRES, porque según dicen, su padre está muy mal, ha abusado de Noelia (no la ha denunciado), maltrata a su madre y tienen miedo de que pase lo mismo con su hermana Leticia. +++HABLAR CON "LA LUZ" para verificar o no si tras la última visita a la familia (sept 2015) Le ticia ha mostrado algún tipo de alteración. +++HABLAR CON SSB para saber si se está trabajando algo con esta familia o si tienen información significativa respecto al posible riesgo que dichas visitas pudieran entrañar para nuestra tutelada. EN CASO DE CONFIRMARSE ESTE RIESGO, NO AUTORIZAR DICHAS VISITAS Y QUE LAS MISMAS SE REALICEN EN EL PROPIO CENTRO Y CON SUPERVISIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-07-28','Conversación con Dra. Agustina Glez (UHB de Mérida: 924-381000, ext. 81620): ayer, sobre la una de la madrugada llevaron a Mª Dolores a Urgencias porque la encontraron sobre un puente del Guadiana amenazando con tirarse. Va a estar ingresada unos días y seguramente le darán el alta la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-07-28','Se envía fax al Juzgado de 1ª Instancia nº 2 de Cáceres con la información facilitada por Francisco y por el ESM de Cáceres. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se intenta comunicar con el C.Salud de "San Jorge" (927-215636///URG:927-215562) para hablar con la Dra. Sara Miguel Carreras, actual Médico de Familia de Saturnino, según nos informa su hermano Francisco: todos los intentos para contactar son infructuosos, por lo que se vuelve a hablar con Francisco para que trate de ponerse en contacto con la Dra. y poder hablar con ella. Dado que seguramente no conozca a Saturnino, se le puede poner en contacto con su Médico anterior, el Dr. Carlos Doncel (se jubila a final de mes), en el C. Salud "Plaza de Argel" (927-242325).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2016-07-28','Hablamos con Margarita Fernandez Pérez, es la administrativo que le está gestionando la ayuda para el alquiler de Miguel Ángel Sánchez Bautista y Vanesa. Tienen hasta el 5 de agosto. Necesitan el contrato de alquiler y justificante del banco del pago del alquiler. Se lo vamos a remitir a ella por mail. mfperez@velezmalaga.es tlf. 952002232 / directo 673054006 y posteriormente por correo ordinario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-07-29','Llama nuevamente Francisco, nervioso por el estado de agitación con que se ha ido esta mañana su hermano de casa (había ido a tomar un café) al decirle que queriamos que lo viera su Médica de Familia: "...Me ha dicho que no se nos ocurra mandar a nadie porque no le va a abrir la puerta..." +++Francisco no había ido todavía a hablar con la Dra. Sara Miguel (le pido que vaya después de hablar conmigo) y nosotros, a pesar de los intentos reiterados de ayer y hoy, todavía en estos momentos no lo hemos conseguido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-07-29','FUTUEx informa: nueva dirección en C. Médico Sorapán 14,4ºD. Teléfono: 654-703639.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-08-01','-SE RECIBE RESOLUCION PFHC PERO CON EFECTOS ECONOMICOS DEL 1 DE OCTUBRE , NO HAN SOLAPADO LA PENSION CON LA QUE VENIA PERCIBIENDO . VUELVO A LLAMAR A JUAN PERO NO COGEN TF.','2');
