insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTINA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2016-08-01','Nos envían fax para informarnos que Martina desde el 30/07/2016, trasladada a la unidad de neurología, su hermana Paula le está acompañando. Nos adjuntan informes médicos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-07-28','Nos llama Clara TS del centro de salud, también hablamos con Raquel la TS de ESM y con la enfermera (Nuria). Juan el 12 de julio fue a revisión en ESM, comentan que no tiene adherencia al tratamiento y que él dice que no quiere ir más, fue solo a la consulta. El psiquiatra le ha vuelto a citar para enero de 2017. Le comentamos que nos parece mucho tiempo sin verlo!!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2016-08-02','enviamos al CADEX solicitud de tarjeta acreditativa de grado de minusvalía, nos la ha solicitado el centro,( Pisos supervisados de Zafra)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-08-02','Nos llama FUTUEX, Tomás ha estado en la oficina del banco y tiene la cuenta en números rojos, se ha puesto violento con la directora y han llamado a la policía. La policía después lo ha llevado al centro de salud porque estaba muy alterado. Hablamos con la Dra. comenta que no lo conoce y que no se puede hablar con él, le enviamos sentencia de incapacitación y lo deriva a UHB de Cáceres. Centro de salud de Guadalupe 927367217 Clara T.S centro de salud 927154305','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2016-08-02','-Tras llamada del curatelado , nos informa que la Guardia civil se ha personado en su domicilio para expulsarlo de allí , siguiendo la sentencia judicial por un asunto de violencia domestica , en el que le pegó a su madre hace unos años. La madre se fué al cuartel y comunicó la sentencia . Se le busca hostal a pension completa en Olivenza como él solicita durante 3 dias ( Hostal los Amigos ) pq del 5 al 12 de agosto se va a Badajoz con Aprosuba 14 de respiro familiar. Contacto con dependencia , para confirmar que tiene una revision PIA solicitando plaza RAL . Amalia se ruene con Manuela para trasladarle la informacióm, está en el puesto 57 por PIA . Hay que hacer solicitud por emergencia social , quedo con ella en facilitarle la sentencia por la que no puede estar a menos de 150m de la madre durante un año + 1 mes de trabajo en la comunidad y la comuniciación de este asunto que nos llegó desde Ap14. El informe social que necesita nosotros no podemos elaborarlo ni firmarlo , le corresponderia al SSB de Barcarrota .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2016-08-03','Desde el centro Hogar San Vicente, nos solicitan dinero para salida de vacaciones en Rota del 23 de agosto al 3 de septiembre. Autorizamos salida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-08-02','- el compañero de PFHC nos comenta que no pudo solapar la pension con la que ya venia percibiendo ( hubo que hacer cambio de titularidad a CTAEX) y que la normativa estblece que son trimestrales. Hasta el 1 de octubre no percibirá la PF .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-08-03','Se envía fax al Juzgado informando del ingreso en UHB de Tomás y su situación actual. La guardia civil enviará informes de todas las intervenciones que han tenido con el en los últimos tiempos para aportarlo a la petición de ingreso involuntario.','2');
