insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2016-08-09','Le hace seguimiento FUTUEX, nos comentan que este chico vivía en casa de su abuela pero la familia le ha dicho que se vaya de allí. Hace 5 años que va a al comedor social de Cáceres. Hemos hablado con la TS. del comedor Pilar 671016615, está de baja pero nos comenta que Samuel no se toma la medicación , que hace poco le dio un ataque epiléptico y que necesita supervisión, no sabe dónde está durmiendo ahora, cree que se queda en casa de amigos y conocidos. Una tía de Samuel también va a comer al comedor con él, pero comenta que ella no puede llevárselo. La TS del Ayto. está de vacaciones. Hablar con ella para ver el tema del alojamiento.','2');
