insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2016-08-12','El padre de Jose Luis Calvo ha ingresado el 11 de agosto en una residencia privada en Medina de las Torres. José Luis sigue en Cáceres en la UHB. La DRa María García ( psiquiatra) ha solicitado a Llerena un traslado para que se vaya a su área de salud. El puente de agosto lo va a pasar en Cáceres y tenemos pendiente despues el traslado. Nos comenta Soledad la TS de Virgen de la Montaña que tiene que ser Llerena quien solicite la derivación a UME de Mérida. En cuanto esté en Llerena hablar con ellos para derivación a UME Mérida. También nos llama Ana de la empresa de Valencia del Ventoso que tenían para SAD, hay que pagarles hasta el 12 de agosto, le comentamos que está en el hospital y no sabemos cuanto tiempo.Tlf empresa 924562228 y 606921558.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-08-11','-Realizamos visita a domicilio en Usagre. Nos reunimos con la TS que nos informa de la situación del tutelado , cree que lo más conveniente es plaza residencial pero en su informe social no refleja situación de emergencia social . En 2013 envió solicitud de ingreso residencial , renunció a una plaza en Los Santos .( Teresa de la Gerencia Bjoz nos comunica que está el 3 en los Santos y que en marzo de este año renunció a una plaza en Zafra . La información no concuerda , no sabemos en realidad qué es lo que ha podido pasar , May tampoco nos da informacíon. ) En el domicilio nos esperan sus sobrinos : Granada y su hno y José que es como Arturo quiere que lo llamamos. La vivienda está en perfectas condiciones de higiene y habitabilidad. José se encuentra sentado en el pequeño salón y nos hace una demostración de cómo se mueve por la casa , tiene dificultades en la movilidad pero puede acceder a todas las dependencias de la casa. Su sobrino es el que se encarga de ducharlo y su sobrina le lleva la comida y cena y se encarga de limpiar la casa y de la ropa . José no quiere que nadie realice estas funciones , declina el SAD .No ha ido nunca al médico especialista para su problema en las piernas y no quiere ni hablar de ir a ningún médico , no tiene conciencia de enfermedad ni toma ninguna medicación . El forense lo diagnosticó de discapacidad intelectual moderada . Es analfabeto , no sabe leer ni escribir , ni conoce la moneda actual ni siquiera sabe en qué año estamos . No sabe enceder el gas, ni el brasero , ni la TV ... Ante la negativa de sus sobrinos a seguir cuidandolo y la negativa del tutelado a recibir ayuda a domicilio no cabe otra opción que el ingreso en Centro residencial que se va a solicitar por Emergenicia Social ; puesto que por decreto está en una posición alejada y por dependencia no ha dado grado ( valorado con G. 1) A nivel economico se acuerda que de la nueva pension que se le ha abierto donde se ingresan 875€ en cpto de P.Orfandad , se le va a hacer transferencia bancaria a Granada para gastos de atención de su tio , quitando todos los recibos que se han domiciliado en la misma ( agua , luz, OAR, seguro decesos ...) y algún dinero que se le irá ahorrando , en torno a uno 50€.','2');
