insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2016-08-17','Nos llega denuncia de una vecina de Ricardo a través del teléfono del mayor. Le enviamos denuncia a Blanca TS del centro sociosanitario para que nos informe de la situación actual. Ya que en la denuncia la vecina manifiesta que en el domicilio de Ricardo se consume estupefacientes, hay peleas, gritos... también lo han visto a él por los pasillos del bloque.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='ESTRELLA'and apellido2='CARRASCO'),'2016-08-17','- Tras numerosas llamadas telefonicas consigo averiguar que fue Carolina ( TS del patronado de discapacidad de V.del freno) la que tramitó la PNC y la firmó el hno de nuestro curatelado . -Según ella y las TS de Daimiel la intencion de su hna es que los dos hnos se queden a vivir con ella , residen ella y su pareja con dos hijas de la misma y los dos hnos. quiere vender la casa del pueblo para comprarse allí otra más grande y solicitar la tutela de su hno. - No se va a enviar la documetancion solicitada por PNC para que anuelen el expte. -Se va a comunicar la situación a los Jgdos de Castilla León . NO se va a gestionar nada desde CTAEX puesto que su intención es no regresar a Extremadura','2');
