insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-08-18','-Dora y su hija se presentan en la oficina muy nerviosas pq Javier ha tenido un enfrentamiento con ella y quiere que nos lo llevemos del campo familiar donde están pasando las vacaciones. Ni Asun ni Pedro están que al parecer en otra ocasión lo han tranquilizado . Hablo con él y le digo que tiene que volverse a su piso , le envio un taxi a recogerlo . La madre nos queda las llaves del piso de Javier y 10€ para comida pq a las 14.30 que llega los bancos ya estan cerrados. Cuando llega Javier se muestra tranquilo y colaborador , acordamos con él darle su asignación semanal ( 43€) . Tiene que hacerse una analitica y acudir el dia 30 a la cita con su psiquiatra . La semana que viene realizará visita en su domicilio para supervisión y he enviado a la D. Tutelar','2');
