insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2016-08-24','Nos llega escrito enviado por la hermana (Antonia Valencia), Tlf. 661904382. En el escrito hace refencia a las deudas que tiene Juan Francisco del IBI y de recogida de residuos( OAR) y nos envia los recibos. la hermana tb manifiesta en el escrito que su hermano ingrese en centro residencial. Hablamos con el TS de Monterrubio, Antonio López, nos comenta que el señor con la ayuda a domcilio que tiene a través de dependencia lo ve bien, el tutelado no le ha manifestado que quiera irse a una residencia. Cree que entre los hermanos no hay buena relación por eso la hermana que vive en Bilbao solicita ingreso residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTINA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2016-08-26','Nos envía Juana TS del Hospital San Pedro de Alcantara, la resolución de ingreso en residencia de Martina. Hoy será trasladada en ambulancia desde el Hospital a la residencia de mayores de Villa del Campo. Está sin ropa, tenemos que ver cómo le llevamos ropa y sino se la compramos. La hermana se ha puesto muy alterada al enterarse en el hospital que su hermana se iba a una residencia. (La TS nos envió informe de lo sucedido).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2016-08-29','Llama Dª MªLuisa. Quire 300€ para ir a Servilla a cuidar a su hermana que está enferma y se va a ir con su hija Carolina y con su nieta.A las preguntas que le formulo me contesta con nula seguridad: si van a operar o no a su hermana, qué problema tiene, en qué hospital está ingresada...A nada de todo ello responde con seguridad alguna. +++Llamo a la hermana de DªMarisa, Dª Carolina (696-281560). Desmiente la "historia" de su hemana: "Mª Luisa no tiene ninguna hermana en Sevilla. La que tenemos está en Madrid y se encuentra perfectamente. Lo que pasa es que su hija tiene un novio en Sevilla y se quiere ir con él mientras mi hermana cuida de la nieta...". Dª Carolina se ofrece para cualquier consulta que necesites formularle en cualquier momento. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llama nuevamente Dª Mª Luisa. Sin revelar la fuente, se le indica que no se ha podido confirmar los datos dados por ella. Preguntada nuevamente, insiste en que tiene que coger esta tarde mismo el autobús, pero no sabe responder a si está ingresada o no y en caso de estarlo en qué hospital. Dice que se lo ha dicho su hermana Dª Carolina (con la que hemos hablado esta mañana) y al quedarse sin razones ha colgado directamente.','2');
