insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2016-08-26','SALIDA Entre el 09/05/2016 y el 13/05/2016. Programa de Turismo y Termalismo. IMSERSO. Conil de la Frontera (Cádiz).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2016-08-29','CSS de Plasencia. +++Conversación con Pilar Bueno T.Soc: plantea solicitud para que D. José Luis pase unos días en compañía de su madre en la localidad de Valle de la Serena. La madre pedía que fueran 15 días pero en el CSS consideran que una semana es suficiente. La CTAEx no se opone simpre y cuando se haga la solcitud por escrito junto con un Informe Clínico y Social que incluya, al menos, los siguientes aspectos: ********Justificación del beneficio clínico y social que para nuestro tutelado supondrá dicho permiso; ********Requerimientos que en cuanto a su salud precisa D. José LUis, dado que nos dicen que la madre es una persona de 82 años que no puede atenderle adecuadamente y que la Auxiliar que va a la casa una hora al día por parte del Ayto. dejará de ir si el hijo se presenta en la casa. Entre dichos requerimientos estarán: medicación y pautas, horarios de comidas, posibles alergias, etc. ******** Una vez recibido ese Informe, contactaremos con el SSB de Valle de la Serena para solicitar, bien la designación de una persona que pueda atender adecuadamente a D. José Luis, bien que nos informen de empresas de servicios de la zona que puedan hacerse cargo de dichos cuidados durante la semana en que D. José Luis esté allí. ********Tanto en uno como en otro caso habrá que PEDIR PRESUPUESTO para saber si nuestro tutelado lo puede costear y caso de que no sea así, VER LA POSIBILIDAD DE QUE SEA LA MADRE QUIEN LO HAGA. ********vALORAR CÓMO HACER EL TRASLADO, dado que parece ser que D. José Luis no puede hacerlo solo (Cruz ROja/Taxi/Futuex...). +++Converscaión con Rosa, Psiquiatra de D. José Luis: ve la convenciencia de dicha salida y está de acuerdo en remitir dicho Informe a la mayor brevedad posible, dado que se va de vacaciones en unos días, al igual que Pilar. En cualquier caso, se le indica que LA CTAEx NUNCA SE OPONDRÁ A NINGUNA MEDIDA QUE, CON LAS GARANTÍAS NECESARIAS, VAYA EN BENEFICIO DE NUESTROS TUTELADOS. En este sentido se le recuerda que quedó en el aire la solicitud por APROXIMACIÓN FAMILIAR, sin que ello fuera debido a esta Comisión, planteando nuevamente la misma, con lo cual Rosa está de acuerdo en llevarlo a una subcomisión de casos.TENER EN CUENTA QUE LA MADRE DE D. JOSÉ LUIS SOLO RESIDE EN VALLE DE LA SERENA DE MAYO A NOVIEMBRE (el resto del tiempo vive en el País Vasco donde residen el resto de sus hijos).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2016-08-30','Conversación con D. José Tello, propietario de terreno colindante a un olivar propiedad de las hermanas Collado. Plantea la necesidad de arreglo del camino de acceso por parte de los propietarios a las fincas de su propiedad, arreglo que debe ser sufragado por todos los propietarios de las mismas. También plantea la limpieza de dicho olivar por el riesgo de incendio. En su día se visitó ante la oferta de compra por parte de D. José, pero no se concretó por no necesitar el dinero nuestras tuteladas. Actualmente, si llegamos a aun acuerdo en el precio, se podría retomar esa opción si el precio de los arreglos supera el valor del terreno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2016-08-30','Citan a José María el día 20 de septiembre de 2016, para comunicarle la condena por el juicio (Procedimiento abreviado 502/2016), agresión al médico forense. La condena es de 60 euros y 6 meses de prisión. Le acompaña personal del Sociosanitario de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2016-09-16','Conversación con Yolanda Villegas (634675798). Hablará con su hermanao para saber si le pueden dejar el dinero para luego devolverselo poco a poco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-08-30','Conversación con Carmen, T. Soc. SSB de Jerez de los Caballeros. SE le consulta sobre las alternativas que pueden existir para el cuidado de los animales que tiene Ramón, durante le tiempo que este permanezca ingresado una vez se haga efectiva la orden del Juzgado. la alternativa de la familia creo que debería contemplarse en último lugar. Hará la consulta para ver si desde el Ayto. se puede plantear alguna opción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-08-30','Hablo con Patricia, T. Soc.C. Psiq. penit. de Sevilla, a raiz de correo-e solicitando un incremento en el peculio de Jesús.SE autoriza pasar de 150 a 175€ al mes (sin que él sea consciente de dicho incremento). La salida para enero está pendiente de que no tenga que cumplir otras penas, ya que se está "metiendo" en situaciones conflictivas con frecuencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2016-08-31','Llama Mª Socorro Blanco, hermana de Diego. Plantea que si había habido alguna incidencia en el centro con su hermano (al parecer algún trabajador del mismo la había informado, si bien, según cuenta, esa misma persona se había desdicho de lo informado). +++Pregunta también por el reparto de la herencia (quieren vender unas fincas y quiere saber qué tiene que hacer). Le pongo con Angel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2016-08-31','Hablamos con Dolores TS de Orellana, (924867801), nos comenta que el señor está muy abandonado.. el domicilio en muy malas condiciones (adjunta fotografías). No puede tener SAD x las condiciones en las que está la vivienda, comenta ella. Se le puso servicio de comida a domicilio pero tampoco resultó. Lo ven en los bares, no se alimenta adecuadamente..de hecho ha adelgazado mucho. No acude al médico, tampoco está derivado a ESM. La TS le ha solicitado depedencia. El único familiar directo que tiene es su hermana y ésta vive en Barcelona. Una vez tengamos inventario, volver a hablar con ella y ver qué recursos se podrían solicitar. Derivar a FUTUEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2016-08-31','Hablamos con Angeles la TS de Cáceres de Samuel, dice que antes de vacaciones estuvo hablando con él y no tiene muy claro si quiere ir a un centro. Le comento como bien ya sabe ella que es una curatela para la esfera económica. Le comento que hemos hablado con el comedor y allí tampoco sabían dónde pasa las noches. En septiembre que vuelva FUTUEX y a ver si consiguen que vaya al médico y tenga un seguimiento y buscarle recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-08-30','Hablamos con Isabel TS del Hospital Virgen de la Montaña. Nos comenta que están esperando plaza para Tomás en UME de Plasencia, en cuanto tengan el alta nos avisa. Hablamos con Clara TS del centro de salud de Guadalupe porque vamos a solicitarle la ley de depedencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-08-31','SE presenta Jonathan en la Comisión. Quiere dinero para la Feria de Mérida y comprarse ropa y una tarjeta para el móvil (traerá los justificantes de compra). Debería haberse presentado a su Oficial encargado el pasado lunes 29 de agosto pero no lo hizo (dice que porque su madre estaba ingresada). Llamo a la Policía Local de Mérida para comprobar si efectivamente ha acudido a su cita, pero no me cogen el teléfono. Puestos en contacto con el Policía Local, nos dice que acababa de comunicar hacía una hora a SSPenitenciarios de Badajoz esta incidencia y que él ya no puede hacer nada al respecto. Llamo a Paqui, T. Soc. de SSPenitenciarios para ver qué alternativas hay. Quedamos en lo siguiente:Jonathan irá a ver al Oficial Encargado esta mañana y empezará la prestación el día 2 de septiembre. Por otro lado, se le autorizan 70€: ropa para las Fiestas de Mérida, la Feria y comprar una tarjeta de móvil para estar en contacto con su Oficial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABINA'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2016-08-31','Conversación con Ana, T. Social de Valle Matamoros. Una sobrina de Dª Gabina ha preguntado por ella, porque dice que sigue manejando ella las cuentas, pagando todo, etc. Me llamará nuevamente para darme un teléfono de contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2016-09-02','Comunican por fax, desde el CSS de Plasencia, que se "amplia el pase" de Alfonso hasta el 3 de octubre, momento en el cual se valorará la posibilidad de alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-09-02','Nueva conversación con Carmen, T. Soc. del SSB de Jerez. NO ha podido averiguar todavía nada, pero hablará con el concejal cuando vuelva de vacaciones. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento comunicar varias veces con el Juzgado de 1ª Instancia nº 1 de Jerez de los Caballeros sin conseguirlo. Se envía fax con informe adjunto del ESM del día 1 de septiembre, así como explicaciones en relación a la ejecución del internamiento de D. Ramón.','2');
