insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-09-02','Conversación con Francisco, hermano de Saturnino. Muy alterado, diciendo que la situación de su hermano y de la familia es insostenible, a pesar del informe emitido por la Dra. Sara Miguel Carreras a principios de agosto. +++No sabe si, como se quedó entonces, se ha solicitado asignación de médico en el C. Salud de su zona: lo averiguará, intentará hablar con la Médico asignada y nos llamará. +++Hablo con el ESM de Cáceres (Pilar está de vacaciones hasta mitad de sept.) La Aux. Admva. me confirma que Saturnino fua a la cita que con Pilar tenía el pasado 27 de julio. PEDIR I. SOCIAL cuando Pilar regrese de vacaciones. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Francisco confrima el cambio de Médico de Familia: Dra. Rosa Harmeño, del C. SALUD de Plaza de Argel (927-242262 y 927-242325). Trato de hablar con la T. Social del Centro (Trinidad Alonso) pero tiene el día libre y la Dra. está de vacaciones. Su cupo lo asume el Dr. Alí. CONVERSACIÓN CON EL Dr. Alí.Tras explicarle la situación, no sabe si será posible hacer la visita domiciliaria en el día de hoy, pero dado que hoy viernes y el domingo va a estar de guardia en el PAC del "Virgen de la Montaña", me pide que le dé el siguiente teléfono, 927-256821, a Francisco Salgado para que se ponga en contacto con él si se produjera esta tarde una situación de crisis, incluso si no se diera esta. El Dr. Alí dejará aviso a sus compañeros de nuestra petición y, en el caso de que no se interviniese durante el fin de semana, el lunes 5 de septiembre, en cualquier caso, se realizaría la visita domiciliaria. EN CASO de que desde el punto de vista CLÍNICO se considerase necesario el ingreso involuntario, se procedería a él según el protocolo establecido. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Tal como he quedado con el Dr. Alí, llamo a Francisco, comunico el teléfono mencionado y las intervenciones a llevar a cabo. Francisco se compromete a estar pendiente durante el fin de semana, a pesar de que tiene previsto irse al pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LETICIA'and edp.apellido1='NIETO'and apellido2='SAN CARLOS'),'2016-09-02','Hablamos con Sole TS, nos comenta que ayer ya estuvieron hablando con la hermana y le ha comentado lo mismo que a nosotros. Así que ante la duda no la van a mandar a casa con su padre, que ayer por la tarde se la quería llevar pero le han dicho que no. Q si quiere verla que vayan al centro. Le envio x email a Sole la denuncia que ha puesto Noelia( hermana de Leticia) a su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GABINA'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2016-09-05','Llama nuevamente Ana, T. Soc.de Valle de la Matamoros(924-753894).Estamos pendientes de recibir los movimientos de su cuenta. Me da el teléfono de su sobrina, Paqui (680-737626), que vive en Madrid pero que ha estado este verano en el pueblo: VALORAR gastos habituales de su tía y si procede una limitación de su cuenta. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Paqui Venegas Corbacho, sobrina de Dª Gabina. Ella es la que se ha estado encargando de hacer la transferencia para el pago del SAD (Dependencia), motivo por el cual se puso como autorizada en la cuenta. Quiere que su tía esté en las mejores condiciones posibles. Se propondrá visita domiciciliaria a FUTUEx y se pedirá informe médico para valorar posible "demencia" y, en su caso, ingreso resoidencial. Paqui se propuso al parecer como tutora, pero no quería asumir la responsabilidad de ingresar a su tía (política) en una residencia. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo nuevamente con Ana (T. S.): me comenta que la empresa que lleva el SAD es MG SERVICIOS (924-731701 Y 652733914), de Jerez de los Caballeros. Dª Gabina tiene un GRADO II y recibe 45h/mes de SAD (2h 15´)díaFecha reconoceimiento de Dependencia el 21-05-2015. Solicitará visita domiciliaria del Médico de Cabecera para valorar estado de Dª Gabina y valorar también si se le debe derivar a neurología. SOLICITAR TAMBIEN VISITA A FUTUEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2016-09-05','Se recibe en la CTAEx citación en el Juzgado de 1ª Inst. e Instr. Nº 2 de Cáceres el DÍA 14 DE SEPTIEMBRE DE 2016, a las 09:15h, para declaración indagatoria en caso de supuestos a.s.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICOLAS'and edp.apellido1='LUIS'and apellido2='RODRIGUEZ'),'2016-09-05','El centro nos envia solicitud de dependencia, lo enviamos a dependencia la solicitud ya firmada. El director de la residencia "Virgen de la Asunción" también nos llama para comunicarnos que hay una plaza libre de asistido. Intentamos hablar con Mai pero no la localizamos para ver si se puede hacer un cambio de plaza de válido a asistido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2016-09-05','Enviamos hoy a la Oficina Liquidadora de Jerez de los Caballeros, solicitud de liquidación del impuesto de sucesiones por la herencia correspondiente a su madre, Dª. Sabina Ramos Rodríguez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-09-06','Recibimos citación judicial para el día 22/9/2016 en el Juzgado de Logrosán, a las 10:30 horas, por amenazas a su hermana María Isabel (Juicio sobre delitos leves 25/2016)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-09-06','Conversación con el Dr. Alí: no se ha realizado la visita domiciliaria, ni el pasado viernes, ni durante el fin de semana, ni ayer lunes, al no haberse puesto en contacto el hermano con el Médico (la del lunes habíamos quedao en que se realizaría en cualquier caso). +++No pone objección alguna para realizarla, pero cree conveniente hacerla junto a Trinidad Alonso, T. Social del C.Salud. +++Me pongo en contacto con Trinidad, quien considera que esa intervención se le debe pedir a los SSB. A pesar de mis explicaciones de que lo que la Comisión necesita es una valoración clínica ante una posible situación de crisis, de que se le informa de los términos en los que el juzgado nombra a la Comisión, insiste en que no es "asunto" suyo, pero que lo va a hablar con el médico. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada del Dr. Alí: ha ido con la T. Social y la P. Nacional (no ha hecho falta su intervención)y han trasladado a D. Saturnino a Urgencias del Hospital "Virgen de la Montaña" para valoración en Psiquiatría. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con la Médico de Urgencias en el "Virgen de la Montaña" (927-256800) para informar del caso: contenido de la tutela, diagnóstico, sin acudir a ESM desde 2014, cumplimineto de pena y últimas informaciones sobre la situación de emergencia referidas por su hermano Francisco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORA'and apellido2='RODRIGUEZ'),'2016-09-06','Nos envian fax del centro sociosanitario de Mérida para comunicar que Juan será trasladado al Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-09-07','Llama Carmen, la T. Soc. de Jerez.No es posible que nadie se encargue de los animales de Ramón, pero ha hablado con Manolo, su hermano (697-781239)y se ha comprometido a cuidar de ellos mientras esté ingresado. AVISAREMOS a Carmen de la fecha del ingreso para que se empiece a cuidar de los animales. Según Carmen, Manolo es una persona en la que se puede confiar para que lleve a cabo la tarea. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se pasa Nota Interior a la Jefatura de Unidad para dar cumplimiento a la orden judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2016-09-07','Quiere hacerse un tatuaje por el que al parecer ya ha pagado 30€. Gysela ha hablado con ella y opina que no es oportuno que se lo haga. Nos consulta para saber si lo autorizamos o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2016-09-07','Llama Ceferino solicitando dinero para ir a ver a su madre: "Quiero darle 100€ porque soy el principal beneficiario y mi hermano no puede darle nada...También querría que me subieseis la asignación mensal (200€) a 350-400€..." ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Leonor (CRR de Badajoz):+++los 100 € son para él, para el despalzamiento a Plasenzuela porque el autobús no llega a llí y tiene que coger taxi.+++Ahora le sstamos dando al día 4€ en función del cumplimiento de actividades, por lo que en basoluto requiere ningún aumento de asignación. +++Aunque su cuenta está limitada a 200€/mes, el ha sacado del cajero con la cartilla. ACTUACIONES: +++COMPROBAR la existencia o no de tarjeta para el cajero y si la cartilla tiene pin para usarlo: en caso AFIRMATIVO, ANULAR AMBAS ALTERNATIVAS. +++VIAJE A PLASENZUELA: se quiere ir el día 15 de septiembre. AUTORIZAMOS para el día 12 de sept. el reintegro de 100€, enviando la autorización al CRR por correo-e para que lo impriman y presenten en el banco. INSTRUCCIONES YA TRANSMITIDAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2016-09-07','Leonor (CRR de Badajoz) informa que debido a la fractura del brazo por una caída de Andrea al levantarse de la cama para ir al servicio, se han visto en la necesidad de contratar una empresa de servicios para el aseo de Andrea, ya que no pued e mover el brazo y necesita ayuda. Intentaron ponerse en contacto con nosotros pero no pudieron (feria) y tomaron esta decisión. La perosna que realiza esta tarea acude al CRR 1/2 hora al día, a un precio de 5€/hora todos los días de la semana. LE PIDO QUE NOS MANDE FACTURA MENSUAL DE DICHOS GASTOS. +++CONSULTAS MÉDICAS:16 de septiembre a las 8:00 en RX (en la "L" de Badajoz) y Traumatología a las 11h. Según lo que suponga el acompañamineto quizá la lleve la persona de la empresa mencionada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2016-09-07','Llama Aquilino mencionando que tiene un comprador para su "palacete" que le ofrece 30.000.000 pts. Consulto con Leonor, del CRR de Badajoz: "El único inmueble que tienen Aquilino con sus hermanos (un vive en Murcia y otro en Italia) es el de la calle Bravo Murillo, propiedad de la madre y que les queda en herenecia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2016-09-09','Nos llama la psiquiatra de la UHB de Llerena para comunicarnos que el 12 de septiembre lo trasladan en ambulancia a la URH de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LETICIA'and edp.apellido1='NIETO'and apellido2='SAN CARLOS'),'2016-09-09','VISITA de los padre de Leticia, D. Pedro y Dª Margarita. Piden explicaciones de por qué no le han dado permiso a su hija para ir a su casa en ferias y por qué no la dejan salir a pasear con ella por Badajoz: "¿Por qué me ha denunciado mi hija Noelia? ¿Uste se cree que a una persona que le han renovado el permiso de armas (lo muestra) se le puede tener alguna desconfianza? Yo también voy a denunciar a mi hija Noelia...? SE LE INFORMA DE QUE ESTAS MEDIDAS SE HAN TOMADO EN TANTO SE ACLARA LA MENCIONADA DENUNCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2016-09-09','Visita de Concepción a la CTAEx: quiere 100€ para ropa de trabajo. No se le autorizan al no ser el propio CRR los que hacen la petición, tal y como Concepción sabe por las reuniones con ella mantenidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2016-09-07','Correo de Gisela:Buenas tardes; Les comunico que de momento Concepción Alejandro Díaz no ha regresado al CRR desde ayer que se ha ido a ver a su hermana al hospital en Badajoz. Se había acordado con ella que regresaría anoche para la cena. Los mantenemos informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='ARNEDO'and apellido2='LOPEZ'),'2016-09-09','Llama nuevamente José Manuel. Comen ta que en relación a la finca de D. Francisco, en el reg. catastral aparece incluida una construcción QUE NO PERTENECE A DICHA FINCA. +++SUPERFICIE finca: 3has de secano en ladera. +++VALORACIÓN CATASTRAL: entre 1708 y 2500€ por ha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2016-09-09','Conversación con D. José Felipe Gutiérrez Gallego (630-541432), hermano de D. Álvaro, y demandante de la remoción de la tutela para asumir su ejercicio. Insiste en todos y cada uno de los motivos alegados en la demanda. Se explica en la medida de lo posible las limitaciones con las que cuenta la Comisión (dinero, sobre todo). En cuanto a la tutela, considera que su hermano debe permanecer en el centro en el que se encuentra, ya que uno de los motivos para haber renunciado a la tutela en su día era la posibilidad, actualmente inexistente, de que pudiera escaparse, además del grado de agresividad que manifestaba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-09-09','Conversación con el Dr. Alí (C. Salud Plaza de Argel, 0927-242262 y927-242325). D. Saturnino está ingresado en la UHB del H. Nuestra Señora de la Montaña desde el pasado día 7 de septiembre, con diagnóstico de trastorno psicótico y agresividad, con incumplimiento del tratamineto prescrito. +++En la visita domiciliaria realizada el pasado día 7, Saturnino les atendió desde el balcón. Cuando salió a la puerta, tapó la misma impidiendo el paso y la vista de la vivienda; se le impidió entrar para "coger algo", salvo que lo fuese a recoger con la Policía y se le retiró del bolsillo un objeto para evitar que se hiciese daño.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-09-12','Conversación con el Dr. Enrique Daniel, Psiquiatra de la UHB del "Virgen de la Montaña". Coincide con esta Comisión en que no es posible que D. Saturnino viva solo y conviene en que hay que buscarle un recurso dentro de la red de salud mental, aunque no tiene claro cúal: se le propone UME, al menos unos meses y llegado el caso un CRR (se le informa de la experiencia en el CRR de Badajoz). hablraá con los T. Soc. del Hospital para valorar las alternativas, pero de momento, Saturnino va a estar ingresado una temporada. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Francisco, hermano de Saturnino, para informarle de su ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2016-09-13','Conversación con Beatriz, Psicóloga del CRR de Mérida (924-304538). +++TATUAJE: Hablaron con el encargado de la tienda para explicarle la situación y le devolvieron los 30€ adelantados. Se quería tatuar el número del diablo. +++PESO: actualmente pesa 44Kg, 4 menos que cuando vino antes del verano a la CTAEx. Tiene cita en la U. de Trastornos Alimentarios de Badajoz esta semana. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Visita de Consuelo a la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-09-13','Conversación con Paqui, SSPenitenciarios de Badajoz (924-256158): NO SE PRESENTÓ AL AGENTE EL DÍA 2. Ayer lo comunicó el Policía Local a SSpenitenciarios. Nos enviará citación por FAX para Jonathan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='GONZALEZ'and apellido2='ROJAS'),'2016-09-13','Enviamos revisión PIA porque los pisos tutelados donde se encuentra lo van a cerrar. El TS. Daniel nos remite la solicitud de revisión de PIA para cambiar a otro piso tutelado. Lo enviamos a los equipos de valoración de dependencia de ZAFRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2016-09-14','Visita domiciliaria realizada hoy por Amalia y Pedro. +++DOMICILIO: impecable. +++ALIMENTACIÓN: compra diariamente la comida en una tienda de comida preparada (Mesa y Mantel, telf.xxxxxxxxxxx) donde estuvimos y pudimos comprobar que era así (lleva yendo 2ó 3 semanas) y no plantea problemas. Dejamos contactos de la CTAEx por si fueran necesarios. +++VECINOS: pudimos hablar con dos vecinos y el presidente de la Comunidad. El principal problema que plantea es que en ocasiones los pone "de vuelta y media" llamándolos brujos, que la estamos hechizando y poniéndole pócimas, etc. ESto, según los vecinos, no va más allá de suponerles ciertas molestias en la convivencia que tienden a relativizar. Les preocupa que de las palabras pueda pasar a ponerse violenta: creemos que no se va a dar la situación, pero se les indica que caso de que así fuera no dudasen en llamr al 112. Les dejamos también diferentes vías de contacto con la CTAEx de ser necesarias. +++DELIRIOS: mantiene sus delirios acerca de sus orígenes aristocráticos y su ideación acerca de estar sometida a conjuros, pócimas y complots a nivel mundial, mencionando a figuras políticas actuales y personajes famosos. +++VIDA DIARIA: creemos que dichos delirios no afectan significamente a su vida diaria, por cuanto ella desarrolla las actividades habituales sin problema alguno: tareas domésticas, uso del dinero, etc. Cuando terminamos la visita salimos a la calle y vimos que tomaba el autobús. Tras hacer diversas gestiones en relación al caso, volvimos a verla y a hablar con ella: llevaba la comida del día y se dirigía a casa.Nos pidió que a ver si le mandábamos a alguien de la Junta para que le arreglase la persiana para que no le costase nada, porque el que se la arregla le pide 30€. +++CENTRO DE SALUD: su médico de familia estaba de vacaciones y la T. Social estaba en otro centro. Hablamos con Mª Dolores, su Enfermera: considera que, a pesar de sus delirios, tampoco cree que fuese conveniente instar un ingreso involuntario, dado que los mismos no afectan significativamente a su forma de vida ni a sus relaciones.Ha estado últimamente en el C. Salud en varias ocasiones, pero al parecer al ESM lleva desde 2012 sin acudir (debemos comprobarlo). +++SSB: nuestra visita coincidió en el día con la realizada por Cristina (Futuex) acompañada de Iliana (T. Soc. del SSB). El punto de vista de Iliana era que ella creía que Paula se sentía muy sola al haber quedado su hermana Martina ingresada en la Residencia de Villa del Campo. Nosotros no sacamos esa conclusión. +++CONVERSACIÓN CON PAULINA. Al margen de los delirios antes mencionados, que centraron una buena parte de dicha visita, tratamos los siguinetes aspectos de su vida: *******SOLEDAD: a raíz del ingreso de su hermana ella denunció a la Junta por "secuestro" (nos mostró la denuncia ante el Juzgado de Guardia de Cáceres, en la que figuraba con el nombre de Isabel Martínez Fitschjames Stuart ¿?). ********RESIDENCIA: se niega en rotundo a ingresar con su hermana en la misma residencia ni en ninguna otra, ni quiere salir de su casa, porque en ella se siente segura a pesar de los conjuros de los vecinos y otros personajes.LLAMAMOS A LA RESIDENCIA para que pudiera hablar con su hermana: solamente mostró cierta emcoción cuando Dª Martina se pueso al habla y le hechó en cara, con voz muy forzada y frágil, que porqué la había dejado sola. Fuera de ese momento, paula no mostró más emociones al respecto.LE PROPUSIMOS IR A VERLA SI ELLA QUERÍA, pero se negó: "Yo no voy a ver a nadie, estoy muy bien así como estoy. Y si ella no viene mejor..." Por esto la impresión que sacamos en la visita no coincide con la de la compañera del SSB: realmente Paula parecía incluso sentirse liberada de la presencia de Martina. +++ACTUACIONES FUTURAS: ********Mantener las visita periódicas de FUTUEx. Inicialmente reacia, parece que finalmente lo aceptó. ********Solicitar al ESM informes de Paulina y valorar tipo de intervención a desarrollar. ********TIPO DE INTERVENCIÓN: creemos que el ingreso involuntarioo para valoración y estabilización de la situación, al menos en estos momentos y por las razones antes mencionadas, podría ser contraproducente para nuestra tuetelada desde el punto de vista personal y social, salvo que desde la perspectiva clínica así se aconsejase, debiendo, en cualquier caso, valorar conjuntamente ambas dimensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-09-15','Nos pide extra para butano y productos de limpieza. Ha pedido cita para renovar el DNI el 11 de octubre (9,30h-10.00h), cuando se vaya acercando la cita hay que darle un extra para tasas y fotos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2016-09-15','Ver correos electrónicos de Asunción Cabrera en relación con la hermana de Catalina (expediente).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-09-15','Hablamos con Teresa de territoriales de Badajoz sobre el ingreso en residencia por emergencia social. Nos comenta que el informe social sugiere plaza para asistidos y en el informe médico para válidos. Le comento que la Dra. lo ha visto un momento porque él no se deja explorar. Dice Teresa que necesita un informe social que justifique la emergencia social porque con la hoja complementaria que envió la TS Fefi no es suficiente. (El exp. 446/13) Así que llamamos a Fefi Ts de Usagre para comentarle que haga un informe social y si pudiera que hable con la Dra para hacerle un informe médico nuevo porque tiene poca puntuación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='PEREZ'and apellido2='GARCIA'),'2016-09-15','Visita de D. Bartolomé (678-581842), cuñado de D. José Antonio y Dª Celia, su mujer (hermana de D. José Antonio).Solicitando información de la situación de las cuentas de su hermano. Se les explica que se está pendiente de enviar la rendición final al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2016-09-15','Reunión con Valentín y Mariluz. Interpretan que el Auto del Juzgado no autoriza el ingreso involuntario y que, en cualquier caso, ni la Unidad ni la CTAEx pueden ingresar a nadie si no lo establece así un médico. Hablará con Fabiola, Psiquiatra del ESM. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Tras hablar con fabiola, Mariluz comenta que va a convocar una subcomisión de casos. CONFIRMA, demás, que hoy Ramón, acompañado de Silvia, ha acudido a la consulta para ponerse el inyectable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2016-09-16','Conversación con Gisela: alta de Emilia el pasado día 7 de septiembre y regreso al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-09-16','Conversación con Gisela: alta de Mariloli el pasado día 7 de septiembre y regreso al CRR. Prevista consulta para colonoscopia, para la que ya se firmó el consentimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-09-16','Conversación con Tomás, T. Soc. "Padre Cristóbal". +++José Mª está en el Piso de Cáritas, en Mérida, desde ayer. Nervioso inicialmente pero muy contento. PROFESIONAL DE CONTACTO: Toñi (607-500722 y 924-241231). +++CITACIÓN Juzgado de 1ª Instancia nº 1 de Mérida.19 DE OCTUBRE DE 2016 a las 10:30h. Tomás enviará informe sobre la evolución de José Mª en el centro desde su llegada. LO aportaremos al juzgado para que se tenga en cuenta en el mencionado procedimiento. Posteriormente, enviarán también informe desde el Piso con la evolcuión en el mismo. Si fuese preciso, también se aportará al Juzgado. +++Ya realizado el ingreso correspondiente al desplazamiento de Tomás al ESM de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-16','Visita domiciliaria a la madre de Cristofer y la pareja de aquella, Juan. +++Tienen pendiente un juicio por violencia doméstica contra Cristofer. +++Están de mudanza para trasladarse a un piso de Juan porque dicen que la convivencia con su hijo es imposible. +++SE le va a tramitar a Cristofer una PNC y valoraremos cuál es el recurso idóneo para él. Mientras tanto,seguirá acudiendo al Comedor Social y los fines de semana acudirá a Cáritas a por bolsas de alimentos. - tf de Cristopher: 636461030 - tf de su novia Sara : 651337597 - tf del padre Juan Rollán) : 615 127 248 - tf de la madre Antonia . 675474275 - tf de la pareja d la madre ( Juan ) 653165073','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-09-16','Nos envian informe médico de alta del Hospital Virgen de la Montaña, lo trasladan de UHB de Cáceres a UME de Plasencia. Le solicitamos a Marivi TS del C. Sociosanitario de Plasencia un certificado como que está actualmente en Plasencia porque el jueves 22 tiene juicio pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-09-16','Nos envian del hospital Virgen de la Montañ,informe de alta con el ingreso involuntario en UHB. En su centro de salud de Guadalupe activaron el día 15 el protocolo, derivándolo a UHB CC','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2016-09-19','Conversación con Clara (69269). D. Álvaro tiene reconocido Dependencia en G1,N1 desde el 6 de marzo de 2012. (Exp:CCO-09336-11) ala espera de determinar su PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-09-19','hablo con Paqui, del S. de Gestión de Penas de Badajoz. Nos envía por fax citación para Jonathan:+++++++ 10 de OCTUBRE de 2016 A LAS 11:00h+++++++. Debido a ciertas dificultades para comunicárselo a él, nos piden que lo hagamos nosotros: se le indica que no tenemos teléfono donde localizarle y que dependemos de que venga por la Comisión antes de dicha fecha. CUANDO VENGA, SE LE ENTREGARÁ CITACIÓN Y FIRMARÁ UN RECIBÍ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-19','Acuden a la Comisión Cristopher y Sara: "Mi madre dice que no va a renunciar a la casa por si su pareja la necesita en al gún momento..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2016-09-19','Conversación con Maribel, Directora de Apba. 9 (924-840900).DENUNCIA (16-9-2016) por abusos sexuales. Desde entonces solo puede salir en compañía de un Educador, si bien ella se lo toma como un castigo. Ella no tiene conciencia de que lo que hace no es correcto ni seguro para ella. Está desde hace años en el Programa de Modificación de Conducta, habiendo conseguido avances importantes pero no tanto en este aspecto.','1');
