insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='ANDREU'and apellido2='DAVILA'),'2016-09-19','Conversación con Maribel, Directora de Apba.9.Ha llamado Dª Sacramento Dávila Dávila (600-285406), prima de Javier, que vive en Zarauz. +++Casa de los padres de Javier: sin pagar impuestos, al parecer, desde el fallecimiento de su tía en 2013. DIRECCIÓN: C/. Sesmo nº 46 (Zalamea de la Serena). +++La tía de javier, en su testamento, lo dejó a él como heredero. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++La herencia de su tía ya está tramitándose. La de sus padres:se pedirá al reg. de Últimas Voluntades testamento si lo hubiera y también al Reg. de la Propiedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2016-09-19','OPERACIÓN CATARATAS Se procede a la comunicación con objeto de informar convenientemente de la operación de cataratas que se realizará hoy 19/09/2016, a su tutelada Gudalupe Martín Martín.','2');
