insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-09-19','Llamada de Francisco (hermano).Quieren comprarle ropa. Se le informa que los compañeros de la UHB nos piden aquello que pueda necesitar, pero que si le quieren comprar ellos algo, bien es pagándolo previamente y justificando dicho pago, o bien desde el hospital que se pongan en contacto con nosotros como ya quedé con su Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2016-08-16','Nos solicita Victoria cambio de centro, hablamos con ASINDI, le vamos a solicitar traslado a un centro más cercano a su familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='SOTO'and apellido2='DURAN'),'2016-09-20','REMOCIÓN Mediante Sentencia 243/16, de 19 de mayo, se produce la remoción del cargo de tutor de la Comisión Tutelar en favor de D. MANUEL SOTO VERJANO. Es hijo de José.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2016-09-16','Llega el informe solicitado por la CTAEx al CSS de Plasencia, tanto psiquiátrico como psicológico, con los requerimientos para garantizar una estancia de 15 días de D. Jose Luis con su madre en Valle de la Serena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2016-09-20','Conversación con Mª José, T. Soc. de Valle de la Serena (924-778001): no cree que sea una buena idea la visita del hijo por los siguinetes motivos: +++la madre acudió a ver a Mª Jose y la vió muy deprimida y baja de fuerzas. Además presenta una importante hipoacusia. +++la "intensa" relación entre madre e hijo que ella califica de "apasionada". +++el riesgo de que José Luis no se quiera volver al CSS una vez en el pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2016-09-20','Llama D. Carmelo: quiere hacer una obra en la cochera. Enviará dos presupuestos por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-09-20','Llamada de Elena, T. Soc. de Las Cumbres (920-269527 y 920-222610). Margarita se fugó ayer con otra compañera cuando fueron a un Taller en Ávila: se negaron a hacer nada y se escaparon. Aparecieron a la 01:00 de la madrugada en la estación de tren y la G. Civil las llevó al Centro, con la oposición de Margarita para volver.Mostraba una fuerte agresividad verbal. +++Comenta Elena que Margarita es una persona muy influenciable y que con toda seguridad fue la otra compañera la que influyó en la decisión. +++Si bien es la primera vez vez que el incidencte llega a este extremo, Elena comenta que ha habido otros episodios desde hace algún tiempo en los que Margarita ha insistido en que se quiere marchar de aquí. +++DECISIÓN DE LA DIRECCIÓN: ¡¡¡EXPULSIÓN!!!. Pido a Elena que hable con la dirección o bien que me llamen para tratar de cambiar la expulsión por otro tipo de medida. +++En cualquier caso, si la decisión es definitiva, les pido que den tiempo a esta Comisión para gestionar el recurso más adecuado para Margarita. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON MARGARITA: "Yo me quiero ir a Mérida, o Badajoz, allí con vosotros, pero no pudimos coger un tren ni un autobús porque no teníamos dinero...Ya sé que antes no me quería marchar, pero ahora sí..." .Le pregunto por el motivo pero no me da ninguna razón aparente. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversación con Elena: ha hablado con la dirección de "Las Cumbres" y podrían plantearse otra opción si Margarita hubiese reconocido su mal comportamiento, pero que dado que ella mantiene su actitud y deseo de marcharse del Centro, no les queda otra opción que continuar con la medida inicial. Piden que lo agilicemos lo más posible, pero no plantean ningún plazo para el traslado. Plazo que la Comisión tampoco puede determinar, como así se lo hago saber. +++ENVIARÁN INFORMES PSIQUIÁTRICO Y SOCIAL en relación a la medida adoptada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2016-09-20','En relación con la citación judicial para el día 19 de octubre de 2016, a las 10:30 horas, en la sede del Juzgado de Primera Instancia e Instrucción nº 1, de Mérida, se le cita a José María para tomarle declaración por denuncia de amenazas a Luis Fernando Fernández Muñoz, en el carrefour. Tenemos que acompañarle ese día. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se envía citación por fax (924-253193) a Tomás, T. Soc. "Padre Cristóbal". Seguramente acompañará también a Tomás él o alguno de los profesionales con los que ha convivido José Mª en el último año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-20','Le solicitamos PNC invalidez, enviamos solicitud junto con documentación compulsada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-09-21','Llama Elena, T. Soc. de Las Cumbres. HAN RECONSIDERADO SU DECISIÓN Y VAN A ESPERAR UN TIEMPO PARA VER CÓMO EVOLUCIONA. Nos piden que, de acuerdo con ellos, durante un tiempo llamemos a Margarita al menos una vez por semana para que vea que tanto el centro como los tutores vamos en la misma línea.','2');
