insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2016-09-21','Conversación con CSS de Plasencia. Rosa (Secr. Admón.). No está Pilar (T. Soc.). Conoce la situación de D. José Luis. Le comentó las últimas gestiones realizadas (SSB, presupuesto para 14 días de 3902€, etc.). Pido hablar con Rosa, La Psiquiatra, pero no estará hasta el lunes. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Mª José (T. Soc. de Valle de la Serena): tratará de hablar con Dª Inés para ver si sería posible que fuese ella la que acudiese a Plasencia para ver a su hijo, aunque en caso necesario hubiese que pagar un hotel unos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-09-21','Nos comunican desde el Juzgado de Logrosán, que los juicios 11/2016 y 25/2016, se suspenden hasta nuevo señalamiento.','2');
