insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2016-09-21','Hablamos con el centro porque nos han pedido si puede ir al club de ocio Koala y son 30€ al mes, le comentamos que en principio si y que siga manteniendo sus gastos de bolsillo en 70€. Si más adelante viéramos que no llega con esos gastos pues se reduciría gastos de bolsillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2016-09-21','Conversación con María Argeme, Directora de la Residencia de Mayores de Pinofranqueado (927-674276): el traslado desde la R."Felipe Trigo" se ha producido hoy, 21 de septiembre de 2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2016-09-21','Nos llega resolución con el traslado de centro de Felipe Trigo a residencia de mayores municipal de Pinofranqueado. Ya se encuentra en la residencia de Pinofranqueado. Se lo pasamos a la parte económica para realizar cambio de centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2016-09-22','Condenado por al Audiencia Provincial de Mérida a una medida de seguridad de 9 años y 8 meses de internamiento, con comienzo el 22 de octubre de 2010 hasta 2020. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Ingresado en el H. Psiquiátrico Penitenciario de Sevilla desde el pasado 16 de junio de 2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-09-22','Conversación con Manoli, T. Soc. del H. Psiq. Peniten. de Sevilla (955-616666, Ext. 135) +++AGRESIÓN.Jesús ha vuelto a pelearse con otro interno: lo golpeó con una bandeja de la comida tras la oreja y le tuevieron que dar 10 puntos. +++ROPA.Necesita ropa de temporada. Se le enviarán 200€ a su cuenta peculio indicando dicho concepto. +++CONVIVENCIA FAMILIAR. Prevista para el día de la Merced, se ha aplazado hasta mediados de octubre (15 o 22 seguramente).Nos confirmarán la fecha para que su familia pueda ir a visitarle. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se recibe FAX de JUICIO ORAL en el Juzgado de Instrucción Nº 16 de Sevilla el 23 DE enero de 2016 A LAS 11:00h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2013-01-30','Se recibe llamada desde el Psiquiátrico Penitenciario preguntando si el informe que se pide desde la CTA desde qué aspectos interesa saber del tutelado. Se le comunica que sobre las cuentes del mismo. También nos informan que se la intentado hacer la Tarjeta Individual Sanitaria de la Junta de Extremadura y se han enterado que carece de cobertura sanitaria. Se pide información a Seguridad Social y se constata que está en situación de alta y que nos remitirán una copia sellada para enviar al Psiquiátrico Penitenciario de Sevilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2005-04-21','Se ha aceptado y jurado por Acuerdo de 21.02.00. Solicitado todo a Mérida, a Monterrubio y PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTINA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2016-09-22','Hablo con Juana la TS del pueblo, Villa del Campo, nos comenta que nos ha enviado la autorización para firma por correo ordinario. Le vamos a tramitar PNC y le comento que su hermana no nos facilita la ropa, así que cuando necesite que nos envien presupuesto y nosotros se lo pagamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2016-09-22','Una vez aprobada la solicitud de PNC, visitarle, informarle de ello y valorar con él gastos al margen de la alimentación (comedor social Cáceres). Averiguar dónde vive ahora y valorar con él sus planes en relación a la vivienda (compartir alquiler, pensión, etc.).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROGELIO'and edp.apellido1='FERNANDEZ'and apellido2='VEGA'),'2016-09-22','Actualmente se encuentra en Residencia Club de ancianos de Coria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-09-22','Se envía respuesta a la Secretaría General de la Consejería para su contestación a D. Miguel Ángel Rebollo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2016-09-22','Nos llama la TS de Llerena, Maribel, nos comenta que tenía cita con él, el 27 para hacer el informe social para enviarnoslo para el inventario. Y hoy le han informado del Hospital que está ingresado en la UHB de Llerena porque ha intentado tirarse a la vía del tren(porque dice que no quiere ir a un centro).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2016-09-22','Gabinete Jurídico. Restitución de la Capaciad. Ref: 38117.Lo lleva Escalona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2016-09-23','Llama Fátima T. Soc. del ESM de Mérida, para interesarse por Carmen. PRÓXIMA CITA :28 DE OCTUBRE DE 2016 A LAS 14:10 (con Psiquiatra y T. Soc.).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-09-22','Nos llama María Barrasa TS nos comenta que la Dra. no ve a Ramón como paciente psiquiátrico y a finales de mes le van a dar el alta ( comenta que no tiene esquizofrenia), nos tienen que mandar los informes médicos. Comenta María que solicitemos revisión CADEX y que nos digan allí qué tipo de centro para este chico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-09-23','Llamada a Margarita para ver qué tal sigue su situación. Elena comenta que está mucho mejor y que ha pedido disculpas por inciativa propia a cada uno de los profesionales implicados en la solución de su "escapada". Refiere nuevamente que los problemas que plantea Margarita lo que tienen detrás es realmente la influencia de terceros, dado el carácter extremadamente influenciable de Margarita que le lleva a "dar" a los demás "esperando" a su vez de ellos una respuesta que, cuando no llega, la frustra y enfada. Refiere que se está trabajando con ella este tema, relacionado con su necesidad de afecto y su sexualidad. Quedo con ella en que la llamaremos todas las semanas sobre las 10:00 o la 13:00 para ver evolución y hablar con ella. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON MARGARITA: Le felicito por sus disculpas ante los compañeros de Las Cumbres, y sin decírselo sabe a qué me refiero con dicha felicitación. No ha desayunado todavía, me explica lo que van a tomar y que le gusta la gimnasia y los talleres de dinámicas y de manualidades. Le pregunto si quiere que la llame la semana que viene y responde que sí, creo que con ilusión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-09-23','Conversación con Manoli, T., Soc. Psiq. Penitenciario Sevilla:CORREO-e de Manuela:manuela.raspon@dgip.mir.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2016-09-23','Llama Catalina:¿qué hago si viene mi hermana? la opinión nuestra es que ella está mejor sola. Su hermana está tramitando en el SSB la renta básica o las prestaciones por desempleo por si tuviera derecho a ello. Se le indica que pregunten también por posibilidad de vivienda social o centro residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2016-09-23','Se recibe en la Comisión sanción de Hacienda por posesión de una cantidad de droga (0,50gr) remitida por el CSS de Mérida, a donde ha llegado remitido por un familiar. Se firmó el acuse de recibo el 22 de agosto por su hermano Ramón y no ha llegado aquí hasta hoy. SE comunica con Hacienda y solamente queda el pago de la sanción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2016-09-26','Llama Eva, T. SSB de Arroyo de la Luz (927-640019). Ha vuelto a recibir petición de informe social (lo envio a finales de julio). TRazón: coincidió la petición de ingreso involuntario con la rendición anual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2016-06-09','Se visita en su domicilio a Dª Carmen.No muestra ningún inconveniente para recibirme, una vez me identifico como Pedro, de CTAEx.Se encuentra bien. Comenta que tiene una deuda con Hacienda de 14.000€ y un préstamo con Bankia de 9000€. Con la P. de Horfandaz dice pagar los gastos corrientes y un inquilino le debe 4000€ del piso de la calle Macom nº 137.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2016-09-26','Llama D. Juan (924-366582), hermano de D. José Mª: "Mi hermano está empeñado en que le compre una silla de ruedas con motor..." llamaré a Ana, Médico de Familia de Villagonzalo,y/o a Guadalupe, T. Soc. del C.Salud para ver si es necesaria la silla y en caso de serlo, si José Mª es capaz de manejarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-26','Conversación con Fátima, T. Soc. ESM de Mérida (924-487229). Cristofer acudió ayer a Urgencias muy alterado (no sabemos si acompañado o solo) tras una discusión con su novia Sara, según comenta Fátima.Tras darle la medicación correspondiente se le dió el alta. +++Le explico a Fátima la situación en la que se encuentra en estos momentos Cristofer y quedamos en que hablará con su Psiquiatra para valorar tratamiento, seguimiento y recurso más adecuado para él. En opinión de Fátima, un CRR o un piso supervisado serían las alternativas más adecuadas (coincido en su opinión). La dificultad principal puede estar en que tiene un Trastorno Límite de Personalidad asociado a Retraso mental moderado. Hablará con el Psiquiatra y nos informará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICOLAS'and edp.apellido1='LUIS'and apellido2='RODRIGUEZ'),'2016-09-26','Llama la T. Soc. de la Residencia de Torre de Don Miguel (638-658981): solicita información para comprar un colchón antiescaras. Enviará dos presupuestos y una vez autorizado se pagará por transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-26','CITACIÓN PARA DECLARAR: Juzgado de 1ª Instancia e Instrucción Nº 2 de Mérida. DÍA 14 DE NOVIEMBRE a las 10:00h. P.A. 599/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-09-26','Llama nuevamente María Barrasa. Este miércoles le dan el alta a D. Ramón. La Psiquiatra ha citado a los familiares a las 10:30h DEL MIÉRCOLES 28 de para hablar con ellos y plantean a la Comisión nuestra presencia en dicha reunión.+++DIAGNÓSTICO CORRECTO: TRASTORNO LÍMITE DE PERSONALIDAD (NO esquizofrenia). +++Envían Informe médico con dicho diagnóstico para que SOLICITEMOS revisión en CADEx para determinar perfil (no es de Salud mental) y recurso más adecuado. +++Consideran en el CSS de Mérida que el recurso adecuado sería el CAMP, porque ya no es justificable su permanencia en la UME dado la buena evolución del paciente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-27','Llama la madre de Cristofer. Al parecer la pelea fue con el hermano de Sara. Cristopher se cortó y lo llevaron al Hospital. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Su madre dice que va a seguir pagando la casa, pero que en noviembre ya le viene el recibo de luz y agua y que lo cortará si no nos podemos hacer cargo de él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-09-27','Visita de Luis Miguel a la Comisión. +++Teléfono: 654-703639. +++Quiere cambiar de abogado porque ha perdido la confianza en el suyo. Dice querer cambiarse a A.L. Aparicio jabón, porque se lo ha recomendado un amigo suyo. +++Plantea la posibilidad de solicitar una ampliación de la incapacidad para eludir la pena que dice que pueden llegar a imponerle (15 años), pena que no sabemos quien le ha podido decir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2016-09-27','En relación al procedimiento sobre agresiones sexuales a su exnovia, Elena Álvarez Senso, consultado en qué estado se encuentra el mismo con la Audiencia Provincial de Cáceres (Procedimiento Sumario nº 10/2015), nos indican que se encuentra en fase de calificación, sin haberse realizado el juicio aún. Su abogado es Francisco Elías Rodríguez Plaza (927212263-927224245)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2016-09-27','Conversación con Rosa, Psiquiatra del CSS de Plasencia. Se le exponen las dificultades de todo tipo que plantea la estancia de D. José Luis en casa de su madre, también a nivel económico. +++Ve bien si la madre puede ir a pasar unos días a Plasencia. Intentarían ajustar los horarios para que pudieran pasar el mayor tiempo posible juntos. La llamaré nuevamente cuando hable con Mª José. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª José:no ha podido hablar todavía con Dª Inés. Quedamos en hablar mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2016-09-27','-viene su hno Juan para comunicarnos que va a comprarle una silla con motor , él la pagará de su dinero (2300€) , lo financiará mensualmente , le informanan que seguramente la Seguridad Social le abonará una parte o la totalidad , y si no de igual forma la va a comprar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-09-27','Conversación con Inmaculada (T. Soc. C. Salud de Jerez de los Caballeros) y con Fabiola (Psiq. del ESM): +++En ningún caso está de acuerdo con el diagnóstico de Trastorno Límite de Personalidad. +++Ya había hablado con Isabel, Psiquiatra de UME, con la intención de convocar una subcomisión de casos para tratar la situación tanto de Ramón Giles Salazar como la de R. G.H. Está pendiente de dicha convocatoria, a la que citarán también a la Comisión Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE VALERIANO'and edp.apellido1='RUBIO'and apellido2='ENCINAS'),'2016-09-26','- se realiza visita domiciliaria ( Amalia y Teresa ( futuex) . La casa la tiene en perfecto orden y limpieza y rechaza SAD , con lo que se declina solicitarlo . -Tf de Jose Vale : 634659641 es de prepago , recarga 10€ al mes . -A partir del 1 de octubre deja el comedor social y va a ir a comprar la comida al Horno de San Juan , menu diario 5€/ dia. Los domingos come con su hna. -Sacará 150€ para comida y el resto para desayuno , cena , ropa ... no se le pondrá limite en cuenta , le cuesta gastar el dinero hasta para cosas necesarias y tiene 6000€ ahorrado.Limite máximo 250€/mes desde el dia 25 /09/15. -futuex lo visitará mensualmente , el 6 de octubre tiene cita en ESM . -Se le ha hecho seguro de decesos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EULALIA'and edp.apellido1='RANGEL'and apellido2='PORRO'),'2016-09-28','Se envía autorización para su participación en un Ptograma de Terapia Canina en Apba. 8.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-09-28','Se envía autorización para su participación en un Programa de Terapia Canina en Apba. 8.','2');
