insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2016-06-09','Guardo el correo de la R.M: Buenos dias, comunicaros que a partir de este mes vamos a pasar a cobrarle a MARIA SANCHEZ BELLO, 1300€ que es el coste de la residencia para un grado II que es el que le han dado a ella el SEPAD. Me he puesto en contacto con el equipo de dependencia de Trujillo, y me comentan que ya se están haciendo los tramites de la ayuda que le pertenece, y que la tiene aprobada desde el día que entró en residencia el 29 de octubre de 2015, les he facilitado el contrato que para la tramitación de dicha ayuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2016-09-28','Conversación con Ana Mª Arroyo Mantaño, Educadora Social de "Plena Inclusión" de Zafra (924-563092. Solo en caso necesario: 659338110). Considera que la mejor alternativa para Dª Mª Antonia sería el ingreso en plaza residencial en el propio centro, pero Dª Mª Antonia se ha negado siempre a dicho ingreso.','2');
