insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2016-09-28','Conversación con María José, T.Soc. de Valle de la Serena. Dª INés estaría dispuesta a pasar un fin de semana en Plasencia para estar con su hijo.','2');
