insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-22','Viene Cristofer con su pareja Sara, quieren copia del certificado de discapacidad actual porque tenían el antiguo y lo va a entregar en INSERTA para búsqueda de empleo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-09-28','Viene Cristofer solo, ha tenido una discusión en su casa con el hermano de su novia Sara. Los vecinos llamaron a la policía, y él acabó en el hospital porque rompió una figura de su casa con la mano y se cortó. El hermano de Sara se había ido a su piso porque el padre lo había echado de casa. Comenta que llevaba una semana sin tomarse la medicación, pero que ya le están organizando el pastillero su hermana y su primo, que ahora van a verlo todos los días. Le comentamos que si tiene duda con el pastillero que vaya a la enfermera del centro de salud o que nos lo traíga a nosotros. Ha roto la relación con su novia Sara tras el altercado del fin de semana. Así que ahora le está ayudando su hermana con la comida y con las cosas que necesita. Esta semana no ha ido al comedor social porque manifiesta que no tiene hambre y que Sara(su exnovia) se ha quedado con el carnet del autobus.Le recomendamos que vuelva a ir. Le comentamos lo de ir a un centro y que vamos a hablar con el ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2016-09-28','Enviamos solicitud de PNC, junto con su documentación debidamente compulsada','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='SANTANTON'and apellido2='GOMEZ'),'2016-09-29','- se le deniega la P. Orfandad , la madre fallecida no era pensionista . El padre vive aunque no tenemos muchos datos de él .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='SANTANTON'and apellido2='GOMEZ'),'2016-09-29','-soluciono el tema de las pensiones , PNC no habia enviado aún la opción para declinar esta , la volveré a retomar , le llegará la PNC de ocutubre con retraso pero no la perderá . -PFHC le va a suspender el pago que empezaba a cobrar el dia 1 de octubre para que luego no tengamos que devolverlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2016-09-29','Hablamos con Lourdes Pérez TS de SAD, nos comenta que Concepción no quiere SAD, pone muchas pegas para que entre la aux en su casa, según nos comenta la TS porque ella dice que la aux. mira a su marido y su marido a la aux. y no quiere que vayan. La TS valora ingreso en residencia, comenta que Concepción a veces dice que si quiere ingreso en residencia y otra veces no. La vivienda esta sucia, y hace un mes que no quiere q la aux, le haga el aseo personal. La TS va a llamar a Cristina (FUTUEX) para ir con ella a visita domiciliaria y valorar el ingreso en residencia y converceles para que sigan con SAD. Nos llamarán cuando se haga visita domiciliaria La TS me facilita el tlf de Tomás Maceda(yerno) 603651150 y Juan Pedro( hijo) 654744819. Comenta LOurdes TS que Concepción rechazó el PIA, hablar con dependencia para ver cómo está el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2016-09-29','Llama Ana Pérez Tejeda, Psiq. del CSS de Plasencia: "José Mª quiere ir a prisión porque dice que tiene más libertad que en el Centro: allí dice tener su televisión, poder pasear por el recinto, etc. Ana considera que dada la situación y que es una persona muy joven que se puede pasar la vida en un centro, entiende que el prefiera ir a la carcel durante esos 6 meses" dado que el abogado en su defensa pretende que los cumpla en el propio centro socisosanitario, cree que deberíamos hablar con él para exponerle la opinión de Jose Mª.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMASA'and edp.apellido1='SANCHO'and apellido2='GARCIA'),'2016-09-29','Conversación María, T. Soc. del C.M. Sierra de San Pedro (673-315439):Tomasa se encuentra perfectamente adaptada al Centro e inteegrada en la dinámica del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCO ANTONIO'and edp.apellido1='BENITEZ'and apellido2='PIN'),'2016-09-30','-Marcos viaja 1 vez al mes a Mérida a casa de los padres. Tras las insistencias de la madre y confirmar la información , a partir de ahora Maribel ( Ap9 ) le dará 100€ , 50 para gastos personales y 50 para entregar a la madre para comida.Maribel justificará el gasto trimestrlmente , no hay que mandar transferencia .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2015-11-09','Se aprueba darle una asignación semanal de 50€. Pendiente contactar Marisa con Liberbank de Guadalupe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-09-16','Nos envian del hospital Virgen de la Montañ,informe de alta con el ingreso involuntario en UHB. En su centro de salud de Guadalupe activaron el día 15 el protocolo, derivándolo a UHB CC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='ROMERO'and apellido2='DUBERT'),'2016-09-30','FALLECIDO El 23/09/2016. Aunque fue abierto como una curatela, en realidad jamás fuimos nombrados. Ni como curatela, ni como tutela. Se nos asignaron las funciones de curador para una medida cautelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-09-30','Consulta dirigida al Juzgado de 1ª Instancia nº 1 de Llerena, para saber cómo proceder en relación al ingreso en C. de Mayores de D. Arturo, al tener ya la paza por E. Social y carecer de la preceptiva orden judicial (en base a Doctrina del T. Constitucional, p. e. en la Sentencia 34/2016, de 29 de febrero): SE LLEVARÁ A CABO EL INGRESO, DEBIÉNDOSE COMUNICAR AL JUZGADO EN LAS 24h SIGUIENTES AL MISMO. En estos momentos, ya se ha dado traslado al Mº Fiscal de la solicitud de internamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-09-30','Llamada de Dª Isabel (madre de Saturnino): "Mi hijo no debe salir de un Centro, porque él no puede vivir solo...Ahora está muy bien en el Hospital, pero porque está atendido permanentemente... Tengo miedo de que haga lo que mi otro hijo, que se ha terminado suicidando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2016-10-03','Conversación con Asun. Javier está empeorando: al parecer está haciendo compras por internet y relacionándose con gente "no recomendable". PROPUESTA DE ASUN: +++Enviará informe a su Psiquiatra. +++Por parte de la CTAEx: proponer a Futuex visitas sin avisar y citarlo en la Comisión del 1 al 5 de cada mes para control de cuentas. +++Comprobar existencia de tarjeta de crédito y anular.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-10-03','Conversación con Dr Enrique Daniel: Saturnino sigue ingresado en UHB. El viernes solicitaron traslado al CSS de Plasencia (en espera de respuesta). En cualquier caso, estamos de acuerdo en que necesita supervisión permanente, por lo que, tras 1 o 2 de tratamiento en CSS la alternativa que se puede plantear es CRR o Pisos Supervisados.','2');
