insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2016-10-03','Nos confirman del centro penitenciario que el 22 de octubre es la siguiente convivencia. Hablamos con la hermana, María José, para decirselo, sólo falta hablar con el taxista. El último servicio fue pagado. Hay que pedir presupuesto para el siguiente viaje y avisar a la hermana con la hora de recogida.','2');
