insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2016-10-03','SALUD El 29/09/2016. Tiene un grano muy grande en la axila. Le receta augmentine 1-1-1 (mínimo 7 días) y bactroban 1 vez al día. Tiene que hacerse una analítica 3 o 4 días después del tratamiento porque pesa muy poco y si dan autorización le mandrá los batidos de proteínas para coger peso. Si el antibiótico le da diarrea debe tomarse prodefen que es un probiótico. Si el grano se abre tiene que ir a su enfermero para que le haga las curas.','2');
