insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2016-09-29','Hablamos con la empresa GILSAN, porque Francisco ha firmado contrato con ellos para la ley de dependencia. Empieza el servicio el 3 de octubre y la auxiliar es Monica la misma que estaba yendo a su casa. El tlf. de la empresa es 675811406 y 927702752, Victor o Silvia.','2');
