insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2016-10-04','HABLO CON EL JUZGADO DE 1ª INSTANCIA Nº 3 DE CÁCERES PARA INTERESARME POR LA SOLICITUD DE INTERNAMIENTO DE Mª EUGENIA. EL Nº DE PROCTO. ASIGNADO ES 557/2016, ME INFORMAN QUE EL FISCAL HA EMITIDO INFORME FAVORABLE Y ESTA PENDIENTE DE RESOLVER POR EL JUEZ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2016-10-04','Nos llama Soledad TS que hoy trasladan a Juan Chamorro a UME Plasencia. Ahora tenemos el problema de la ropa, porque él tiene las llaves de su casa y dice que tiene mucha ropa y que no le compremos ropa. Hablamos con FUTUEX y se encargará del tema de la ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='ARNOSI'and apellido2='PEREZ'),'2016-10-04','Hablamos con Cristina TS del CAMP, hay que solicitarle PF y orfandad igual que está su hermana. Le comento que inicie ella los trámites y que nos envie la solicitud junto con la documentación que pueda recabar y nosotros ya lo pasamos a firma y lo enviamos. También le va a solicitar revisión del PIA, se lo mandamos a ella una vez firmado. Nos va a mandar certificado de defunción de los padres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2016-10-04','Conversación con Ángeles Escudero (Res. de Pinofranqueado) tras comunicarnos Olga (SePAD Discapacidad) que desde la Residencia les habían solicitado traslado a Nuñomoral. Considera que ese sería el sitio ideal para él: ha agredido a una residente y a una trabajadora, si bien es una persona afable y tranquila reaccionar de esa manera en determinadas circustancias: constantemente queire salir a tomar café, a pasear, etc... Y eso no lo podemos asumir porque "...mis chicos...no son así, son personas mayores..." +++Enviará Informe sobre la situación que se ha producido. +++A pesar de que el traslado desde "Felipe TRigo" se produjo por su deseo de acercamiento familiar, NO HA RECIBIDO LLAMADAS NI VISITAS DE SU FAMILIA (que vive muy cerca). Cuando desde la Residencia se han puesto en contacto con ellos les han asegurado que sí, que irían a visitarlo...cosa que no ha sucedido hasta ahora (cuando llama, porque D. Teodoro insiste en que quiere hablar con su prima y se sabe de memoria el teléfono, nunca es ella la que se pone, sino su marido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-10-04','+++Llamada al 112 para ver posibilidad de traslado sin haber recibido la autorización judicial, dado que el plazo para ocupar la plaza termina el 10 de octubre (al ser por Emergencia Social): en caso de que no llegue la Autorización, solicitarlo al 12 exponiendo lasa mencionadas razones, indicando el nº de teléfono del Juzgado al que llamar en caso de que sea precisa la intervención de las fuerzas de seguridad. Además, enviar por fax la documentación habitual:Sentencia, Aceptación del cargo e indicar persona de contacto en la localidad. +++Llamada al Juzgado de 1ª Instancia e Instrucción nº 1 de Llerena (Teléfono: 924-870575 y 924-870862): posiblemente la autorización llegue en esta semana, si no es así, proceder de la manera indicada anteriormente. +++Conversación con May (Mayores), por si se pasase el plazo para ocupar la plaza: vamos a esperar a si en esta semana llega la Autorización. +++Conversación con Fefi, T. Soc. SSB de Usagre: ella estará en la localidad martes, jueves y viernes. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++DOMICILIO: C/ El Puente nº 14, de Usagre +++CONTACTO: Josefa Espino Pereira (T. SOCIAL).Telf: 924-585011 +++MÉDICO DE FAMILIA: Dra. Olga Chaparro (C. Salud Usagre: 924-585309 y 924-280805)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2016-10-04','Asistencia al Juzgado de 1ª Instancia nº 1 de Castuera: se renuncia a cualquier tipo de acción, quedando archivado el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2005-04-21','Se remite al Juzgado Inventario de Bienes y se aprueba el mismo por providencia de fecha 23 de octubre de 2003','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2016-10-04','Código para devolución y envío de la tablet por Correos: R025961124. Se comunica a Gisela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2016-10-05','Conversación con Mariví (T. Soc. CSS de Plasencia). +++Tras los tres meses de "vacaciones" con su madre, ésta ha pedido el alta de su hijo. Como la situación durante este tiempo ha sido positiva y había razones clínicas para dar el alta, se le ha dado esta (nos enviarán informe de alta). +++La madre nos va a solicitar hacerse guardadora de su hijo y tiene la intención de solicitar la remoción de la tutela para asumirla ella. +++Tras el alta, se le ha puesto en contacto con el ESM para seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MENDEZ'and apellido2='MARTIN'),'2016-10-05','REcibimimos Informe de la Residencia de Pinofranqueado por correo-e. También lo envían por correo ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2016-10-05','Llamada de Ventura. Empieza con amenazas: "...Es mi dinero, como no me des mi dinero el juez va a ir a por tí, Pedro. Lo siento mucho...". +++Quiere comprarse ropa y zapatos. También una televisión. Pero no tenemos presupuesto alguno. Solicitar a Futuex que en la próxima visita realice una valoración de la necesidades reales en este sentido y envíe presupuesto. +++SE le propone a Ventura un aumento del dienro disponible semanalmente: "...Quiero 200€ a la semana..." Actualmente tiene autorizados 100€/semana. Se le propone aumentar a 125€/semana pero no acepta menos de 150, por lo que tras insistir en no aceptar el incremento propuesto, se mantiene la asignación en los 100€/semana. Hay que tener en cuenta que además de dicho dinero, los extras que solicita para viajes, eventos sociales, suscripciones, etc. son frecuentes, además de los pagos que últimamente ha habido que hacer por deudas pendientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2016-10-05','Llamo a Margarita.La situación sigue buena evolución: buen comportamiento, buena actitud en talleres, pero más demandante de lo habitual (dinero, etc.). Está haciendo un puzzle de 500 piezas (le propongo que una vez terminado le haga una fotografía y nos la envíe). También quiere que vayamos a visitarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2016-10-05','SI LLAMA Dª Teodora, la hermana de D. Feliciano, PEDIRLE Nº DE CUENTA NUEVO para transferir los pagos comunes de la vivienda ncuya propiedad comparten (la cuenta anterior está cancelada).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2016-10-05','Llamada de Valentina, T. Soc. C. Salud de Aldea Moret (927-235141 y el suyo 606-113961). NO sabía de nuestra visita a Dª Paula y al C. de Salud. Le informo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Toni (FUTUEx) para que se ponga en contacto con Valentina para la próxima visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2016-10-05','Se autoriza 30€ para farmacia (la ha pagado él) y para el DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-10-05','Llamada de Juanjo, T. Soc. del H. Infanta Cristina (924-218075): INGRESO de D. Ramón en UHB el día 30 de septiembre. Se comunica a Juanjo que se le dió el alta el día 28 de septiembre de la UME de Mérida. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se comunica con Isabel, Psiquiatra de UME Mérida, el nuevo ingreso de Ramón en UHB de Badajoz. Cree que deberías estar en crónicos. Le pido que nos envíe el Informe de Alta para transmitirlo al Infanta Cristina. Se le informa también de la conversación mantenidacon Fabiola en relación a la subcomisión de casos que ésta quería convocar.Isabel me pide que diga al Psiquiatra del Infanta que se ponga en contacto con ella. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
