insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2016-10-05','Llamada de Jose Manuel: +++Pago de facturas. +++Visitas a la abuela. Ya ha recibido el Auto del Juzgado.','2');
