insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2016-10-06','Llamada de Estrella Durán (Vivienda:57489): la hermana de Dª Isabel, Dª Mª Ángeles, ha solicitado un cambio de la vivienda social que tenía asignada, en donde vivía Dª Isabel hasta su ingreso en la Residencia. Hecha la solicitud, ha autorizado a la Consejería de Vivienda a tirar todos los muebles y resto de contenido de la misma. Estrella comunica que se ha procedido de esa manera, pero que recogieron alguna documentación y un álbum de fotos. Pido a Toni (Futuex) que pasen a recogerlo y lo lleven a la Residencia, para que la diercción valore el momento en el que es más conveniente entregárselo a Dª Isabel.','2');
