insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2016-10-10','Hablo con Olga, Médica de Familia, para informarle del posible traslado e ingreso en la Residencia de San Vicente de Alcántara de D. Arturo durante esta semana, para que en caso de tener que activar el 112, si su sobrina no lo lleva, esté informada al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2016-10-11','Desde el pasado día 5 estamos intentando hablar con Juanjo y con la UHB del Infanta Cristina para tratar de que se pongan en contacto con Isabel, Psiquiatra de la UME de Mérida. Hasta este momento no hemos podido hablar con la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2016-10-11','-Tras conversacion con la TS del SSB de Llerena y la TS de la empresa de dependencia "Dependencia de EXtremadura " (tf.924552344/648867252/zafrdp@hotmail.com )quddamos en lo siguiente: Agustin va a percibir 300€ de dependencia que entre ts del SSB y TS dependencia y empresa acordaron un servicio de psicologia . La empresa lo ajusta a 8 sesiones / mes para que él no tenga que poner parte ec alguna . Acuerdo con la empresa en iniciar el servicio una vez que se perciba financiacion de dependencia para no ir adelanto el dinero . Nos van a enviar contrato por email para ser firmado a la espera de esta financiación . Desde el SSB la TS le ha puesto SAD municipal +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con la Dr. Constanza, Psiquiatra de la UHB de Llerena. Hoy le da el alta a Agustín, aunque ella considera que debería estar en un Centro con supervisión: le va a proponer derivación a URH porque considera que sí da perfil para ello, aunque no se puede quedar en la UHB dado que ya se encuentra clínicamente estable. Hará solicitud de derivación a URH. Cree que pasado un tiempo volverá a ingresar, porque aunque él ha pasado varios meses tomando correctamente el tratamineto, llega un momento en el que se cansa, lo abandona y entra en crisis nuevamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2016-10-10','-Acudo a SSSS penitenciarios para acompañar a Jonathan , este no se presenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2016-10-10','- Nos reunimos en la territorial del Sepad para hablar con la pareja y ajustar pto. mensual. - El tema de la particion de herencia , han contratado un abogado que va a intentar llegar a un acuerdo con la otra parte , en caso de tener que ir a juicio se valorará la opcion de abogado de oficio ( de esto se encarga la parte juridica)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='ORTEGA'and apellido2='APARICIO'),'2016-10-11','Llamada de D. Pedro Tapia (657-543901///953-602750),Presidente de la Comunidad de Vecinos, interesándose por Vanesa: "Me ha pedido que si le encuentro algo -trabajo- que se lo diga...Pero no sé nada de su situación, si tine alguna enfermedad, si tiene medios suficentes para vivir, etc. Algunas veces le he ayudado personalmente, pero no sé si está o no capacitada para realizar un trabajo, etc." SE le informa de que no podemos dar esa información, aunque él sabe que está tutelada porque se lo ha dicho ella y le ha proporcionado nuestro número.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='JIMENEZ'and apellido2='RUIZ'),'2016-10-11','Conversación con Mª Dolores, T. Soc. SSB. Va a enviar Informe Social para solicitar plaza por Emergencia Social. +++Conversación con el Dr.Manuel García Álvarez (C. Salud de Orellana la Vieja. 924-866770). Prácticamente no ha ido por su consulta, aunque confirma que ha estado en dos ocasiones, en 2009, en el ESM de Talarrubias (924-630141). +++Llamada al ESM de Talarrubias.','2');
