insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2016-10-11','Conversación con la Dr. Constanza, Psiquiatra de la UHB de Llerena. Hoy le da el alta a Agustín, aunque ella considera que debería estar en un Centro con supervisión: le va a proponer derivación a URH porque considera que sí da perfil para ello, aunque no se puede quedar en la UHB dado que ya se encuentra clínicamente estable. Hará solicitud de derivación a URH.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='ARNOSI'and apellido2='PEREZ'),'2016-10-10','- SE LE DA DE BAJA A LA PNC EN ABRIL 2016 , PERO NO DEBIA HABERLA PERCIBIDO DESDE ENERO 2016 POR SUPERACION DE INGRESOS EN LA U. CONV, CON LA HNA EN EL MODULO FAMILIAR. TIENE UNA DEUDA POR ESTE MOTIVO CON LA TESORERIA POR 1063€. - NO APARECE NI EN PFHC NI P.ORFANDAD. PTE TRAMITAR CAMP LAS CRUCES.','2');
