insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2016-10-11','Llamada de Mariví, T. Soc. de UME Plasencia: SE está planteando dentro de un tiempo el alta de D. Tomás, si bien antes seguramente pasará una temporada por URH. Se le plantea la alternativa de intentar su derivación a Pisos Supervisados. Él no está agusto en la UME y quizá si se le plantea la alternativa de los Pisos Supervisados, en comparación con su forma de vida anterior, acceda a probar.Plantear esta alternativa a Pilar, cuando se incorpore el día 24 de octubre.','2');
