insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2016-10-11','Conversación con Francisco, hermano de Saturnino.Dice que Saturnino ya ha asumido que va a estar mucho tiempo en un Centro. Francisco dice que está dispuesto a llevarlo al CSS de Plasencia cuando el Psiquiatra y vosotros lo digáis. Francisco HA ALQUILADO el piso en el que vivía Saturnino y este es consciente de ello. LA DERIVACIÓN es un tema del que ya se ha hablado con el Psiquiatra, y que ya se ha solicitado desde la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2016-10-10','-Al parecer Jacinto sí entra en el Convenio Cruz Roja y no paga nada , cuando llegue algo hay que pasarselo a Mayte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2016-10-13','Enviamos a ASINDI solicitud firmada de Habilitación Funcional: tratamiento psicológico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-10-06','Viene la madre de Cristofer con su pareja, comenta que a finales de octubre le tiene que llegar la factura del agua y la luz, le comento que en cuanto las reciba nos las traiga para pagarlas nosotros, pero que no le corten el agua y la luz. Dice que ella dejo el piso muy limpio y que él ya lo tiene sucio, que ellos van de vez en cuando a limpiar el piso y a dar una vuelta. La madre tenia pronto la cita para la declaración por la denuncia que tienen. La madre nos comentaba que no se toma la medicación. ------- Viene después Cristofer con su padre, el padre dice que lo llama a menudo y si necesita que lo acompañe al psiquiatra q el va con él. Vamos a intentar adelantarle la cita del psiquiatra, hablamos con Fátima. Cristofer no tiene muy claro ir a un centro porque piensa que si le dan la pensión se la van a quitar. Tlf. del padre de Cristofer 615127248 ( Juan Rollan)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2016-10-07','Viene Cristofer solo, porque dice que la familia de Sara su exnovia le ha dicho que no se acerque a ella ni la llame ni nada. Él dice que no la va a llamar ni nada ¿¿¿???, que se está tomando la medicación y que quiere ir a Coria a ver a una amiga. Le comentamos que no es el mejor momento para ir a visitar a esa amiga.','2');
